// Parseo robusto de fechas: acepta ms numérico, string numérico o ISO string
const toMs = (v) => {
  if (!v) return 0;
  if (typeof v === "number") return v;
  const n = Number(v);
  if (!isNaN(n) && n > 1e12) return n;   // string "1741826400000"
  return new Date(v).getTime();           // ISO string "2026-03-12T..."
};
