const TRAFICO_STATUS = {
  fluido:   { color: "#22c55e", label: "Fluido",   icon: "green-dot", bg: "#dcfce7", text: "#15803d" },
  moderado: { color: "#f97316", label: "Moderado", icon: "orange-dot", bg: "#ffedd5", text: "#c2410c" },
  detenido: { color: "#ef4444", label: "Detenido", icon: "red-dot", bg: "#fee2e2", text: "#b91c1c" },
  sinuso:   { color: "#a855f7", label: "Sin Uso",  icon: "purple-dot", bg: "#f3e8ff", text: "#7e22ce" },
};

const TRAFICO_MAP_STYLES = {
  streets:     { name: "Calles",   url: "https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png",    attribution: "© OpenStreetMap", subdomains: "abc" },
  humanitarian:{ name: "Claro",    url: "https://{s}.tile.openstreetmap.fr/hot/{z}/{x}/{y}.png", attribution: "© OpenStreetMap", subdomains: "ab"  },
  satellite:   { name: "Satélite", url: "https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}", attribution: "© Esri", subdomains: "" },
};

const toLLC = (coords) => coords.map(([lng, lat]) => [lat, lng]);

const VOTOS_DEFAULT = {
  1: { fluido: 0, moderado: 0, detenido: 0, sinuso: 0 },
  2: { fluido: 0, moderado: 0, detenido: 0, sinuso: 0 },
  3: { fluido: 0, moderado: 0, detenido: 0, sinuso: 0 },
};

const USER_VOTES_DEFAULT = { 1: {}, 2: {}, 3: {} };

const contarVotosFases = (userVotes = USER_VOTES_DEFAULT) => {
  const counts = JSON.parse(JSON.stringify(VOTOS_DEFAULT));
  [1, 2, 3].forEach((fase) => {
    Object.values(userVotes?.[fase] || {}).forEach((tipo) => {
      if (counts[fase]?.[tipo] !== undefined) counts[fase][tipo] += 1;
    });
  });
  return counts;
};

const normalizarVotosFases = (raw) => {
  // Formato nuevo: { _userVotes: { fase: { userId: status } } }
  if (raw?._userVotes) {
    const userVotes = { ...USER_VOTES_DEFAULT, ...raw._userVotes };
    return { userVotes, counts: contarVotosFases(userVotes) };
  }
  // Formato anterior: solo conteos. Se respeta para no romper datos existentes,
  // pero los votos nuevos ya se guardan por usuario.
  return {
    userVotes: { ...USER_VOTES_DEFAULT },
    counts: { ...VOTOS_DEFAULT, ...(raw || {}) },
  };
};

const paqueteVotosFases = (userVotes) => ({
  _version: 2,
  _userVotes: userVotes,
  counts: contarVotosFases(userVotes),
  updatedAt: Date.now(),
});

function useLeaflet() {
  const [L, setL] = useState(null);
  useEffect(() => {
    if (window.L) { setL(window.L); return; }
    const link = document.createElement("link");
    link.rel = "stylesheet";
    link.href = "https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/leaflet.min.css";
    document.head.appendChild(link);
    const script = document.createElement("script");
    script.src = "https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/leaflet.min.js";
    script.onload = () => setL(window.L);
    document.head.appendChild(script);
  }, []);
  return L;
}

// ─── Sub-componente: Mapa de Tráfico para 2do Acceso ─────────────────────────
function TrafficMapSegundo({ theme, myId }) {
  const L = useLeaflet();
  const mapRef    = useRef(null);
  const mapInstanceRef = useRef(null);
  const linesRef  = useRef({});
  const shadowsRef = useRef({});
  const tileLayerRef = useRef(null);

  const [votos, setVotos]           = useState(VOTOS_DEFAULT);
  const [userVotes, setUserVotes]   = useState(USER_VOTES_DEFAULT);
  const [statusMapa, setStatusMapa] = useState({ 1: "fluido", 2: "fluido", 3: "fluido" });
  const [lastUpdate, setLastUpdate] = useState(null);
  const [activeVote, setActiveVote] = useState({ fase: null, tipo: null });
  const [mapStyle, setMapStyle]     = useState("streets");

  const TABLA  = "carriles";
  const ROW_ID = "trafico_mapa_votos";

  // ── Calcular status dominante ──────────────────────────────────────────────
  const calcStatus = (votes) => {
    // "Sin Uso" toma prioridad si tiene al menos un voto
    if ((votes.sinuso || 0) > 0) return "sinuso";
    const entries = Object.entries(votes).filter(([k]) => k !== "sinuso");
    const total = entries.reduce((s, [, n]) => s + n, 0);
    if (total === 0) return "fluido";
    return entries.reduce((best, [k, n]) => (n > best[1] ? [k, n] : best), ["fluido", -1])[0];
  };

  const recalcAllStatus = (v) => ({
    1: calcStatus(v[1]),
    2: calcStatus(v[2]),
    3: calcStatus(v[3]),
  });

  // ── Cargar votos desde Supabase + suscripción en tiempo real ──────────────
  useEffect(() => {
    sb.from(TABLA).select("*").eq("id", ROW_ID).single().then(({ data }) => {
      if (data?.data) {
        const { userVotes: uv, counts } = normalizarVotosFases(data.data);
        setUserVotes(uv);
        setVotos(counts);
        setStatusMapa(recalcAllStatus(counts));
      }
    });
    const chan = sb.channel("trafico-mapa-rt")
      .on("postgres_changes", { event: "*", schema: "public", table: TABLA }, ({ new: r }) => {
        if (r?.id === ROW_ID && r?.data) {
          const { userVotes: uv, counts } = normalizarVotosFases(r.data);
          setUserVotes(uv);
          setVotos(counts);
          setStatusMapa(recalcAllStatus(counts));
        }
      }).subscribe();
    return () => sb.removeChannel(chan);
  }, []);

  // ── Inicializar mapa Leaflet ───────────────────────────────────────────────
  useEffect(() => {
    if (!L || !mapRef.current || mapInstanceRef.current) return;
    const map = L.map(mapRef.current, { center: [19.0905, -104.2890], zoom: 15, zoomControl: true });
    const style = TRAFICO_MAP_STYLES[mapStyle];
    tileLayerRef.current = L.tileLayer(style.url, { attribution: style.attribution, subdomains: style.subdomains || "abc", maxZoom: 20 }).addTo(map);
    L.polygon(toLLC(TRAFICO_POLIGONO), { color: "#fbbf24", weight: 2.5, opacity: 0.7, fillColor: "#fbbf24", fillOpacity: 0.08 })
      .addTo(map).bindTooltip("Vialidad — contorno general", { sticky: true });
    Object.entries(TRAFICO_FASES).forEach(([id, fase]) => {
      const shadow = L.polyline(toLLC(fase.coords), { color: "#000", weight: 14, opacity: 0.2, lineCap: "round", lineJoin: "round" }).addTo(map);
      const line   = L.polyline(toLLC(fase.coords), { color: TRAFICO_STATUS.fluido.color, weight: 9, opacity: 0.95, lineCap: "round", lineJoin: "round" }).addTo(map);
      line.bindTooltip(`<b>${fase.nombre}</b><br>${fase.descripcion}`, { sticky: true });
      shadowsRef.current[id] = shadow;
      linesRef.current[id]   = line;
    });
    L.circleMarker([19.08615, -104.29568], { radius: 8, fillColor: "#6366f1", color: "#fff", weight: 3, fillOpacity: 1 }).addTo(map).bindTooltip("Explanada Zona Norte", { direction: "right" });
    L.circleMarker([19.08743, -104.28564], { radius: 8, fillColor: "#8b5cf6", color: "#fff", weight: 3, fillOpacity: 1 }).addTo(map).bindTooltip("Correos de México",    { direction: "top"   });
    L.circleMarker([19.09373, -104.28356], { radius: 8, fillColor: "#ec4899", color: "#fff", weight: 3, fillOpacity: 1 }).addTo(map).bindTooltip("Algodones",             { direction: "top"   });
    L.circleMarker([19.09845, -104.28316], { radius: 8, fillColor: "#14b8a6", color: "#fff", weight: 3, fillOpacity: 1 }).addTo(map).bindTooltip("Libramiento",           { direction: "left"  });
    mapInstanceRef.current = map;
  }, [L]);

  // ── Cambiar estilo de mapa ─────────────────────────────────────────────────
  const changeMapStyle = (newStyle) => {
    if (!mapInstanceRef.current || !tileLayerRef.current) return;
    mapInstanceRef.current.removeLayer(tileLayerRef.current);
    const style = TRAFICO_MAP_STYLES[newStyle];
    tileLayerRef.current = L.tileLayer(style.url, { attribution: style.attribution, subdomains: style.subdomains || "abc", maxZoom: 20 }).addTo(mapInstanceRef.current);
    setMapStyle(newStyle);
  };

  // ── Actualizar colores en el mapa cuando cambia el status ─────────────────
  useEffect(() => {
    Object.entries(statusMapa).forEach(([id, st]) => {
      const line = linesRef.current[id];
      if (line) line.setStyle({ color: TRAFICO_STATUS[st].color });
    });
  }, [statusMapa]);

  // ── Votar y guardar en Supabase ────────────────────────────────────────────
  const votar = async (fase, tipo) => {
    const faseKey = String(fase);

    // Modo tipo "Segundo Acceso": un toque cambia el estado operativo de la fase.
    // No pide confirmación ni acumula consenso; el último estado reportado queda activo.
    const rl = rateLimiter.check(`trafico_fase_${myId}_${fase}`, 2500);
    if (!rl.allowed) return;

    setActiveVote({ fase, tipo });
    setTimeout(() => setActiveVote({ fase: null, tipo: null }), 600);

    const nextUserVotes = {
      ...userVotes,
      [faseKey]: { [myId || "ultimo"]: tipo },
    };
    const nextCounts = contarVotosFases(nextUserVotes);

    setUserVotes(nextUserVotes);
    setVotos(nextCounts);
    setStatusMapa(recalcAllStatus(nextCounts));

    const now = new Date();
    setLastUpdate(`${now.getHours().toString().padStart(2,"0")}:${now.getMinutes().toString().padStart(2,"0")}:${now.getSeconds().toString().padStart(2,"0")}`);

    await sb.from(TABLA).upsert({ id: ROW_ID, data: paqueteVotosFases(nextUserVotes) });
  };

  const totalVotos = (fase) => Object.values(votos[fase] || {}).reduce((a, b) => a + b, 0);

  // ── Render ─────────────────────────────────────────────────────────────────
  return (
    <div>
      {/* Header del mapa */}
      <div style={{ background: "rgba(255,255,255,0.05)", border: "1px solid rgba(255,255,255,0.12)", borderRadius: "12px", padding: "12px 16px", marginBottom: "12px", display: "flex", justifyContent: "space-between", alignItems: "center", flexWrap: "wrap", gap: 8 }}>
        <div>
          <div style={{ fontSize: "10px", color: "#38bdf8", fontFamily: getFont(theme,"secondary"), letterSpacing: "2px", marginBottom: "2px", fontWeight: "700" }}>MAPA — VIALIDAD EN TIEMPO REAL</div>
          <div style={{ color: "rgba(255,255,255,0.7)", fontSize: "12px", fontFamily: getFont(theme,"secondary") }}>Reportado por usuarios · Manzanillo, Colima</div>
        </div>
        {lastUpdate && (
          <span style={{ fontSize: "11px", color: "#e2e8f0", background: "rgba(56,189,248,0.12)", padding: "5px 12px", borderRadius: "20px", border: "1px solid rgba(56,189,248,0.3)", fontFamily: getFont(theme,"secondary") }}>
            🕐 {lastUpdate}
          </span>
        )}
      </div>

      {/* Selector de estilo de mapa */}
      <div style={{ display: "flex", gap: 6, flexWrap: "wrap", marginBottom: "10px", alignItems: "center" }}>
        <span style={{ fontSize: "11px", color: "rgba(255,255,255,0.45)", fontFamily: getFont(theme,"secondary") }}>Estilo:</span>
        {Object.entries(TRAFICO_MAP_STYLES).map(([key, style]) => (
          <button key={key} onClick={() => changeMapStyle(key)} style={{ fontSize: "11px", padding: "5px 10px", borderRadius: "8px", border: `1.5px solid ${mapStyle === key ? "#38bdf8" : "rgba(255,255,255,0.18)"}`, background: mapStyle === key ? "rgba(56,189,248,0.18)" : "rgba(255,255,255,0.04)", color: mapStyle === key ? "#38bdf8" : "#e2e8f0", cursor: "pointer", fontWeight: mapStyle === key ? 700 : 500, fontFamily: getFont(theme,"secondary"), transition: "all 0.2s" }}>
            {style.name}
          </button>
        ))}
      </div>

      {/* Mapa Leaflet */}
      <div ref={mapRef} style={{ width: "100%", height: 420, borderRadius: "14px", overflow: "hidden", border: "1px solid rgba(255,255,255,0.15)", boxShadow: "0 8px 32px rgba(0,0,0,0.4)", marginBottom: "14px", background: "#1a2942" }} />
      {!L && <div style={{ textAlign: "center", color: "#94a3b8", fontSize: "13px", marginBottom: "12px", padding: "12px", background: "rgba(255,255,255,0.04)", borderRadius: "10px", border: "1px solid rgba(255,255,255,0.1)", fontFamily: getFont(theme,"secondary") }}>Cargando mapa…</div>}

      {/* Cards de votación */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(280px, 1fr))", gap: 12, marginBottom: 14 }}>
        {[1, 2, 3].map((id) => {
          const st    = statusMapa[id];
          const t     = TRAFICO_STATUS[st];
          const v     = votos[id];
          const total = totalVotos(id);
          const fase  = TRAFICO_FASES[id];
          return (
            <div key={id} style={{ background: "rgba(255,255,255,0.05)", backdropFilter: "blur(12px)", borderRadius: "14px", border: `2px solid ${t.color}`, padding: "14px", display: "flex", flexDirection: "column", gap: 9, transition: "all 0.4s", boxShadow: `0 4px 16px ${t.color}40` }}>
              {/* Encabezado */}
              <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between" }}>
                <span style={{ fontSize: "14px", fontWeight: 700, color: "#ffffff", fontFamily: getFont(theme,"secondary") }}>{fase.nombre}</span>
                <span style={{ fontSize: "10px", fontWeight: 700, background: t.bg, color: t.text, padding: "3px 9px", borderRadius: "20px", border: `1px solid ${t.color}40` }}>{t.emoji} {t.label}</span>
              </div>
              <p style={{ margin: 0, fontSize: "11px", color: "#94a3b8", lineHeight: 1.5, fontFamily: getFont(theme,"secondary") }}>{fase.descripcion}</p>

              {/* Barra de estado dominante: ya no pinta varios colores al mismo tiempo */}
              {total > 0 && (
                <div style={{ height: 6, borderRadius: 6, overflow: "hidden", background: "rgba(255,255,255,0.1)" }}>
                  <div style={{ width: "100%", height: "100%", background: t.color, transition: "background 0.4s", boxShadow: `0 0 12px ${t.color}70` }} />
                </div>
              )}

              {/* Botones de voto */}
              <div style={{ display: "flex", flexDirection: "column", gap: 5, marginTop: 2 }}>
                {["fluido","moderado","detenido","sinuso"].map((tipo) => {
                  const tr = TRAFICO_STATUS[tipo];
                  const isActive = activeVote.fase === id && activeVote.tipo === tipo;
                  const miVoto = userVotes?.[String(id)]?.[myId] || userVotes?.[id]?.[myId];
                  const isMine = miVoto === tipo;
                  const isSinUsoOn = tipo === "sinuso" && st === "sinuso";
                  return (
                    <button
                      key={tipo}
                      onClick={() => votar(id, tipo)}
                      style={{ fontSize: "11px", padding: "9px 10px", borderRadius: "9px", border: `2px solid ${tr.color}`, background: isActive || isMine ? tr.color : "rgba(255,255,255,0.04)", color: isActive || isMine ? "#fff" : "#e2e8f0", cursor: "pointer", fontWeight: 600, transition: "all 0.2s", transform: isActive ? "scale(0.97)" : "scale(1)", display: "flex", alignItems: "center", gap: 7, fontFamily: getFont(theme,"secondary") }}
                      onMouseEnter={(e) => { if (!isActive && !isMine) e.currentTarget.style.background = `${tr.color}20`; }}
                      onMouseLeave={(e) => { if (!isActive && !isMine) e.currentTarget.style.background = "rgba(255,255,255,0.04)"; }}
                    >
                      <AppIcon name={tr.emoji} size={16} active={true} />
                      <span>{tr.label}{st === tipo ? " · activo" : ""}</span>
                    </button>
                  );
                })}
              </div>

              {/* Total votos */}
              <div style={{ fontSize: "10px", color: "#94a3b8", borderTop: "1px solid rgba(255,255,255,0.1)", paddingTop: 7, textAlign: "center", fontFamily: getFont(theme,"secondary") }}>
                Estado por fase · el último reporte actualiza el mapa en tiempo real
              </div>
            </div>
          );
        })}
      </div>

      {/* Leyenda */}
      <div style={{ display: "flex", gap: 14, alignItems: "center", flexWrap: "wrap", fontSize: "11px", color: "#94a3b8", background: "rgba(255,255,255,0.04)", backdropFilter: "blur(12px)", borderRadius: "10px", padding: "12px 16px", border: "1px solid rgba(255,255,255,0.1)" }}>
        <span style={{ fontWeight: 700, color: "#ffffff", fontFamily: getFont(theme,"secondary") }}>Leyenda:</span>
        {Object.entries(TRAFICO_STATUS).map(([key, t]) => (
          <span key={key} style={{ display: "flex", alignItems: "center", gap: 5 }}>
            <span style={{ width: 24, height: 5, borderRadius: 4, background: t.color, display: "inline-block", boxShadow: `0 0 8px ${t.color}60` }} />
            <span style={{ color: "#e2e8f0", fontFamily: getFont(theme,"secondary") }}>{t.label}</span>
          </span>
        ))}
        <span style={{ display: "flex", alignItems: "center", gap: 5 }}>
          <span style={{ width: 24, height: 5, borderRadius: 4, background: "#fbbf24", display: "inline-block", boxShadow: "0 0 8px #fbbf2460" }} />
          <span style={{ color: "#e2e8f0", fontFamily: getFont(theme,"secondary") }}>Vialidad (contorno)</span>
        </span>
      </div>
    </div>
  );
}

// ─── UI: Toggle tipo iOS (segmented switch de 2 opciones) ─────────────────────
// Reemplaza pares de botones mutuamente excluyentes (ej. LIBRE/SATURADO) por
// un solo control deslizante con animación, más rápido de leer y de tocar.
function SegmentedToggle({ value, onChange, leftLabel, rightLabel, leftColor = "#22c55e", rightColor = "#ef4444", pending = false, theme }) {
  const activeColor = value ? rightColor : leftColor;
  return (
    <div
      onClick={() => onChange(!value)}
      role="button"
      aria-pressed={value}
      style={{
        position: "relative",
        display: "grid",
        gridTemplateColumns: "1fr 1fr",
        width: "100%",
        height: "38px",
        background: "#0a1628",
        border: `1px solid ${activeColor}55`,
        borderRadius: "10px",
        padding: "3px",
        cursor: "pointer",
        userSelect: "none",
        opacity: pending ? 0.65 : 1,
        transition: "opacity 0.15s, border-color 0.25s",
        boxSizing: "border-box"
      }}
    >
      {/* Thumb deslizante */}
      <div style={{
        position: "absolute",
        top: "3px",
        bottom: "3px",
        left: value ? "calc(50% + 1.5px)" : "3px",
        width: "calc(50% - 4.5px)",
        background: activeColor + "26",
        border: `1px solid ${activeColor}`,
        borderRadius: "7px",
        transition: "left 0.22s cubic-bezier(.4,0,.2,1), background 0.22s, border-color 0.22s",
        boxShadow: pending ? "none" : `0 0 10px ${activeColor}33`
      }} />
      <div style={{ position:"relative", zIndex:1, display:"flex", alignItems:"center", justifyContent:"center", fontFamily:getFont(theme, "secondary"), fontSize:"11px", fontWeight: !value ? "700" : "400", color: !value ? leftColor : "#64748b", transition:"color 0.22s" }}>
        {leftLabel}
      </div>
      <div style={{ position:"relative", zIndex:1, display:"flex", alignItems:"center", justifyContent:"center", fontFamily:getFont(theme, "secondary"), fontSize:"11px", fontWeight: value ? "700" : "400", color: value ? rightColor : "#64748b", transition:"color 0.22s" }}>
        {rightLabel}
      </div>
    </div>
  );
}

// ─── UI: Dropdown de selección rápida (reemplaza <select> ambiguos) ───────────
// Muestra claramente que es un control de selección (chevron + panel flotante
// con opciones), evitando que el usuario dude si el campo es texto libre.
function QuickSelectDropdown({ value, options, onChange, placeholder = "— Sin especificar —", allowClear = false, pending = false, theme }) {
  const [open, setOpen] = useState(false);
  const [menuPos, setMenuPos] = useState(null);
  const ref = React.useRef(null);
  const current = options.find(o => o.id === value) || null;

  const updateMenuPos = useCallback(() => {
    if (!ref.current) return;
    const r = ref.current.getBoundingClientRect();
    const margin = 8;
    const maxH = Math.min(260, Math.max(140, window.innerHeight - r.bottom - margin));
    setMenuPos({ top: r.bottom + 4, left: r.left, width: r.width, maxHeight: maxH });
  }, []);

  useEffect(() => {
    if (!open) return;
    updateMenuPos();
    const onDocPointer = (e) => {
      if (ref.current && ref.current.contains(e.target)) return;
      if (e.target?.closest?.('[data-cm-quickselect-menu="1"]')) return;
      setOpen(false);
    };
    const onMove = () => updateMenuPos();
    document.addEventListener("mousedown", onDocPointer);
    window.addEventListener("scroll", onMove, true);
    window.addEventListener("resize", onMove);
    return () => {
      document.removeEventListener("mousedown", onDocPointer);
      window.removeEventListener("scroll", onMove, true);
      window.removeEventListener("resize", onMove);
    };
  }, [open, updateMenuPos]);

  const color = current?.color || "#64748b";
  const menu = open && menuPos ? createPortal(
    <div data-cm-quickselect-menu="1" style={{
      position:"fixed", top:menuPos.top, left:menuPos.left, width:menuPos.width,
      zIndex:2147483000, background:"#0f233a", border:"1px solid #1e3a5f", borderRadius:"8px",
      boxShadow:"0 18px 42px rgba(0,0,0,0.62)", overflowY:"auto", maxHeight:menuPos.maxHeight,
      WebkitOverflowScrolling:"touch"
    }}>
      {allowClear && (
        <div
          onClick={() => { onChange(null); setOpen(false); }}
          style={{ padding:"9px 10px", fontFamily:getFont(theme,"secondary"), fontSize:"11px", color:"#64748b", cursor:"pointer", borderBottom:"1px solid rgba(255,255,255,0.06)" }}
          onMouseEnter={e => e.currentTarget.style.background = "rgba(255,255,255,0.05)"}
          onMouseLeave={e => e.currentTarget.style.background = "transparent"}
        >
          {placeholder}
        </div>
      )}
      {options.map(o => (
        <div
          key={o.id}
          onClick={() => { onChange(o.id); setOpen(false); }}
          style={{ padding:"9px 10px", display:"flex", alignItems:"center", justifyContent:"space-between", cursor:"pointer", background: o.id === value ? o.color + "18" : "transparent" }}
          onMouseEnter={e => e.currentTarget.style.background = o.color + "22"}
          onMouseLeave={e => e.currentTarget.style.background = o.id === value ? o.color + "18" : "transparent"}
        >
          <IconText icon={o.icon} label={o.label} size={14} style={{ color: o.color, fontFamily:getFont(theme,"secondary"), fontSize:"11px", fontWeight: o.id === value ? "700" : "500" }} />
          {o.id === value && <span style={{ color:o.color, fontSize:"12px" }}>✓</span>}
        </div>
      ))}
    </div>,
    document.body
  ) : null;

  return (
    <div ref={ref} style={{ position:"relative", zIndex: open ? 99999 : 1, opacity: pending ? 0.65 : 1, transition:"opacity 0.15s" }}>
      <button
        type="button"
        onClick={() => setOpen(v => !v)}
        style={{
          width:"100%", padding:"9px 10px", background:"#0a1628",
          border:`1px solid ${current ? color : "#1e3a5f"}`, borderRadius:"8px",
          color: current ? color : "#64748b", fontFamily:getFont(theme, "secondary"),
          fontSize:"11px", cursor:"pointer", fontWeight: current ? "700" : "400",
          display:"flex", alignItems:"center", justifyContent:"space-between", gap:"6px",
          transition:"border-color 0.2s, color 0.2s"
        }}
      >
        <span style={{ display:"flex", alignItems:"center", gap:"6px", overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>
          {current ? <IconText icon={current.icon} label={current.label} size={14} /> : placeholder}
        </span>
        <svg width="11" height="11" viewBox="0 0 24 24" style={{ flexShrink:0, transform: open ? "rotate(180deg)" : "rotate(0deg)", transition:"transform 0.18s" }}>
          <path d="M6 9l6 6 6-6" stroke={current ? color : "#64748b"} strokeWidth="2.4" fill="none" strokeLinecap="round" strokeLinejoin="round"/>
        </svg>
      </button>
      {menu}
    </div>
  );
}

// ─── UI: Selector de Rueda compacto ──────────────────────────────────────────
// Reduce espacio en listas largas: muestra un botón compacto y abre un wheel picker
// con scroll-snap, selección central y confirmación explícita.
function WheelPickerSelect({ value, options, onChange, placeholder = "— Sin especificar —", allowClear = false, pending = false, theme, title = "Seleccionar opción" }) {
  const [open, setOpen] = useState(false);
  const listRef = React.useRef(null);
  const scrollTimerRef = React.useRef(null);
  const lastInteractionRef = React.useRef("wheel");
  const current = options.find(o => o.id === value) || null;
  const [draft, setDraft] = useState(value ?? null);

  const syncDraftFromWheelCenter = useCallback(() => {
    const list = listRef.current;
    if (!list) return;
    const centerY = list.getBoundingClientRect().top + list.clientHeight / 2;
    const items = Array.from(list.querySelectorAll('[data-wheel-id]'));
    let closest = null;
    let closestDist = Infinity;
    items.forEach(el => {
      const rect = el.getBoundingClientRect();
      const itemCenter = rect.top + rect.height / 2;
      const dist = Math.abs(itemCenter - centerY);
      if (dist < closestDist) {
        closestDist = dist;
        closest = el;
      }
    });
    if (!closest) return;
    const nextId = closest.getAttribute('data-wheel-id');
    setDraft(nextId === '__clear' ? null : nextId);
  }, []);

  const handleWheelScroll = useCallback(() => {
    lastInteractionRef.current = "wheel";
    if (scrollTimerRef.current) clearTimeout(scrollTimerRef.current);
    scrollTimerRef.current = setTimeout(syncDraftFromWheelCenter, 90);
  }, [syncDraftFromWheelCenter]);

  const getDraftFromWheelCenter = useCallback(() => {
    const list = listRef.current;
    if (!list) return draft;
    const centerY = list.getBoundingClientRect().top + list.clientHeight / 2;
    const items = Array.from(list.querySelectorAll('[data-wheel-id]'));
    let closest = null;
    let closestDist = Infinity;
    items.forEach(el => {
      const rect = el.getBoundingClientRect();
      const itemCenter = rect.top + rect.height / 2;
      const dist = Math.abs(itemCenter - centerY);
      if (dist < closestDist) {
        closestDist = dist;
        closest = el;
      }
    });
    if (!closest) return draft;
    const nextId = closest.getAttribute('data-wheel-id');
    return nextId === '__clear' ? null : nextId;
  }, [draft]);

  const applyWheelSelection = useCallback(() => {
    const next = lastInteractionRef.current === "tap" ? draft : getDraftFromWheelCenter();
    setDraft(next);
    onChange(next);
    setOpen(false);
  }, [draft, getDraftFromWheelCenter, onChange]);

  const chooseDraftByTap = useCallback((next, el = null) => {
    lastInteractionRef.current = "tap";
    setDraft(next);
    el?.scrollIntoView?.({ block:"center", behavior:"smooth" });
  }, []);

  useEffect(() => {
    if (!open) return;
    setDraft(value ?? null);
    lastInteractionRef.current = "wheel";
    const onKey = (e) => { if (e.key === "Escape") setOpen(false); };
    document.addEventListener("keydown", onKey);
    return () => {
      document.removeEventListener("keydown", onKey);
      if (scrollTimerRef.current) clearTimeout(scrollTimerRef.current);
    };
  }, [open, value]);

  useEffect(() => {
    if (!open || !listRef.current) return;
    const idx = Math.max(0, options.findIndex(o => o.id === (draft ?? value)));
    setTimeout(() => {
      const item = listRef.current?.querySelector(`[data-wheel-id="${CSS.escape(String(options[idx]?.id || ""))}"]`);
      item?.scrollIntoView?.({ block:"center", behavior:"smooth" });
      setTimeout(syncDraftFromWheelCenter, 220);
    }, 40);
  }, [open, syncDraftFromWheelCenter]);

  const color = current?.color || "#64748b";
  const display = current ? current.label : placeholder;

  const modal = open ? createPortal(
    <div onClick={() => setOpen(false)} style={{ position:"fixed", inset:0, zIndex:2147483000, background:"rgba(2,6,23,.68)", backdropFilter:"blur(8px)", display:"flex", alignItems:"flex-end", justifyContent:"center", padding:"16px" }}>
      <div onClick={e => e.stopPropagation()} style={{ width:"100%", maxWidth:"460px", background:"linear-gradient(180deg,#10233b,#081424)", border:"1px solid rgba(56,189,248,.28)", borderRadius:"18px", boxShadow:"0 24px 70px rgba(0,0,0,.65)", overflow:"hidden" }}>
        <div style={{ padding:"14px 16px", display:"flex", alignItems:"center", justifyContent:"space-between", borderBottom:"1px solid rgba(255,255,255,.08)" }}>
          <div>
            <div style={{ color:"#e2e8f0", fontFamily:getFont(theme,"secondary"), fontWeight:900, fontSize:"13px" }}>{title}</div>
            <div style={{ color:"rgba(255,255,255,.38)", fontFamily:getFont(theme,"secondary"), fontSize:"10px", marginTop:"2px" }}>Desliza la rueda o toca una opción y confirma</div>
          </div>
          <button onClick={() => setOpen(false)} style={{ width:"32px", height:"32px", borderRadius:"999px", border:"1px solid rgba(255,255,255,.12)", background:"rgba(255,255,255,.06)", color:"#94a3b8", cursor:"pointer" }}>✕</button>
        </div>

        <div style={{ position:"relative", padding:"10px 14px" }}>
          <div style={{ position:"absolute", left:"14px", right:"14px", top:"50%", height:"44px", transform:"translateY(-50%)", border:"1px solid rgba(56,189,248,.42)", background:"rgba(56,189,248,.08)", borderRadius:"12px", pointerEvents:"none", boxShadow:"0 0 0 999px rgba(2,6,23,.18)" }} />
          <div
            ref={listRef}
            onScroll={handleWheelScroll}
            onPointerUp={syncDraftFromWheelCenter}
            onTouchEnd={syncDraftFromWheelCenter}
            style={{ height:"190px", overflowY:"auto", scrollSnapType:"y mandatory", WebkitOverflowScrolling:"touch", padding:"74px 0", scrollbarWidth:"thin" }}
          >
            {allowClear && (
              <button
                type="button"
                data-wheel-id="__clear"
                onClick={(e) => chooseDraftByTap(null, e.currentTarget)}
                style={{ scrollSnapAlign:"center", width:"100%", height:"48px", margin:"4px 0", borderRadius:"12px", border:"none", background: draft == null ? "rgba(100,116,139,.20)" : "transparent", color:draft == null ? "#94a3b8" : "#64748b", fontFamily:getFont(theme,"secondary"), fontSize:"13px", fontWeight:draft == null ? 800 : 500, cursor:"pointer" }}
              >{placeholder}</button>
            )}
            {options.map(o => {
              const active = o.id === draft;
              return (
                <button
                  type="button"
                  key={o.id}
                  data-wheel-id={o.id}
                  onClick={(e) => chooseDraftByTap(o.id, e.currentTarget)}
                  style={{ scrollSnapAlign:"center", width:"100%", minHeight:"48px", margin:"4px 0", padding:"9px 14px", borderRadius:"12px", border:"none", background: active ? o.color + "22" : "transparent", color: active ? o.color : "rgba(226,232,240,.68)", fontFamily:getFont(theme,"secondary"), fontSize: active ? "14px" : "13px", fontWeight: active ? 900 : 650, cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"space-between", gap:"10px", transition:"all .14s" }}
                >
                  <IconText icon={o.icon} label={o.label} size={15} />
                  {active && <span style={{ color:o.color, fontWeight:900 }}>✓</span>}
                </button>
              );
            })}
          </div>
        </div>

        <div style={{ padding:"12px 14px 14px", display:"grid", gridTemplateColumns:"1fr 1fr", gap:"8px", borderTop:"1px solid rgba(255,255,255,.08)" }}>
          <button type="button" onClick={() => setOpen(false)} style={{ padding:"11px", borderRadius:"10px", border:"1px solid rgba(255,255,255,.12)", background:"rgba(255,255,255,.05)", color:"#94a3b8", fontFamily:getFont(theme,"secondary"), fontWeight:800, cursor:"pointer" }}>Cancelar</button>
          <button type="button" onClick={applyWheelSelection} style={{ padding:"11px", borderRadius:"10px", border:"1px solid rgba(34,197,94,.45)", background:"rgba(34,197,94,.16)", color:"#22c55e", fontFamily:getFont(theme,"secondary"), fontWeight:900, cursor:"pointer" }}>Aplicar</button>
        </div>
      </div>
    </div>,
    document.body
  ) : null;

  return (
    <div style={{ opacity: pending ? .65 : 1 }}>
      <button
        type="button"
        onClick={() => setOpen(true)}
        style={{ width:"100%", minHeight:"44px", padding:"11px 14px", background:"linear-gradient(180deg, rgba(10,22,40,.98), rgba(8,18,34,.98))", border:`1px solid ${current ? color : "#1e3a5f"}`, borderRadius:"10px", color: current ? color : "#64748b", fontFamily:getFont(theme,"secondary"), fontSize:"13px", cursor:"pointer", fontWeight: current ? 900 : 650, display:"flex", alignItems:"center", justifyContent:"space-between", gap:"10px", boxShadow: current ? `inset 0 0 0 1px ${color}22` : "none" }}
      >
        <span style={{ minWidth:0, flex:1, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap", display:"flex", alignItems:"center", justifyContent:"center", gap:"7px" }}>{current ? <IconText icon={current.icon} label={display} size={16} /> : display}</span>
        <span style={{ color: current ? color : "#64748b", fontSize:"16px", lineHeight:1 }}>☰</span>
      </button>
      {modal}
    </div>
  );
}

// ─── UI: Buscador de terminal (filtro en vivo sobre los botones existentes) ───
function TerminalSearchBox({ value, onChange, theme }) {
  return (
    <div style={{ position:"relative", marginBottom:"10px" }}>
      <svg width="13" height="13" viewBox="0 0 24 24" style={{ position:"absolute", left:"10px", top:"50%", transform:"translateY(-50%)", pointerEvents:"none" }}>
        <circle cx="10.5" cy="10.5" r="6.5" stroke="#64748b" strokeWidth="2" fill="none"/>
        <path d="M15.5 15.5L20 20" stroke="#64748b" strokeWidth="2" strokeLinecap="round"/>
      </svg>
      <input
        type="text"
        value={value}
        onChange={e => onChange(e.target.value)}
        placeholder="Buscar terminal (ej. CONTECON)…"
        style={{
          width:"100%", padding:"8px 10px 8px 30px", background:"#0a1628",
          border:"1px solid #1e3a5f", borderRadius:"8px", color:"#e2e8f0",
          fontFamily:getFont(theme, "secondary"), fontSize:"11px", outline:"none", boxSizing:"border-box"
        }}
      />
      {value && (
        <button
          onClick={() => onChange("")}
          style={{ position:"absolute", right:"8px", top:"50%", transform:"translateY(-50%)", background:"transparent", border:"none", color:"#64748b", fontSize:"14px", cursor:"pointer", lineHeight:1, padding:"2px 4px" }}
        >
          ✕
        </button>
      )}
    </div>
  );
}

function SegundoAccesoTab({ myId }) {
  const theme = React.useContext(ThemeContext);
  const [subTab, setSubTab] = useState("segundo");
  const [terminalSearch, setTerminalSearch] = useState({}); // { [carrilId]: string } — filtro en vivo del buscador de terminal
  const [pendingKeys, setPendingKeys] = useState({}); // { "carrilId:field": true } — feedback optimista mientras confirma el servidor

  // ── Estado 2DO ACCESO ──
  const [carriles, setCarriles] = useState(mkSegundoIngreso);
  // ── Estado CONFINADA ──
  const [confinada, setConfinada] = useState(mkConfinadaState);

  const [toast, setToast] = useState(null);
  const notify = (msg, color = "#38bdf8") => { setToast({ msg, color }); setTimeout(() => setToast(null), 2800); };

  const TABLA = "carriles";
  const ROW_ID = "segundo_acceso";
  const ROW_ID_CF = "confinada_acceso";

  const saveToSupa = async (newState) => { const { error } = await sb.from(TABLA).upsert({ id: ROW_ID, data: newState }); return error; };
  const saveConfinada = async (newState) => { await sb.from(TABLA).upsert({ id: ROW_ID_CF, data: newState }); };

  // ── Helper: marca/desmarca una clave como "pendiente de confirmación" (feedback optimista) ──
  const setPending = (key, on) => setPendingKeys(prev => {
    if (on) return { ...prev, [key]: true };
    const { [key]: _omit, ...rest } = prev;
    return rest;
  });

  useEffect(() => {
    sb.from(TABLA).select("*").eq("id", ROW_ID).single().then(({ data }) => {
      if (data?.data) setCarriles({ ...mkSegundoIngreso(), ...data.data });
    });
    sb.from(TABLA).select("*").eq("id", ROW_ID_CF).single().then(({ data }) => {
      if (data?.data) setConfinada({ ...mkConfinadaState(), ...data.data });
    });
    const chan = sb.channel("segundo-rt")
      .on("postgres_changes", { event: "*", schema: "public", table: TABLA }, ({ new: r }) => {
        if (r?.id === ROW_ID && r?.data) setCarriles(r.data);
        if (r?.id === ROW_ID_CF && r?.data) setConfinada(r.data);
      }).subscribe();
    return () => sb.removeChannel(chan);
  }, []);

  // ── Handlers 2DO ACCESO ──
  const updateIngreso = async (id, field, value) => {
    if (!carriles) return;
    const prev = carriles;
    const key = `${id}:${field}`;
    const next = { ...carriles, [id]: { ...carriles[id], [field]: value, lastUpdate: Date.now(), updatedBy: "Tú" } };
    setCarriles(next); // ✓ feedback instantáneo, sin esperar al servidor
    setPending(key, true);
    const error = await saveToSupa(next);
    setPending(key, false);
    if (error) {
      setCarriles(prev); // ↩ revertir si el guardado falló
      notify("✗ No se pudo guardar, se revirtió el cambio", "#ef4444");
      return;
    }
    const carrilDefForAudit = SEGUNDO_CARRILES_INGRESO.find(c => c.id === id);
    const valorLabelAudit = field === "retornos" ? (value ? "Con retornos" : "Sin retornos") : field === "saturado" ? (value ? "Saturado" : "Libre") : String(value);
    await auditLog({ action:"modificar_carril_segundo", section:"segundo", entityId:id, before:carriles[id], after:{ carril:carrilDefForAudit?.label || id, campo:field, value, valor_label:valorLabelAudit, summary:`${getDeviceId()} votó ${valorLabelAudit} en ${carrilDefForAudit?.label || id}` }, actor:`Usuario_${myId.slice(-4)}` });
    notify("✓ Carril actualizado", "#22c55e");
    const carrilDef = SEGUNDO_CARRILES_INGRESO.find(c => c.id === id);
    const fieldLabel = field === "saturado" ? (value ? "Saturado" : "Libre") : (value ? "Con Retornos" : "Sin Retornos");
    await publicarNoticia({ tipo: "segundo", icono: "road", color: "#34d399", titulo: `2do Acceso ${carrilDef?.label || id} — ${fieldLabel}`, detalle: "Estado de carril actualizado" });
  };
  const updateSalida = async (field, value) => {
    const prev = carriles;
    const key = `c4:${field}`;
    const next = { ...carriles, c4: { ...carriles.c4, [field]: value, lastUpdate: Date.now(), updatedBy: "Tú" } };
    setCarriles(next); // ✓ feedback instantáneo, sin esperar al servidor
    setPending(key, true);
    const error = await saveToSupa(next);
    setPending(key, false);
    if (error) {
      setCarriles(prev); // ↩ revertir si el guardado falló
      notify("✗ No se pudo guardar, se revirtió el cambio", "#ef4444");
      return;
    }
    await auditLog({ action:"modificar_carril_salida", section:"segundo", entityId:"c4", before:prev.c4, after:{ carril:"Carril 4", campo:field, value, valor_label:String(value), summary:`${getDeviceId()} modificó Carril 4 · ${field}: ${String(value)}` }, actor:`Usuario_${myId.slice(-4)}` });
    notify("✓ Carril de salida actualizado", "#22c55e");
    const fieldLabel =
      field === "saturado" ? (value ? "Saturado" : "Libre") :
      field === "retornos" ? (value ? "Con retornos" : "Sin retornos") :
      field === "expo" ? `Exportación: ${SEGUNDO_TRAFICO_OPTS.find(o => o.id === value)?.label || value}` :
      field === "impo" ? `Importación: ${SEGUNDO_TRAFICO_OPTS.find(o => o.id === value)?.label || value}` :
      field === "expo_contenedor" ? `Contenedor: ${SEGUNDO_CONTENEDOR_OPTS.find(o => o.id === value)?.label || "sin selección"}` :
      "Actualizado";
    await publicarNoticia({ tipo: "segundo", icono: "road", color: "#22c55e", titulo: `2do Acceso Carril 4 — ${fieldLabel}`, detalle: "Estado de carril de salida actualizado" });
  };
  const updateIngresoEstado = async (id, estadoId) => {
    if (!carriles) return;
    const prev = carriles;
    const def = SEGUNDO_CARRILES_INGRESO.find(c => c.id === id);
    const opt = CARRIL_ESTADO_OPTS.find(o => o.id === estadoId) || CARRIL_ESTADO_OPTS[0];
    const current = carriles[id] || {};
    const nextTerminal = opt.id === "sin_uso" ? "sin_uso" : (current.terminal === "sin_uso" ? (def?.defaultTerminal || "ssa") : current.terminal);
    const next = {
      ...carriles,
      [id]: { ...current, terminal: nextTerminal, estado_carril: opt.id, saturado: carrilEstadoIsSaturado(opt.id), lastUpdate: Date.now(), updatedBy: "Tú" }
    };
    setCarriles(next);
    setPending(`${id}:estado_carril`, true);
    const error = await saveToSupa(next);
    setPending(`${id}:estado_carril`, false);
    if (error) { setCarriles(prev); notify("✗ No se pudo guardar, se revirtió el cambio", "#ef4444"); return; }
    await auditLog({ action:"modificar_estado_carril_segundo", section:"segundo", entityId:id, before:prev[id], after:{ carril:def?.label || id, campo:"estado_carril", value:opt.id, valor_label:opt.label, summary:`${getDeviceId()} marcó ${def?.label || id} como ${opt.label}` }, actor:`Usuario_${myId.slice(-4)}` });
    notify("✓ Estado del carril actualizado", opt.color);
    await publicarNoticia({ tipo: "segundo", icono: "road", color: opt.color, titulo: `2do Acceso ${def?.label || id} — ${opt.label}`, detalle: "Estado de carril actualizado" });
  };

  const updateSalidaEstado = async (estadoId) => {
    if (!carriles?.c4) return;
    const prev = carriles;
    const opt = CARRIL_ESTADO_OPTS.find(o => o.id === estadoId) || CARRIL_ESTADO_OPTS[0];
    const next = { ...carriles, c4: { ...carriles.c4, estado_carril: opt.id, saturado: carrilEstadoIsSaturado(opt.id), lastUpdate: Date.now(), updatedBy: "Tú" } };
    setCarriles(next);
    setPending("c4:estado_carril", true);
    const error = await saveToSupa(next);
    setPending("c4:estado_carril", false);
    if (error) { setCarriles(prev); notify("✗ No se pudo guardar, se revirtió el cambio", "#ef4444"); return; }
    await auditLog({ action:"modificar_estado_carril_salida", section:"segundo", entityId:"c4", before:prev.c4, after:{ carril:"Carril 4", campo:"estado_carril", value:opt.id, valor_label:opt.label, summary:`${getDeviceId()} marcó Carril 4 como ${opt.label}` }, actor:`Usuario_${myId.slice(-4)}` });
    notify("✓ Estado del carril de salida actualizado", opt.color);
    await publicarNoticia({ tipo: "segundo", icono: "road", color: opt.color, titulo: `2do Acceso Carril 4 — ${opt.label}`, detalle: "Estado de carril de salida actualizado" });
  };

  const resetAll = async () => {
    const next = mkSegundoIngreso();
    setCarriles(next);
    await saveToSupa(next);
    notify("✓ Todos los carriles restablecidos", "#22c55e");
  };
  const resetOne = async (id) => {
    const def = SEGUNDO_CARRILES_INGRESO.find(c => c.id === id);
    const next = { ...carriles, [id]: { terminal: def?.defaultTerminal || "ssa", estado_carril: "libre", saturado: false, retornos: false, expo: "libre", expo_contenedor: null, impo: "libre", lastUpdate: Date.now(), updatedBy: "Reset" } };
    setCarriles(next);
    await saveToSupa(next);
    notify("✓ Carril restablecido", "#22c55e");
  };

  // ── Handlers CONFINADA ──
  const updateConfinada = async (id, field, value) => {
    if (!confinada) return;
    const key = `${id}:${field}`;
    const next = { ...confinada, [id]: { ...confinada[id], [field]: value, lastUpdate: Date.now(), updatedBy: "Tú" } };
    setConfinada(next);
    setPending(key, true);
    await saveConfinada(next);
    setPending(key, false);
    const carrilDefForAudit = CONFINADA_CARRILES.find(c => c.id === id);
    const valorLabelAudit = field === "retornos" ? (value ? "Con retornos" : "Sin retornos") : field === "saturado" ? (value ? "Saturado" : "Libre") : field === "transferencia" ? (value ? "Segundo Acceso" : "Normal") : String(value);
    await auditLog({ action:"modificar_carril_confinada", section:"segundo", entityId:id, before:confinada[id], after:{ carril:carrilDefForAudit?.label || id, campo:field, value, valor_label:valorLabelAudit, summary:`${getDeviceId()} votó ${valorLabelAudit} en ${carrilDefForAudit?.label || id}` }, actor:`Usuario_${myId.slice(-4)}` });
    notify("✓ Carril Confinada actualizado", "#a78bfa");
    const carrilDef = CONFINADA_CARRILES.find(c => c.id === id);
    const fieldLabel = field === "saturado" ? (value ? "Saturado" : "Libre") : field === "transferencia" ? (value ? "Segundo Acceso" : "Normal") : (value ? "Con Retornos" : "Sin Retornos");
    await publicarNoticia({ tipo: "segundo", icono: "🔒", color: "#a78bfa", titulo: `Confinada ${carrilDef?.label || id} — ${fieldLabel}`, detalle: "Estado de carril actualizado" });
  };
  const updateConfinadaEstado = async (id, estadoId) => {
    if (!confinada) return;
    const prev = confinada;
    const def = CONFINADA_CARRILES.find(c => c.id === id);
    const opt = CARRIL_ESTADO_OPTS.find(o => o.id === estadoId) || CARRIL_ESTADO_OPTS[0];
    const current = confinada[id] || {};
    const nextTerminal = estadoId === "sin_uso" ? "sin_uso" : (current.terminal === "sin_uso" ? (def?.defaultTerminal || "general") : current.terminal);
    const next = {
      ...confinada,
      [id]: { ...current, terminal: nextTerminal, estado_carril: opt.id, saturado: carrilEstadoIsSaturado(opt.id), lastUpdate: Date.now(), updatedBy: "Tú" }
    };
    setConfinada(next);
    setPending(`${id}:estado_carril`, true);
    await saveConfinada(next);
    setPending(`${id}:estado_carril`, false);
    await auditLog({ action:"modificar_estado_carril_confinada", section:"segundo", entityId:id, before:prev[id], after:{ carril:def?.label || id, campo:"estado_carril", value:opt.id, valor_label:opt.label, summary:`${getDeviceId()} marcó ${def?.label || id} como ${opt.label}` }, actor:`Usuario_${myId.slice(-4)}` });
    notify("✓ Estado del carril Confinada actualizado", opt.color);
    await publicarNoticia({ tipo: "segundo", icono: "🔒", color: opt.color, titulo: `Confinada ${def?.label || id} — ${opt.label}`, detalle: "Estado de carril actualizado" });
  };

  const resetAllConfinada = async () => {
    const next = mkConfinadaState();
    setConfinada(next);
    await saveConfinada(next);
    notify("✓ Confinada restablecida", "#a78bfa");
  };
  const resetOneConfinada = async (id) => {
    const def = CONFINADA_CARRILES.find(c => c.id === id);
    const next = { ...confinada, [id]: { terminal: def?.defaultTerminal || "timsa", estado_carril: "libre", saturado: false, retornos: false, transferencia: false, expo: "libre", expo_contenedor: null, impo: "libre", lastUpdate: Date.now(), updatedBy: "Reset" } };
    setConfinada(next);
    await saveConfinada(next);
    notify("✓ Carril restablecido", "#a78bfa");
  };

  const getTermName = (id) => id === "sin_uso" ? "SIN USO" : TODAS_TERMINALES.find(t => t.id === id)?.name || id?.toUpperCase() || "—";
  const getTermZona = (id) => id === "sin_uso" ? "Sin uso" : TODAS_TERMINALES.find(t => t.id === id)?.zona || "";
  const termsNorte  = TODAS_TERMINALES.filter(t => t.zona === "Norte");
  const termsSur    = TODAS_TERMINALES.filter(t => t.zona === "Sur");
  const terminalOptionsSegundo = [
    { id:"general", label:"GENERAL · todas las terminales", color:"#fbbf24", icon:"bolt" },
    ...termsNorte.map(t => ({ id:t.id, label:`Norte · ${t.name}`, color:"#38bdf8", icon:"port-terminal" })),
    ...termsSur.map(t => ({ id:t.id, label:`Sur · ${t.name}`, color:"#a78bfa", icon:"port-terminal" })),
  ];
  const terminalOptionsConfinada = [
    { id:"general", label:"GENERAL · todas las terminales", color:"#fbbf24", icon:"bolt" },
    ...termsSur.map(t => ({ id:t.id, label:`Sur · ${t.name}`, color:"#a78bfa", icon:"port-terminal" })),
  ];

  return (
    <div style={{ padding:"16px", paddingBottom:"80px", minHeight:"100vh" }}>

      {/* ── Header principal ── */}
      <div style={{ background:"rgba(255,255,255,0.08)", backdropFilter:"blur(12px)", WebkitBackdropFilter:"blur(12px)", border:"1px solid rgba(255,255,255,0.15)", borderRadius:"12px", padding:"12px", marginBottom:"14px" }}>
        <div style={{ fontSize:"10px", color:"#38bdf8", fontFamily:getFont(theme, "secondary"), letterSpacing:"2px", marginBottom:"4px" }}>CONFINADOS — PUERTO MANZANILLO</div>
        <div style={{ color:"rgba(255,255,255,0.7)", fontSize:"12px" }}>2do Acceso y zona confinada · Ingreso con terminal asignada.</div>
      </div>

      {/* ── Sub-tab selector ── */}
      <div style={{ display:"flex", gap:"8px", marginBottom:"16px" }}>
        {[
          { id:"segundo",   label:"2DO ACCESO",   icon:"route-road",  color:"#34d399" },
          { id:"confinada", label:"CONFINADA",    icon:"lock", color:"#a78bfa" },
        ].map(tab => (
          <button
            key={tab.id}
            onClick={() => setSubTab(tab.id)}
            style={{
              flex:1, padding:"12px 8px",
              background: subTab===tab.id ? tab.color+"22" : "rgba(255,255,255,0.04)",
              border: `2px solid ${subTab===tab.id ? tab.color : "rgba(255,255,255,0.12)"}`,
              borderRadius:"10px",
              color: subTab===tab.id ? tab.color : "rgba(255,255,255,0.45)",
              fontFamily:getFont(theme, "secondary"), fontSize:"12px", fontWeight:"800",
              cursor:"pointer", letterSpacing:"1px",
              transition:"all 0.2s",
              display:"flex", alignItems:"center", justifyContent:"center", gap:"6px",
            }}
          >
            <AppIcon name={tab.icon} size={18} active={subTab===tab.id} />{tab.label}
          </button>
        ))}
      </div>

      {/* ════════════════════════════════════════════════════
          SUB-TAB: 2DO ACCESO
      ════════════════════════════════════════════════════ */}
      {subTab === "segundo" && <>
        {/* ── Diagrama visual de carriles ── */}
        <div style={{ background:"rgba(255,255,255,0.05)", border:"1px solid rgba(255,255,255,0.15)", borderRadius:"14px", padding:"14px", marginBottom:"18px", overflow:"hidden" }}>
          <div style={{ fontSize:"10px", color:"rgba(255,255,255,0.5)", fontFamily:getFont(theme, "secondary"), letterSpacing:"1px", marginBottom:"12px" }}>DIAGRAMA — VISTA DE CARRILES (PUENTE 2DO ACCESO)</div>

          {/* Carretera con carriles */}
          <div style={{ background:"#1a1a2e", borderRadius:"10px", padding:"14px 10px 10px", position:"relative", border:"1px solid rgba(255,255,255,0.08)" }}>

            {/* Líneas amarillas del pavimento */}
            <div style={{ position:"absolute", top:0, bottom:0, left:"50%", width:"3px", background:"repeating-linear-gradient(to bottom, #f59e0b 0px, #f59e0b 12px, transparent 12px, transparent 22px)", transform:"translateX(-50%)", opacity:0.7 }} />
            <div style={{ position:"absolute", top:0, bottom:0, left:"calc(50% - 80px)", width:"2px", background:"repeating-linear-gradient(to bottom, #4b5563 0px, #4b5563 10px, transparent 10px, transparent 20px)", transform:"translateX(-50%)", opacity:0.5 }} />
            <div style={{ position:"absolute", top:0, bottom:0, left:"calc(50% + 80px)", width:"2px", background:"repeating-linear-gradient(to bottom, #4b5563 0px, #4b5563 10px, transparent 10px, transparent 20px)", transform:"translateX(-50%)", opacity:0.5 }} />

            {/* Flechas de carriles */}
<div style={{ display:"flex", gap:"6px", position:"relative", zIndex:1 }}>

  {/* C4 — SALIDA (ciudad, verde/rojo) */}
  {(() => {
    const c4Opt = getCarrilEstadoOpt(carriles?.c4);
    const c4col = c4Opt.color;
    return (
      <div style={{ flex:1, display:"flex", flexDirection:"column", alignItems:"center", gap:"6px" }}>
        
        {/* Flecha hacia ABAJO (ciudad) */}
        <div style={{ position:"relative", width:"52px" }}>
          <svg viewBox="0 0 52 60" style={{ width:"52px", height:"60px", filter:`drop-shadow(0 0 8px ${c4col}88)` }}>
            <polygon
              points="26,56 48,32 36,32 36,4 16,4 16,32 4,32"
              fill={c4col}
              opacity="0.9"
            />
          </svg>
        </div>

        <div style={{ background:c4col+"22", border:`1.5px solid ${c4col}`, borderRadius:"8px", padding:"4px 6px", textAlign:"center", width:"100%" }}>
          <div style={{ color:c4col, fontFamily:getFont(theme,"secondary"), fontSize:"13px", fontWeight:"800" }}>C4</div>
          <div style={{ color:c4col, fontFamily:getFont(theme,"secondary"), fontSize:"9px", fontWeight:"700", letterSpacing:"1px" }}>SALIDA</div>
          <div style={{ color:"rgba(255,255,255,0.5)", fontFamily:getFont(theme,"secondary"), fontSize:"9px", marginTop:"2px" }}>
            {c4Opt.label.toUpperCase()}
          </div>
        </div>
      </div>
    );
  })()}

  {/* C1, C2, C3 — INGRESO (puerto) */}
  {[...SEGUNDO_CARRILES_INGRESO].reverse().map((c) => {
    const st  = carriles?.[c.id];
    const laneOpt = getCarrilEstadoOpt(st);
    const col = laneOpt.id === "libre" ? "#14b8a6" : laneOpt.color;
    const tz  = getTermZona(st?.terminal);
    const tc  = tz === "Sin uso" ? "#6b7280" : tz === "Todas" ? "#fbbf24" : tz === "Norte" ? "#38bdf8" : "#a78bfa";

    return (
      <div key={c.id} style={{ flex:1, display:"flex", flexDirection:"column", alignItems:"center", gap:"6px" }}>
        
        {/* Flecha hacia ARRIBA (puerto) */}
        <div style={{ position:"relative", width:"52px" }}>
          <svg viewBox="0 0 52 60" style={{ width:"52px", height:"60px", filter:`drop-shadow(0 0 8px ${col}88)` }}>
            <polygon
              points="26,4 48,28 36,28 36,56 16,56 16,28 4,28"
              fill={col}
              opacity="0.9"
            />
          </svg>
        </div>

        <div style={{ background:col+"22", border:`1.5px solid ${col}`, borderRadius:"8px", padding:"4px 6px", textAlign:"center", width:"100%" }}>
          <div style={{ color:col, fontFamily:getFont(theme,"secondary"), fontSize:"13px", fontWeight:"800" }}>
            {c.label}
          </div>

          <div style={{ background:tc+"33", borderRadius:"4px", padding:"2px 3px", marginTop:"3px" }}>
            <div style={{ color:tc, fontFamily:getFont(theme,"secondary"), fontSize:"8px", fontWeight:"700", whiteSpace:"nowrap", overflow:"hidden", textOverflow:"ellipsis" }}>
              {getTermName(st?.terminal)}
            </div>
          </div>

          {st?.retornos && (
            <div style={{ color:"#f97316", fontSize:"10px", marginTop:"2px" }}>↩</div>
          )}
        </div>
      </div>
    );
  })}
</div>
            {/* Etiquetas de dirección */}
            <div style={{ display:"flex", justifyContent:"space-between", marginTop:"8px", padding:"0 4px" }}>
              <div style={{ fontSize:"9px", color:"#f97316", fontFamily:getFont(theme,"secondary"), letterSpacing:"1px", fontWeight:"700" }}>↓ HACIA CIUDAD</div>
              <div style={{ fontSize:"9px", color:"#14b8a6", fontFamily:getFont(theme,"secondary"), letterSpacing:"1px", fontWeight:"700" }}>↑ HACIA EL PUERTO</div>
            </div>
          </div>

          {/* Leyenda */}
          <div style={{ display:"flex", justifyContent:"center", gap:"12px", marginTop:"10px", flexWrap:"wrap" }}>
            {[["#14b8a6","LIBRE"],["#f59e0b","LENTO"],["#f97316","MODERADO"],["#ef4444","SATURADO"],["#dc2626","BLOQUEO"],["#6b7280","SIN USO"]].map(([c,l]) => (
              <div key={l} style={{ display:"flex", alignItems:"center", gap:"3px" }}>
                <div style={{ width:"8px", height:"8px", background:c, borderRadius:"2px" }} />
                <span style={{ fontSize:"9px", color:"rgba(255,255,255,0.5)", fontFamily:getFont(theme, "secondary") }}>{l}</span>
              </div>
            ))}
          </div>
        </div>

        <SectionLabel text="CARRILES DE INGRESO (C1–C3)" rightBtn={<NormalBtn onClick={resetAll} label="TODO NORMAL" />} />
        {SEGUNDO_CARRILES_INGRESO.map(carril => {
          const st        = carriles[carril.id];
          const laneOpt   = getCarrilEstadoOpt(st);
          const isSinUso  = laneOpt.id === "sin_uso" || st.terminal === "sin_uso";
          const termObj   = TODAS_TERMINALES.find(t => t.id === st.terminal);
          const zonaColor = isSinUso ? "#6b7280" : termObj?.zona === "Todas" ? "#fbbf24" : termObj?.zona === "Norte" ? "#38bdf8" : "#a78bfa";
          const expoOpt = SEGUNDO_TRAFICO_OPTS.find(o => o.id === (st.expo || "libre"));
          const expoContOpt = SEGUNDO_CONTENEDOR_OPTS.find(o => o.id === st.expo_contenedor);
          const impoOpt = SEGUNDO_TRAFICO_OPTS.find(o => o.id === (st.impo || "libre"));
          const isChanged = getCarrilEstadoId(st) !== "libre" || st.retornos || st.terminal !== carril.defaultTerminal || (st.expo && st.expo !== "libre") || (st.impo && st.impo !== "libre");
          return (
            <div key={carril.id} style={{ background:"rgba(255,255,255,0.08)", backdropFilter:"blur(12px)", WebkitBackdropFilter:"blur(12px)", border:`1px solid ${laneOpt.id !== "libre" ? laneOpt.color+"66" : zonaColor+"44"}`, borderRadius:"12px", padding:"14px", marginBottom:"14px" }}>
              <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", marginBottom:"12px" }}>
                <div>
                  <div style={{ display:"flex", alignItems:"center", gap:"8px" }}>
                    <div style={{ background:"#38bdf822", border:"1px solid #38bdf844", borderRadius:"6px", padding:"3px 10px", color:"#38bdf8", fontFamily:getFont(theme, "secondary"), fontSize:"13px", fontWeight:"700" }}>{carril.label}</div>
                    <Badge color="#22c55e" small>INGRESO</Badge>
                  </div>
                  <div style={{ color:"rgba(255,255,255,0.4)", fontSize:"10px", fontFamily:getFont(theme, "secondary"), marginTop:"4px" }}>{timeAgo(st.lastUpdate)} · {st.updatedBy}</div>
                </div>
                <div style={{ display:"flex", flexDirection:"column", alignItems:"flex-end", gap:"5px" }}>
                  <div style={{ display:"flex", gap:"5px", flexWrap:"wrap", justifyContent:"flex-end" }}>
                    <Badge color={laneOpt.color} small>{laneOpt.label.toUpperCase()}</Badge>
                    {st.retornos && <Badge color="#f97316" small>RETORNOS</Badge>}
                    {expoOpt && expoOpt.id !== "libre" && <Badge color={expoOpt.color} small>EXPO {expoOpt.label}</Badge>}
                    {expoContOpt && <Badge color={expoContOpt.color} small>{expoContOpt.label}</Badge>}
                    {impoOpt && impoOpt.id !== "libre" && <Badge color={impoOpt.color} small>IMPO {impoOpt.label}</Badge>}
                  </div>
                  {isChanged && <button onClick={() => resetOne(carril.id)} style={{ padding:"3px 8px", background:"#22c55e15", border:"1px solid #22c55e44", borderRadius:"5px", color:"#22c55e", fontFamily:getFont(theme, "secondary"), fontSize:"10px", cursor:"pointer", fontWeight:"700" }}>NORMAL</button>}
                </div>
              </div>
              <div style={{ background:zonaColor+"11", border:`1px solid ${zonaColor}33`, borderRadius:"8px", padding:"10px 12px", marginBottom:"12px", display:"flex", alignItems:"center", justifyContent:"space-between" }}>
                <div>
                  <div style={{ fontSize:"9px", color:"rgba(255,255,255,0.5)", fontFamily:getFont(theme, "secondary"), letterSpacing:"1px", marginBottom:"2px" }}>TERMINAL ASIGNADA HOY</div>
                  {isSinUso ? (
                    <>
                      <div style={{ color:zonaColor, fontFamily:getFont(theme, "secondary"), fontWeight:"800", fontSize:"15px" }}>SIN USO</div>
                      <div style={{ color:"rgba(255,255,255,0.35)", fontSize:"10px", marginTop:"1px" }}>Carril no disponible</div>
                    </>
                  ) : (
                    <>
                      <div style={{ color:zonaColor, fontFamily:getFont(theme, "secondary"), fontWeight:"700", fontSize:"15px" }}>{termObj?.name}</div>
                      <div style={{ color:"rgba(255,255,255,0.4)", fontSize:"10px", marginTop:"1px" }}>
                        {termObj?.zona === "Todas" ? "Todas las terminales" : `Zona ${termObj?.zona}`}
                      </div>
                    </>
                  )}
                </div>
                <span style={{ fontSize:"22px" }}>🚛</span>
              </div>
              <div style={{ fontSize:"10px", color:"rgba(255,255,255,0.5)", fontFamily:getFont(theme, "secondary"), letterSpacing:"1px", marginBottom:"8px" }}>CAMBIAR TERMINAL:</div>
              <div style={{ marginBottom:"12px" }}>
                <WheelPickerSelect
                  value={st.terminal || carril.defaultTerminal}
                  options={terminalOptionsSegundo}
                  onChange={(v) => updateIngreso(carril.id,"terminal",v)}
                  pending={!!pendingKeys[`${carril.id}:terminal`]}
                  theme={theme}
                  title={`${carril.label} · Terminal / uso`}
                />
              </div>

              <div style={{ fontSize:"10px", color:"rgba(255,255,255,0.5)", fontFamily:getFont(theme, "secondary"), letterSpacing:"1px", marginBottom:"7px", marginTop:"4px" }}>ESTADO DEL CARRIL:</div>
              <div style={{ marginBottom:"8px" }}>
                <WheelPickerSelect
                  value={getCarrilEstadoId(st)}
                  options={CARRIL_ESTADO_OPTS}
                  onChange={(v) => updateIngresoEstado(carril.id, v || "libre")}
                  pending={!!pendingKeys[`${carril.id}:estado_carril`]}
                  theme={theme}
                  title={`${carril.label} · Estado del carril`}
                />
              </div>
              <div style={{ marginBottom:"10px" }}>
                <SegmentedToggle
                  value={!!st.retornos}
                  onChange={(v) => updateIngreso(carril.id,"retornos",v)}
                  leftLabel="SIN RETORNOS" rightLabel="CON RETORNOS"
                  leftColor="#22c55e" rightColor="#f97316"
                  pending={!!pendingKeys[`${carril.id}:retornos`]}
                  theme={theme}
                />
              </div>
              <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:"8px" }}>
                <div>
                  <div style={{ fontSize:"9px", color:"#f97316", fontFamily:getFont(theme, "secondary"), letterSpacing:"1px", marginBottom:"5px", fontWeight:"700" }}>📤 EXPORTACIÓN — TRÁFICO</div>
                  <WheelPickerSelect
                    value={st.expo || "libre"}
                    options={SEGUNDO_TRAFICO_OPTS}
                    onChange={(v) => updateIngreso(carril.id,"expo",v)}
                    pending={!!pendingKeys[`${carril.id}:expo`]}
                    theme={theme}
                  />
                  <div style={{ fontSize:"9px", color:"#f97316", fontFamily:getFont(theme, "secondary"), letterSpacing:"1px", marginBottom:"5px", marginTop:"8px", fontWeight:"700" }}>CONTENEDOR EXPO</div>
                  <WheelPickerSelect
                    value={st.expo_contenedor}
                    options={SEGUNDO_CONTENEDOR_OPTS}
                    onChange={(v) => updateIngreso(carril.id,"expo_contenedor", v)}
                    placeholder="— Sin especificar —"
                    allowClear
                    pending={!!pendingKeys[`${carril.id}:expo_contenedor`]}
                    theme={theme}
                  />
                </div>
                <div>
                  <div style={{ fontSize:"9px", color:"#38bdf8", fontFamily:getFont(theme, "secondary"), letterSpacing:"1px", marginBottom:"5px", fontWeight:"700" }}>📥 IMPORTACIÓN — TRÁFICO</div>
                  <WheelPickerSelect
                    value={st.impo || "libre"}
                    options={SEGUNDO_TRAFICO_OPTS}
                    onChange={(v) => updateIngreso(carril.id,"impo",v)}
                    pending={!!pendingKeys[`${carril.id}:impo`]}
                    theme={theme}
                  />
                </div>
              </div>
            </div>
          );
        })}

        <SectionLabel text="CARRIL DE SALIDA (C4)" />
        {(() => { const c4LaneOpt = getCarrilEstadoOpt(carriles.c4); return (
        <div style={{ background:"rgba(255,255,255,0.08)", backdropFilter:"blur(12px)", WebkitBackdropFilter:"blur(12px)", border:`1px solid ${c4LaneOpt.id !== "libre" ? c4LaneOpt.color+"66" : "#f9731644"}`, borderRadius:"12px", padding:"14px", marginBottom:"14px" }}>
          <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:"12px" }}>
            <div>
              <div style={{ display:"flex", alignItems:"center", gap:"8px" }}>
                <div style={{ background:"#f9731622", border:"1px solid #f9731644", borderRadius:"6px", padding:"3px 10px", color:"#f97316", fontFamily:getFont(theme, "secondary"), fontSize:"13px", fontWeight:"700" }}>Carril 4</div>
                <Badge color="#f97316" small>SALIDA</Badge>
              </div>
              <div style={{ color:"rgba(255,255,255,0.4)", fontSize:"10px", fontFamily:getFont(theme, "secondary"), marginTop:"4px" }}>{timeAgo(carriles.c4.lastUpdate)} · {carriles.c4.updatedBy}</div>
            </div>
            <Badge color={c4LaneOpt.color} small>{c4LaneOpt.label.toUpperCase()}</Badge>
          </div>
          <div style={{ background:"#f9731611", border:"1px solid #f9731633", borderRadius:"8px", padding:"10px 12px", marginBottom:"12px", display:"flex", alignItems:"center", gap:"10px" }}>
            <span style={{ fontSize:"22px" }}>🚚</span>
            <div>
              <div style={{ color:"#f97316", fontFamily:getFont(theme, "secondary"), fontWeight:"700", fontSize:"13px" }}>Salida General del Puerto</div>
              <div style={{ color:"rgba(255,255,255,0.4)", fontSize:"10px", marginTop:"1px" }}>Todos los vehículos en salida</div>
            </div>
          </div>
          <div style={{ fontSize:"10px", color:"rgba(255,255,255,0.5)", fontFamily:getFont(theme, "secondary"), letterSpacing:"1px", marginBottom:"7px", marginTop:"4px" }}>ESTADO DEL CARRIL:</div>
          <div style={{ marginBottom:"8px" }}>
            <WheelPickerSelect
              value={getCarrilEstadoId(carriles.c4)}
              options={CARRIL_ESTADO_OPTS}
              onChange={(v) => updateSalidaEstado(v || "libre")}
              pending={!!pendingKeys["c4:estado_carril"]}
              theme={theme}
              title="Carril 4 · Estado del carril"
            />
          </div>
          <div style={{ marginBottom:"10px" }}>
            <SegmentedToggle
              value={!!carriles.c4.retornos}
              onChange={(v) => updateSalida("retornos",v)}
              leftLabel="SIN RETORNOS" rightLabel="CON RETORNOS"
              leftColor="#22c55e" rightColor="#f97316"
              pending={!!pendingKeys["c4:retornos"]}
              theme={theme}
            />
          </div>
          <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:"8px" }}>
            <div>
              <div style={{ fontSize:"9px", color:"#f97316", fontFamily:getFont(theme, "secondary"), letterSpacing:"1px", marginBottom:"5px", fontWeight:"700" }}>📤 EXPORTACIÓN — TRÁFICO</div>
              <WheelPickerSelect
                value={carriles.c4.expo || "libre"}
                options={SEGUNDO_TRAFICO_OPTS}
                onChange={(v) => updateSalida("expo",v)}
                pending={!!pendingKeys["c4:expo"]}
                theme={theme}
              />
              <div style={{ fontSize:"9px", color:"#f97316", fontFamily:getFont(theme, "secondary"), letterSpacing:"1px", marginBottom:"5px", marginTop:"8px", fontWeight:"700" }}>CONTENEDOR EXPO</div>
              <WheelPickerSelect
                value={carriles.c4.expo_contenedor}
                options={SEGUNDO_CONTENEDOR_OPTS}
                onChange={(v) => updateSalida("expo_contenedor", v)}
                placeholder="— Sin especificar —"
                allowClear
                pending={!!pendingKeys["c4:expo_contenedor"]}
                theme={theme}
              />
            </div>
            <div>
              <div style={{ fontSize:"9px", color:"#38bdf8", fontFamily:getFont(theme, "secondary"), letterSpacing:"1px", marginBottom:"5px", fontWeight:"700" }}>📥 IMPORTACIÓN — TRÁFICO</div>
              <WheelPickerSelect
                value={carriles.c4.impo || "libre"}
                options={SEGUNDO_TRAFICO_OPTS}
                onChange={(v) => updateSalida("impo",v)}
                pending={!!pendingKeys["c4:impo"]}
                theme={theme}
              />
            </div>
          </div>
        </div>
        ); })()}

        {/* ── Segundo Acceso Por Fases ── */}
        <div style={{ marginTop:"8px" }}>
          <div style={{ display:"flex", alignItems:"center", gap:"8px", marginBottom:"12px" }}>
            <div style={{ flex:1, height:"1px", background:"rgba(52,211,153,0.2)" }} />
            <div style={{ display:"flex", alignItems:"center", gap:"6px", padding:"5px 12px", background:"rgba(52,211,153,0.08)", border:"1px solid rgba(52,211,153,0.25)", borderRadius:"20px" }}>
              <span style={{ fontSize:"13px" }}>🗺️</span>
              <span style={{ fontFamily:getFont(theme,"secondary"), fontSize:"11px", color:"#34d399", fontWeight:"800", letterSpacing:"1px" }}>SEGUNDO ACCESO POR FASES</span>
            </div>
            <div style={{ flex:1, height:"1px", background:"rgba(52,211,153,0.2)" }} />
          </div>
          <TrafficMapSegundo theme={theme} myId={myId} />
        </div>
      </>}

      {/* ════════════════════════════════════════════════════
          SUB-TAB: CONFINADA
      ════════════════════════════════════════════════════ */}
      {subTab === "confinada" && <>
        {/* ── MINI-MAPA VIAL CONFINADA — compacto ── */}
        {(() => {
          const getCarrilColor = (id) => {
            const st = confinada[id];
            if (!st) return "#6b7280";
            const opt = getCarrilEstadoOpt(st);
            if (opt.id !== "libre") return opt.color;
            if (st.transferencia) return "#fbbf24";
            return "#22c55e";
          };
          const c1 = getCarrilColor("cf_c1");
          const c2 = getCarrilColor("cf_c2");
          const c3 = getCarrilColor("cf_c3");

          const getTermShort = (id) => {
            const st = confinada[id];
            if (!st) return "—";
            if (getCarrilEstadoId(st) === "sin_uso" || st.terminal === "sin_uso") return "SIN USO";
            if (st.terminal === "general") return "GENERAL";
            const found = TODAS_TERMINALES.find(t => t.id === st.terminal);
            return found ? found.name : st.terminal.toUpperCase();
          };
          const t1 = getTermShort("cf_c1");
          const t2 = getTermShort("cf_c2");
          const t3 = getTermShort("cf_c3");

          return (
            <div style={{ background:"rgba(4,10,22,0.95)", border:"1px solid rgba(167,139,250,0.25)", borderRadius:"12px", padding:"10px 12px", marginBottom:"16px" }}>
              {/* Header */}
              <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:"8px" }}>
                <span style={{ fontSize:"9px", color:"rgba(167,139,250,0.7)", fontFamily:getFont(theme, "secondary"), letterSpacing:"1.5px", fontWeight:"700" }}>ZONA CONFINADA · VISTA VIAL</span>
                <span style={{ fontSize:"9px", color:"rgba(255,255,255,0.25)", fontFamily:getFont(theme, "secondary") }}>→ entrada puerto</span>
              </div>

              {/* SVG compacto */}
              <svg viewBox="0 0 300 72" style={{ width:"100%", height:"auto", display:"block" }} xmlns="http://www.w3.org/2000/svg">
                {/* Fondo carretera */}
                <rect width="300" height="72" fill="#0a0f1a" rx="6"/>

                {/* Zona entrada (derecha) */}
                <rect x="268" y="0" width="32" height="72" fill="#071828" rx="0"/>
                <line x1="268" y1="0" x2="268" y2="72" stroke="rgba(56,189,248,0.35)" strokeWidth="1" strokeDasharray="4,3"/>
                <text x="284" y="40" textAnchor="middle" fill="rgba(56,189,248,0.5)" fontSize="5.5" fontFamily="DM Sans,sans-serif" fontWeight="700" transform="rotate(-90,284,40)">PUERTO</text>

                {/* Zona salida (izquierda) */}
                <rect x="0" y="0" width="28" height="72" fill="#071a09" rx="0"/>
                <line x1="28" y1="0" x2="28" y2="72" stroke="rgba(34,197,94,0.2)" strokeWidth="1" strokeDasharray="3,3"/>
                <text x="14" y="40" textAnchor="middle" fill="rgba(34,197,94,0.45)" fontSize="5.5" fontFamily="DM Sans,sans-serif" fontWeight="700" transform="rotate(-90,14,40)">2° ACCESO</text>

                {/* ── Carril 1 — franja superior ── */}
                <rect x="28" y="2" width="240" height="20" fill={c1 + "20"} rx="2"/>
                <line x1="28" y1="2"  x2="268" y2="2"  stroke={c1} strokeWidth="1.5" opacity="0.6"/>
                <line x1="28" y1="22" x2="268" y2="22" stroke="rgba(255,255,255,0.08)" strokeWidth="1" strokeDasharray="6,5"/>
                <rect x="28" y="2" width="3" height="20" fill={c1} opacity="0.9"/>
                <text x="32" y="15" fill="rgba(255,255,255,0.6)" fontSize="6" fontFamily="DM Sans,sans-serif" fontWeight="700">C1</text>
                {/* Terminal en centro */}
                <text x="148" y="15" textAnchor="middle" fill={c1} fontSize="6.5" fontFamily="DM Sans,sans-serif" fontWeight="800" opacity="0.9">{t1}</text>

                {/* ── Carril 2 — franja media ── */}
                <rect x="28" y="26" width="240" height="20" fill={c2 + "20"} rx="2"/>
                <line x1="28" y1="26" x2="268" y2="26" stroke={c2} strokeWidth="1.5" opacity="0.6"/>
                <line x1="28" y1="46" x2="268" y2="46" stroke="rgba(255,255,255,0.08)" strokeWidth="1" strokeDasharray="6,5"/>
                <rect x="28" y="26" width="3" height="20" fill={c2} opacity="0.9"/>
                <text x="32" y="39" fill="rgba(255,255,255,0.6)" fontSize="6" fontFamily="DM Sans,sans-serif" fontWeight="700">C2</text>
                <text x="148" y="39" textAnchor="middle" fill={c2} fontSize="6.5" fontFamily="DM Sans,sans-serif" fontWeight="800" opacity="0.9">{t2}</text>

                {/* ── Carril 3 — franja inferior ── */}
                <rect x="28" y="50" width="240" height="20" fill={c3 + "20"} rx="2"/>
                <line x1="28" y1="50" x2="268" y2="50" stroke={c3} strokeWidth="1.5" opacity="0.6"/>
                <line x1="28" y1="70" x2="268" y2="70" stroke={c3} strokeWidth="1.5" opacity="0.6"/>
                <rect x="28" y="50" width="3" height="20" fill={c3} opacity="0.9"/>
                <text x="32" y="63" fill="rgba(255,255,255,0.6)" fontSize="6" fontFamily="DM Sans,sans-serif" fontWeight="700">C3</text>
                <text x="148" y="63" textAnchor="middle" fill={c3} fontSize="6.5" fontFamily="DM Sans,sans-serif" fontWeight="800" opacity="0.9">{t3}</text>
              </svg>

              {/* Leyenda inline compacta */}
              <div style={{ display:"flex", gap:"10px", marginTop:"7px", flexWrap:"wrap" }}>
                {[["#22c55e","Libre"],["#f59e0b","Tráfico lento"],["#f97316","Tráfico moderado"],["#ef4444","Saturado"],["#dc2626","Bloqueo"],["#6b7280","Sin uso"]].map(([c,l]) => (
                  <div key={l} style={{ display:"flex", alignItems:"center", gap:"3px" }}>
                    <div style={{ width:"8px", height:"3px", background:c, borderRadius:"1px" }}/>
                    <span style={{ fontSize:"8px", color:"rgba(255,255,255,0.4)", fontFamily:getFont(theme, "secondary") }}>{l}</span>
                  </div>
                ))}
              </div>
            </div>
          );
        })()}

        <SectionLabel text="CARRILES DE INGRESO (C1–C3) · ZONA SUR" rightBtn={<NormalBtn onClick={resetAllConfinada} label="TODO NORMAL" />} />

        {CONFINADA_CARRILES.map(carril => {
          const st = confinada[carril.id];
          const laneOpt = getCarrilEstadoOpt(st);
          const isSinUso = laneOpt.id === "sin_uso" || st.terminal === "sin_uso";
          const termObj = TODAS_TERMINALES.find(t => t.id === st.terminal);
          const expoOpt = SEGUNDO_TRAFICO_OPTS.find(o => o.id === (st.expo || "libre"));
          const expoContOpt = SEGUNDO_CONTENEDOR_OPTS.find(o => o.id === st.expo_contenedor);
          const impoOpt = SEGUNDO_TRAFICO_OPTS.find(o => o.id === (st.impo || "libre"));
          const borderColor = isSinUso ? "#6b7280" : st.terminal==="general" ? "#fbbf24" : st.transferencia ? "#fbbf24" : laneOpt.id !== "libre" ? laneOpt.color : "#a78bfa";
          const isChanged = getCarrilEstadoId(st) !== "libre" || st.retornos || st.transferencia || st.terminal !== carril.defaultTerminal || st.terminal==="general" || (st.expo && st.expo !== "libre") || (st.impo && st.impo !== "libre");
          return (
            <div key={carril.id} style={{ background:"rgba(255,255,255,0.08)", backdropFilter:"blur(12px)", WebkitBackdropFilter:"blur(12px)", border:`1px solid ${borderColor}44`, borderRadius:"12px", padding:"14px", marginBottom:"14px" }}>
              {/* Header carril */}
              <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", marginBottom:"12px" }}>
                <div>
                  <div style={{ display:"flex", alignItems:"center", gap:"8px" }}>
                    <div style={{ background:"#a78bfa22", border:"1px solid #a78bfa44", borderRadius:"6px", padding:"3px 10px", color:"#a78bfa", fontFamily:getFont(theme, "secondary"), fontSize:"13px", fontWeight:"700" }}>{carril.label}</div>
                    {isSinUso
                      ? <Badge color="#6b7280" small>🚫 SIN USO</Badge>
                      : <Badge color="#22c55e" small>INGRESO</Badge>
                    }
                    {st.transferencia && !isSinUso && <Badge color="#fbbf24" small>🔄 2° ACCESO</Badge>}
                  </div>
                  <div style={{ color:"rgba(255,255,255,0.4)", fontSize:"10px", fontFamily:getFont(theme, "secondary"), marginTop:"4px" }}>{timeAgo(st.lastUpdate)} · {st.updatedBy}</div>
                </div>
                <div style={{ display:"flex", flexDirection:"column", alignItems:"flex-end", gap:"5px" }}>
                  <div style={{ display:"flex", gap:"5px", flexWrap:"wrap", justifyContent:"flex-end" }}>
                    <Badge color={laneOpt.color} small>{laneOpt.label.toUpperCase()}</Badge>
                    {st.retornos && <Badge color="#f97316" small>RETORNOS</Badge>}
                    {expoOpt && expoOpt.id !== "libre" && <Badge color={expoOpt.color} small>EXPO {expoOpt.label}</Badge>}
                    {expoContOpt && <Badge color={expoContOpt.color} small>{expoContOpt.label}</Badge>}
                    {impoOpt && impoOpt.id !== "libre" && <Badge color={impoOpt.color} small>IMPO {impoOpt.label}</Badge>}
                  </div>
                  {isChanged && <button onClick={() => resetOneConfinada(carril.id)} style={{ padding:"3px 8px", background:"#a78bfa15", border:"1px solid #a78bfa44", borderRadius:"5px", color:"#a78bfa", fontFamily:getFont(theme, "secondary"), fontSize:"10px", cursor:"pointer", fontWeight:"700" }}>NORMAL</button>}
                </div>
              </div>

              {/* Terminal asignada */}
              <div style={{ background: isSinUso ? "#6b728011" : st.terminal==="general" ? "#fbbf2411" : "#a78bfa11", border:`1px solid ${isSinUso?"#6b728033":st.terminal==="general"?"#fbbf2433":"#a78bfa33"}`, borderRadius:"8px", padding:"10px 12px", marginBottom:"12px", display:"flex", alignItems:"center", justifyContent:"space-between" }}>
                <div>
                  <div style={{ fontSize:"9px", color:"rgba(255,255,255,0.5)", fontFamily:getFont(theme, "secondary"), letterSpacing:"1px", marginBottom:"2px" }}>TERMINAL ASIGNADA HOY</div>
                  {isSinUso
                    ? <><div style={{ color:"#6b7280", fontFamily:getFont(theme, "secondary"), fontWeight:"700", fontSize:"15px" }}>SIN USO</div><div style={{ color:"rgba(255,255,255,0.3)", fontSize:"10px", marginTop:"1px" }}>Carril no disponible</div></>
                    : st.terminal === "general"
                    ? <><div style={{ color:"#fbbf24", fontFamily:getFont(theme, "secondary"), fontWeight:"700", fontSize:"15px" }}>GENERAL</div><div style={{ color:"rgba(255,255,255,0.4)", fontSize:"10px", marginTop:"1px" }}>Todas las terminales</div></>
                    : <><div style={{ color:"#a78bfa", fontFamily:getFont(theme, "secondary"), fontWeight:"700", fontSize:"15px" }}>{termObj?.name}</div><div style={{ color:"rgba(255,255,255,0.4)", fontSize:"10px", marginTop:"1px" }}>Zona {termObj?.zona}</div></>
                  }
                </div>
                <span style={{ fontSize:"22px" }}>{isSinUso ? "🚫" : "🚛"}</span>
              </div>

              {/* Cambiar terminal — selector de rueda compacto */}
              <div style={{ fontSize:"10px", color:"rgba(255,255,255,0.5)", fontFamily:getFont(theme, "secondary"), letterSpacing:"1px", marginBottom:"8px" }}>CAMBIAR TERMINAL:</div>
              <div style={{ marginBottom:"12px" }}>
                <WheelPickerSelect
                  value={st.terminal || carril.defaultTerminal}
                  options={terminalOptionsConfinada}
                  onChange={(v) => updateConfinada(carril.id,"terminal",v)}
                  pending={!!pendingKeys[`${carril.id}:terminal`]}
                  theme={theme}
                  title={`Confinada ${carril.label} · Terminal / uso`}
                />
              </div>

              {/* Estado del carril */}
              <div style={{ fontSize:"10px", color:"rgba(255,255,255,0.5)", fontFamily:getFont(theme, "secondary"), letterSpacing:"1px", marginBottom:"7px" }}>ESTADO DEL CARRIL:</div>
              <div style={{ marginBottom:"6px" }}>
                <WheelPickerSelect
                  value={getCarrilEstadoId(st)}
                  options={CARRIL_ESTADO_OPTS}
                  onChange={(v) => updateConfinadaEstado(carril.id, v || "libre")}
                  pending={!!pendingKeys[`${carril.id}:estado_carril`]}
                  theme={theme}
                  title={`Confinada ${carril.label} · Estado del carril`}
                />
              </div>
              <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:"6px", marginBottom:"10px" }}>
                <button onClick={() => updateConfinada(carril.id,"retornos",false)} style={{ padding:"9px", background: !st.retornos?"#22c55e22":"#0a1628", border:`1px solid ${!st.retornos?"#22c55e":"#1e3a5f"}`, borderRadius:"8px", color: !st.retornos?"#22c55e":"#64748b", fontFamily:getFont(theme, "secondary"), fontSize:"11px", cursor:"pointer", fontWeight: !st.retornos?"700":"400" }}>SIN RETORNOS</button>
                <button onClick={() => updateConfinada(carril.id,"retornos",true)}  style={{ padding:"9px", background: st.retornos?"#f9731622":"#0a1628",  border:`1px solid ${st.retornos?"#f97316":"#1e3a5f"}`,  borderRadius:"8px", color: st.retornos?"#f97316":"#64748b",  fontFamily:getFont(theme, "secondary"), fontSize:"11px", cursor:"pointer", fontWeight: st.retornos?"700":"400"  }}>CON RETORNOS</button>
              </div>

              {/* Tráfico expo/impo */}
              <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:"8px", marginBottom:"10px" }}>
                <div>
                  <div style={{ fontSize:"9px", color:"#f97316", fontFamily:getFont(theme, "secondary"), letterSpacing:"1px", marginBottom:"5px", fontWeight:"700" }}>📤 EXPORTACIÓN — TRÁFICO</div>
                  <WheelPickerSelect
                    value={st.expo || "libre"}
                    options={SEGUNDO_TRAFICO_OPTS}
                    onChange={(v) => updateConfinada(carril.id,"expo",v)}
                    pending={!!pendingKeys[`${carril.id}:expo`]}
                    theme={theme}
                  />
                  <div style={{ fontSize:"9px", color:"#f97316", fontFamily:getFont(theme, "secondary"), letterSpacing:"1px", marginBottom:"5px", marginTop:"8px", fontWeight:"700" }}>CONTENEDOR EXPO</div>
                  <WheelPickerSelect
                    value={st.expo_contenedor}
                    options={SEGUNDO_CONTENEDOR_OPTS}
                    onChange={(v) => updateConfinada(carril.id,"expo_contenedor", v)}
                    placeholder="— Sin especificar —"
                    allowClear
                    pending={!!pendingKeys[`${carril.id}:expo_contenedor`]}
                    theme={theme}
                  />
                </div>
                <div>
                  <div style={{ fontSize:"9px", color:"#38bdf8", fontFamily:getFont(theme, "secondary"), letterSpacing:"1px", marginBottom:"5px", fontWeight:"700" }}>📥 IMPORTACIÓN — TRÁFICO</div>
                  <WheelPickerSelect
                    value={st.impo || "libre"}
                    options={SEGUNDO_TRAFICO_OPTS}
                    onChange={(v) => updateConfinada(carril.id,"impo",v)}
                    pending={!!pendingKeys[`${carril.id}:impo`]}
                    theme={theme}
                  />
                </div>
              </div>

              {/* Transferencia de Aduana — al final */}
              <div style={{ background: st.transferencia ? "#fbbf2415" : "rgba(255,255,255,0.03)", border:`1px solid ${st.transferencia?"#fbbf2466":"rgba(255,255,255,0.08)"}`, borderRadius:"10px", padding:"12px" }}>
                <div style={{ fontSize:"10px", color:"#fbbf24", fontFamily:getFont(theme, "secondary"), letterSpacing:"1px", marginBottom:"8px", fontWeight:"700" }}>🔄 SEGUNDO ACCESO</div>
                <div style={{ fontSize:"11px", color:"rgba(255,255,255,0.5)", fontFamily:getFont(theme, "secondary"), marginBottom:"8px" }}>Indica si este carril opera como Segundo Acceso.</div>
                <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:"6px" }}>
                  <button onClick={() => updateConfinada(carril.id,"transferencia",false)} style={{ padding:"10px", background: !st.transferencia?"#22c55e22":"#0a1628", border:`1px solid ${!st.transferencia?"#22c55e":"#1e3a5f"}`, borderRadius:"8px", color: !st.transferencia?"#22c55e":"#64748b", fontFamily:getFont(theme, "secondary"), fontSize:"11px", cursor:"pointer", fontWeight: !st.transferencia?"700":"400" }}>NORMAL</button>
                  <button onClick={() => updateConfinada(carril.id,"transferencia",true)}  style={{ padding:"10px", background: st.transferencia?"#fbbf2422":"#0a1628",  border:`1px solid ${st.transferencia?"#fbbf24":"#1e3a5f"}`,  borderRadius:"8px", color: st.transferencia?"#fbbf24":"#64748b",  fontFamily:getFont(theme, "secondary"), fontSize:"11px", cursor:"pointer", fontWeight: st.transferencia?"700":"400"  }}>🔄 TRANSFERENCIA</button>
                </div>
              </div>
            </div>
          );
        })}
      </>}

      <ToastBox toast={toast} />
    </div>
  );
}

// ─── TAB: CARRILES ────────────────────────────────────────────────────────────
function CarrilesTab() {
  const theme = React.useContext(ThemeContext);
  const [estado,  setEstado]  = useState(mkCarrilesState);
  const [accView, setAccView] = useState(() => {
    try { return sessionStorage.getItem("carriles_acc") || "pezvela"; } catch { return "pezvela"; }
  });
  const setAccViewPersist = (v) => {
    try { sessionStorage.setItem("carriles_acc", v); } catch {}
    setAccView(v);
  };
  const [toast,   setToast]   = useState(null);
  const notify = (msg, color = "#38bdf8") => { setToast({ msg, color }); setTimeout(() => setToast(null), 2500); };

  const TABLA  = "carriles";
  const ROW_ID = "expo_impo";

  const saveToSupa = async (newState) => {
    await sb.from(TABLA).upsert({ id: ROW_ID, data: newState });
  };

  useEffect(() => {
    sb.from(TABLA).select("*").eq("id", ROW_ID).single().then(({ data }) => {
      if (data?.data) setEstado(data.data);
    });
    const chan = sb.channel("carriles-rt")
      .on("postgres_changes", { event: "*", schema: "public", table: TABLA }, ({ new: r }) => {
        if (r?.id === ROW_ID && r?.data) setEstado(r.data);
      }).subscribe();
    return () => sb.removeChannel(chan);
  }, []);

  const toggle = async (cid, value) => {
    const next = { ...estado, [cid]: { ...estado[cid], abierto: value, lastUpdate: Date.now(), updatedBy: "Tú" } };
    setEstado(next);
    await saveToSupa(next);
    await auditLog({ action:"modificar_carril_expo_impo", section:"carriles", entityId:cid, before:estado[cid], after:{ carril:cid, campo:"abierto", value, valor_label:value ? "Abierto" : "Cerrado", summary:`${getDeviceId()} marcó ${cid.toUpperCase()} como ${value ? "Abierto" : "Cerrado"}` }, actor:`Usuario_${getDeviceId().slice(-4)}` });
    notify(value ? "✓ Carril abierto" : "⛔ Carril cerrado", value ? "#22c55e" : "#6b7280");
    await publicarNoticia({ tipo: "carril", icono: "🚦", color: value ? "#22c55e" : "#6b7280", titulo: `Carril ${cid.toUpperCase()} — ${value ? "Abierto" : "Cerrado"}`, detalle: "Estado de carril expo/impo actualizado" });
  };

  const resetAcceso = async (acc) => {
    const next = { ...estado };
    acc.carriles.forEach(c => { next[c.id] = { abierto: true, lastUpdate: Date.now(), updatedBy: "Reset" }; });
    setEstado(next);
    await saveToSupa(next);
    notify("✓ Acceso restablecido", "#22c55e");
  };

  const resetAll = async () => {
    const next = mkCarrilesState();
    setEstado(next);
    await saveToSupa(next);
    notify("✓ Todo restablecido", "#22c55e");
  };

  const currentAcc   = ACCESOS_CARRILES.find(a => a.id === accView);
  const expoCarriles = currentAcc?.carriles.filter(c => c.tipo === "expo") || [];
  const impoCarriles = currentAcc?.carriles.filter(c => c.tipo === "impo") || [];
  const EXPO_COLOR = "#f59e0b";
  const IMPO_COLOR = "#60a5fa";

  return (
    <div style={{ padding:"16px", paddingBottom:"80px", minHeight:"100vh" }}>
      <div style={{ background:"rgba(255,255,255,0.08)", backdropFilter:"blur(12px)", WebkitBackdropFilter:"blur(12px)", border:"1px solid rgba(255,255,255,0.15)", borderRadius:"12px", padding:"12px", marginBottom:"14px" }}>
        <div style={{ fontSize:"10px", color:"#38bdf8", fontFamily:getFont(theme, "secondary"), letterSpacing:"2px", marginBottom:"4px" }}>CARRILES — PUERTO MANZANILLO</div>
        <div style={{ color:"rgba(255,255,255,0.7)", fontSize:"12px" }}>Estado de carriles de exportación e importación por acceso.</div>
      </div>
      <div style={{ background:"rgba(255,255,255,0.05)", border:"1px solid rgba(255,255,255,0.15)", borderRadius:"12px", padding:"12px", marginBottom:"14px" }}>
        <div style={{ fontSize:"10px", color:"rgba(255,255,255,0.5)", fontFamily:getFont(theme, "secondary"), letterSpacing:"1px", marginBottom:"10px" }}>RESUMEN GENERAL</div>
        {ACCESOS_CARRILES.map(acc => {
          const total    = acc.carriles.length;
          const abiertos = acc.carriles.filter(c => estado[c.id]?.abierto !== false).length;
          const pct      = Math.round((abiertos / total) * 100);
          return (
            <div key={acc.id} style={{ marginBottom:"8px" }}>
              <div style={{ display:"flex", justifyContent:"space-between", marginBottom:"3px" }}>
                <span style={{ fontSize:"11px", color:acc.color, fontFamily:getFont(theme, "secondary"), fontWeight:"700" }}>{acc.label}</span>
                <span style={{ fontSize:"10px", color:"rgba(255,255,255,0.5)", fontFamily:getFont(theme, "secondary") }}>{abiertos}/{total} abiertos</span>
              </div>
              <div style={{ background:"#1e3a5f", borderRadius:"3px", height:"5px", overflow:"hidden" }}>
                <div style={{ width:`${pct}%`, height:"100%", background: pct===100?"#22c55e": pct>50? acc.color:"#ef4444", transition:"width 0.4s", borderRadius:"3px" }} />
              </div>
            </div>
          );
        })}
        <div style={{ display:"flex", justifyContent:"center", gap:"12px", marginTop:"10px", flexWrap:"wrap" }}>
          {[["#f59e0b","EXPORTACIÓN"],["#60a5fa","IMPORTACIÓN"],["#22c55e","ABIERTO"],["#ef4444","CERRADO"]].map(([c,l]) => (
            <div key={l} style={{ display:"flex", alignItems:"center", gap:"3px" }}>
              <div style={{ width:"8px", height:"8px", background:c, borderRadius:"2px" }} />
              <span style={{ fontSize:"8px", color:"rgba(255,255,255,0.5)", fontFamily:getFont(theme, "secondary") }}>{l}</span>
            </div>
          ))}
        </div>
      </div>
      <div style={{ display:"flex", gap:"6px", marginBottom:"16px" }}>
        {ACCESOS_CARRILES.map(acc => (
          <button key={acc.id} onClick={() => setAccViewPersist(acc.id)} style={{ flex:1, padding:"9px 4px", background: accView===acc.id ? acc.color+"22" : "#0a1628", border:`1px solid ${accView===acc.id ? acc.color : "#1e3a5f"}`, borderRadius:"8px", color: accView===acc.id ? acc.color : "#475569", fontFamily:getFont(theme, "secondary"), fontSize:"9px", fontWeight: accView===acc.id?"700":"400", cursor:"pointer", transition:"all 0.15s", textAlign:"center" }}>
            <div style={{ fontSize:"14px", marginBottom:"2px" }}>{acc.zona==="Norte"?"🔵":"🟣"}</div>
            {acc.label}
          </button>
        ))}
      </div>
      {currentAcc && (
        <>
          <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:"14px" }}>
            <div style={{ display:"flex", alignItems:"center", gap:"8px" }}>
              <div style={{ width:"10px", height:"10px", background:currentAcc.color, borderRadius:"50%", boxShadow:`0 0 8px ${currentAcc.color}` }} />
              <span style={{ color:currentAcc.color, fontFamily:getFont(theme, "secondary"), fontWeight:"700", fontSize:"14px" }}>{currentAcc.label}</span>
              <Badge color={currentAcc.zona==="Norte"?"#38bdf8":"#a78bfa"} small>ZONA {currentAcc.zona.toUpperCase()}</Badge>
            </div>
            <NormalBtn onClick={() => resetAcceso(currentAcc)} label="TODO ABIERTO" />
          </div>
          {expoCarriles.length > 0 && (
            <>
              <div style={{ fontSize:"10px", color:EXPO_COLOR, fontFamily:getFont(theme, "secondary"), letterSpacing:"2px", marginBottom:"10px" }}>📤 EXPORTACIÓN</div>
              <div style={{ display:"grid", gridTemplateColumns: expoCarriles.length===1?"1fr":"1fr 1fr", gap:"10px", marginBottom:"16px" }}>
                {expoCarriles.map(carril => {
                  const st = estado[carril.id] || {};
                  return (
                    <div key={carril.id} style={{ background:"rgba(255,255,255,0.08)", backdropFilter:"blur(12px)", WebkitBackdropFilter:"blur(12px)", border:`2px solid ${st.abierto?EXPO_COLOR+"88":"#6b728055"}`, borderRadius:"12px", padding:"14px", textAlign:"center", opacity: st.abierto?1:0.65, transition:"all 0.2s" }}>
                      <div style={{ fontSize:"11px", color:"rgba(255,255,255,0.7)", fontFamily:getFont(theme, "secondary"), marginBottom:"3px" }}>{carril.label}</div>
                      <div style={{ fontSize:"20px", marginBottom:"6px" }}>📤</div>
                      <div style={{ fontSize:"10px", color:EXPO_COLOR, fontFamily:getFont(theme, "secondary"), fontWeight:"700", marginBottom:"12px" }}>EXPORTACIÓN</div>
                      <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:"5px", marginBottom:"8px" }}>
                        <button onClick={() => toggle(carril.id, true)}  style={{ padding:"7px 4px", background: st.abierto?"#22c55e22":"#0a1628", border:`1px solid ${st.abierto?"#22c55e":"#1e3a5f"}`, borderRadius:"6px", color: st.abierto?"#22c55e":"#475569", fontFamily:getFont(theme, "secondary"), fontSize:"10px", cursor:"pointer", fontWeight: st.abierto?"700":"400" }}>✓ ABIERTO</button>
                        <button onClick={() => toggle(carril.id, false)} style={{ padding:"7px 4px", background: !st.abierto?"#6b728022":"#0a1628", border:`1px solid ${!st.abierto?"#6b7280":"#1e3a5f"}`, borderRadius:"6px", color: !st.abierto?"#9ca3af":"#475569", fontFamily:getFont(theme, "secondary"), fontSize:"10px", cursor:"pointer", fontWeight: !st.abierto?"700":"400" }}>⛔ CERRADO</button>
                      </div>
                      <div style={{ padding:"5px", background: st.abierto?"#22c55e15":"#6b728015", borderRadius:"6px", fontSize:"10px", color: st.abierto?"#22c55e":"#6b7280", fontFamily:getFont(theme, "secondary"), fontWeight:"700" }}>{st.abierto?"● OPERANDO":"● CERRADO"}</div>
                      <div style={{ fontSize:"9px", color:"rgba(255,255,255,0.3)", fontFamily:getFont(theme, "secondary"), marginTop:"5px" }}>{timeAgo(st.lastUpdate)}</div>
                    </div>
                  );
                })}
              </div>
            </>
          )}
          {impoCarriles.length > 0 && (
            <>
              <div style={{ fontSize:"10px", color:IMPO_COLOR, fontFamily:getFont(theme, "secondary"), letterSpacing:"2px", marginBottom:"10px" }}>📥 IMPORTACIÓN</div>
              <div style={{ display:"grid", gridTemplateColumns: impoCarriles.length===1?"1fr":"1fr 1fr", gap:"10px", marginBottom:"14px" }}>
                {impoCarriles.map(carril => {
                  const st = estado[carril.id] || {};
                  return (
                    <div key={carril.id} style={{ background:"rgba(255,255,255,0.08)", backdropFilter:"blur(12px)", WebkitBackdropFilter:"blur(12px)", border:`2px solid ${st.abierto?IMPO_COLOR+"88":"#6b728055"}`, borderRadius:"12px", padding:"14px", textAlign:"center", opacity: st.abierto?1:0.65, transition:"all 0.2s" }}>
                      <div style={{ fontSize:"11px", color:"rgba(255,255,255,0.7)", fontFamily:getFont(theme, "secondary"), marginBottom:"3px" }}>{carril.label}</div>
                      <div style={{ fontSize:"20px", marginBottom:"6px" }}>📥</div>
                      <div style={{ fontSize:"10px", color:IMPO_COLOR, fontFamily:getFont(theme, "secondary"), fontWeight:"700", marginBottom:"12px" }}>IMPORTACIÓN</div>
                      <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:"5px", marginBottom:"8px" }}>
                        <button onClick={() => toggle(carril.id, true)}  style={{ padding:"7px 4px", background: st.abierto?"#22c55e22":"#0a1628", border:`1px solid ${st.abierto?"#22c55e":"#1e3a5f"}`, borderRadius:"6px", color: st.abierto?"#22c55e":"#475569", fontFamily:getFont(theme, "secondary"), fontSize:"10px", cursor:"pointer", fontWeight: st.abierto?"700":"400" }}>✓ ABIERTO</button>
                        <button onClick={() => toggle(carril.id, false)} style={{ padding:"7px 4px", background: !st.abierto?"#6b728022":"#0a1628", border:`1px solid ${!st.abierto?"#6b7280":"#1e3a5f"}`, borderRadius:"6px", color: !st.abierto?"#9ca3af":"#475569", fontFamily:getFont(theme, "secondary"), fontSize:"10px", cursor:"pointer", fontWeight: !st.abierto?"700":"400" }}>⛔ CERRADO</button>
                      </div>
                      <div style={{ padding:"5px", background: st.abierto?"#22c55e15":"#6b728015", borderRadius:"6px", fontSize:"10px", color: st.abierto?"#22c55e":"#6b7280", fontFamily:getFont(theme, "secondary"), fontWeight:"700" }}>{st.abierto?"● OPERANDO":"● CERRADO"}</div>
                      <div style={{ fontSize:"9px", color:"rgba(255,255,255,0.3)", fontFamily:getFont(theme, "secondary"), marginTop:"5px" }}>{timeAgo(st.lastUpdate)}</div>
                    </div>
                  );
                })}
              </div>
            </>
          )}
        </>
      )}
      <ToastBox toast={toast} />
    </div>
  );
}

// ─── TAB: NOTICIAS ────────────────────────────────────────────────────────────
// ─── VISOR FULLSCREEN ─────────────────────────────────────────────────────────
function VisorFullscreen({ item, onClose, items = [], currentIndex = 0, onNavigate = null, onDownload = null, downloading = false }) {
  const theme = React.useContext(ThemeContext);
  const isPdf = item?.archivo_url?.toLowerCase().includes(".pdf") || item?.archivo_tipo === "application/pdf";
  const canNavigate = Array.isArray(items) && items.length > 1 && typeof onNavigate === "function";
  const safeIndex = Number.isFinite(currentIndex) ? currentIndex : 0;

  const goPrev = useCallback(() => {
    if (!canNavigate) return;
    onNavigate((safeIndex - 1 + items.length) % items.length);
  }, [canNavigate, onNavigate, safeIndex, items.length]);

  const goNext = useCallback(() => {
    if (!canNavigate) return;
    onNavigate((safeIndex + 1) % items.length);
  }, [canNavigate, onNavigate, safeIndex, items.length]);

  useEffect(() => {
    const handler = (e) => {
      if (e.key === "Escape") onClose();
      if (canNavigate && e.key === "ArrowLeft") goPrev();
      if (canNavigate && e.key === "ArrowRight") goNext();
    };
    document.addEventListener("keydown", handler);
    return () => document.removeEventListener("keydown", handler);
  }, [onClose, canNavigate, goPrev, goNext]);

  if (!item) return null;
  return (
    <div onClick={onClose} style={{ position:"fixed", inset:0, zIndex:9999, background:"rgba(0,0,0,0.95)", display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center", padding:"16px" }}>
      <div onClick={e => e.stopPropagation()} style={{ width:"100%", maxWidth:"1120px", maxHeight:"92vh", display:"flex", flexDirection:"column", gap:"10px" }}>
        {/* Header */}
        <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", flexShrink:0, gap:"12px" }}>
          <div style={{ flex:1, minWidth:0 }}>
            <div style={{ fontFamily:getFont(theme, "secondary"), fontWeight:"700", fontSize:"15px", color:"rgba(255,255,255,0.95)", whiteSpace:"nowrap", overflow:"hidden", textOverflow:"ellipsis" }}>{item.titulo}</div>
            {item.detalle && <div style={{ fontFamily:getFont(theme, "secondary"), fontSize:"11px", color:"rgba(255,255,255,0.5)", marginTop:"2px" }}>{item.detalle}</div>}
            {canNavigate && (
              <div style={{ marginTop:"6px", fontFamily:getFont(theme, "secondary"), fontSize:"10px", color:"#fbbf24", fontWeight:"700" }}>
                Documento {safeIndex + 1} de {items.length}
              </div>
            )}
          </div>
          <button onClick={onClose} style={{ flexShrink:0, width:"38px", height:"38px", borderRadius:"50%", background:"rgba(255,255,255,0.1)", border:"1px solid rgba(255,255,255,0.2)", color:"rgba(255,255,255,0.8)", fontSize:"16px", cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center" }}>✕</button>
        </div>
        {/* Contenido */}
        <div style={{ position:"relative", flex:1, minHeight:0, borderRadius:"16px", overflow:"hidden", background:"#0a1628", border:"1px solid rgba(255,255,255,0.1)", display:"flex", alignItems:"center", justifyContent:"center" }}>
          {isPdf ? (
            <iframe src={item.archivo_url} title={item.titulo} style={{ width:"100%", height:"80vh", border:"none", background:"#fff" }} />
          ) : (
            <img src={item.archivo_url} alt={item.titulo} style={{ width:"100%", height:"80vh", objectFit:"contain", display:"block", background:"#061428" }} />
          )}

          {canNavigate && (
            <>
              <button onClick={goPrev} style={{ position:"absolute", left:"14px", top:"50%", transform:"translateY(-50%)", width:"48px", height:"48px", borderRadius:"50%", border:"1px solid rgba(255,255,255,0.18)", background:"rgba(10,22,40,0.75)", color:"#fff", fontSize:"24px", cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center", backdropFilter:"blur(8px)" }} aria-label="Anterior">‹</button>
              <button onClick={goNext} style={{ position:"absolute", right:"14px", top:"50%", transform:"translateY(-50%)", width:"48px", height:"48px", borderRadius:"50%", border:"1px solid rgba(255,255,255,0.18)", background:"rgba(10,22,40,0.75)", color:"#fff", fontSize:"24px", cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center", backdropFilter:"blur(8px)" }} aria-label="Siguiente">›</button>
            </>
          )}
        </div>
        {/* Acciones */}
        <div style={{ display:"flex", gap:"8px", justifyContent:"center", flexShrink:0, flexWrap:"wrap" }}>
          <a href={item.archivo_url} target="_blank" rel="noopener noreferrer" style={{ padding:"8px 16px", background:"#38bdf822", border:"1px solid #38bdf855", borderRadius:"8px", color:"#38bdf8", fontFamily:getFont(theme, "secondary"), fontSize:"11px", fontWeight:"700", textDecoration:"none", display:"flex", alignItems:"center", gap:"6px" }}>
            Enlace Abrir en nueva pestaña
          </a>
          {onDownload ? (
            <button onClick={() => onDownload(item)} disabled={downloading} style={{ padding:"8px 16px", background: downloading ? "rgba(100,116,139,.18)" : "#22c55e22", border:"1px solid #22c55e55", borderRadius:"8px", color: downloading ? "#94a3b8" : "#22c55e", fontFamily:getFont(theme, "secondary"), fontSize:"11px", fontWeight:"700", textDecoration:"none", display:"flex", alignItems:"center", gap:"6px", cursor: downloading ? "not-allowed" : "pointer" }}>
              {downloading ? "Preparando descarga…" : "⬇️ Descargar con marca de agua"}
            </button>
          ) : (
            <a href={item.archivo_url} download style={{ padding:"8px 16px", background:"#22c55e22", border:"1px solid #22c55e55", borderRadius:"8px", color:"#22c55e", fontFamily:getFont(theme, "secondary"), fontSize:"11px", fontWeight:"700", textDecoration:"none", display:"flex", alignItems:"center", gap:"6px" }}>
              ⬇️ Descargar
            </a>
          )}
        </div>
      </div>
      <div style={{ marginTop:"12px", fontFamily:getFont(theme, "secondary"), fontSize:"10px", color:"rgba(255,255,255,0.25)", textAlign:"center" }}>
        Toca fuera o presiona ESC para cerrar{canNavigate ? " · Usa ← y → para cambiar de archivo" : ""}
      </div>
    </div>
  );
}


// ─── SUBIR COMUNICADO (con fechas y aprobación) ──────────────────────────────
function SubirComunicadoPanel({ onSubido, isAdmin }) {
  const theme = React.useContext(ThemeContext);
  const [titulo, setTitulo] = useState("");
  const [detalle, setDetalle] = useState("");
  const [archivo, setArchivo] = useState(null);
  const [preview, setPreview] = useState(null);
  const [fechaInicio, setFechaInicio] = useState("");
  const [fechaFin, setFechaFin] = useState("");
  const [subiendo, setSubiendo] = useState(false);
  const [error, setError] = useState("");
  const [exito, setExito] = useState(false);
  const inputRef = useRef();

  const localDateInput = (offsetDays = 0) => {
    const d = new Date();
    d.setDate(d.getDate() + offsetDays);
    d.setMinutes(d.getMinutes() - d.getTimezoneOffset());
    return d.toISOString().slice(0, 10);
  };

  const ensureFechaInicio = () => {
    if (!fechaInicio) setFechaInicio(localDateInput(0));
  };

  const plantillasAdmin = [
    {
      id: "tarifa",
      label: "Tarifa pública",
      titulo: "Tarifa pública actualizada",
      detalle: "Se comparte comunicado oficial con tarifa pública vigente para consulta de la comunidad portuaria.",
      duracionDias: 30
    },
    {
      id: "operativo",
      label: "Aviso operativo",
      titulo: "Aviso operativo importante",
      detalle: "Se informa a usuarios y operadores sobre actualización operativa. Favor de revisar el documento adjunto y tomar previsiones.",
      duracionDias: 7
    },
    {
      id: "mantenimiento",
      label: "Mantenimiento",
      titulo: "Mantenimiento programado",
      detalle: "Se informa mantenimiento programado. Considerar posibles ajustes operativos durante el periodo indicado.",
      duracionDias: 3
    },
    {
      id: "horario",
      label: "Horario especial",
      titulo: "Horario especial de atención",
      detalle: "Se comunica horario especial de atención. Revisar el archivo adjunto para mayor detalle.",
      duracionDias: 5
    },
    {
      id: "general",
      label: "Comunicado general",
      titulo: "Comunicado oficial",
      detalle: "Comunicado oficial para conocimiento de usuarios, operadores y comunidad logística.",
      duracionDias: 10
    }
  ];

  const aplicarPlantilla = (tpl) => {
    const inicio = localDateInput(0);
    setTitulo(tpl.titulo);
    setDetalle(tpl.detalle);
    setFechaInicio(inicio);
    setFechaFin(localDateInput(tpl.duracionDias || 7));
    setError("");
  };

  const onFileChange = (e) => {
    const f = e.target.files[0];
    if (!f) return;
    const allowed = ["image/jpeg", "image/png", "image/webp", "application/pdf"];
    if (!allowed.includes(f.type)) {
      setError("Solo se permiten JPG, PNG o PDF");
      return;
    }
    if (f.size > 10 * 1024 * 1024) {
      setError("El archivo no debe superar 10 MB");
      return;
    }
    setError("");
    setArchivo(f);
    if (f.type !== "application/pdf") {
      const reader = new FileReader();
      reader.onload = (ev) => setPreview(ev.target.result);
      reader.readAsDataURL(f);
    } else {
      setPreview("pdf");
    }
  };

  const handleSubir = async () => {
    if (!titulo.trim()) {
      setError("Escribe un título para el comunicado");
      return;
    }
    if (!archivo) {
      setError("Selecciona un archivo");
      return;
    }
    if (!fechaInicio) {
      setError("Especifica la fecha de inicio");
      return;
    }
    if (!fechaFin) {
      setError("Especifica la fecha de término");
      return;
    }

    // Vigencia por fecha completa, sin hora visible para el usuario.
    // Inicio: 00:00:00 del día seleccionado. Fin: 23:59:59 del día seleccionado.
    const inicioDate = new Date(`${fechaInicio}T00:00:00`);
    const finDate = new Date(`${fechaFin}T23:59:59.999`);
    const inicio = inicioDate.toISOString();
    const fin = finDate.toISOString();

    if (finDate < inicioDate) {
      setError("La fecha de término debe ser igual o posterior a la fecha de inicio");
      return;
    }

    setSubiendo(true);
    setError("");
    try {
      const ext = archivo.name.split(".").pop();
      const path = `comunicados/${Date.now()}_${Math.random().toString(36).slice(2)}.${ext}`;
      const { error: upErr } = await sb.storage
        .from("comunicados")
        .upload(path, archivo, { contentType: archivo.type, upsert: false });
      if (upErr) throw upErr;
      const { data: { publicUrl } } = sb.storage.from("comunicados").getPublicUrl(path);
      
      const { data: comunicadoInsertado, error: insErr } = await sb.from("comunicados").insert({
        titulo: titulo.trim(),
        detalle: detalle.trim() || null,
        archivo_url: publicUrl,
        archivo_tipo: archivo.type,
        fecha_inicio: inicio,
        fecha_fin: fin,
        aprobado: isAdmin === true,
        created_at: new Date().toISOString()
      }).select("*").single();
      if (insErr) throw insErr;

      // Si lo publica un admin, ya está aprobado y se replica automáticamente a Noticias.
      if (isAdmin === true && comunicadoInsertado) {
        await syncComunicadoToNoticia(comunicadoInsertado, { processMedia: true });
      }

      setExito(true);
      setTitulo("");
      setDetalle("");
      setArchivo(null);
      setPreview(null);
      setFechaInicio("");
      setFechaFin("");
      if (inputRef.current) inputRef.current.value = "";
      setTimeout(() => setExito(false), 3000);
      if (onSubido) onSubido();
    } catch (err) {
      setError("Error al subir: " + (err.message || "Intenta de nuevo"));
    }
    setSubiendo(false);
  };

  return (
    <div style={{ background: "rgba(251,191,36,0.06)", border: "1px solid rgba(251,191,36,0.25)", borderRadius: "14px", padding: "16px", marginBottom: "16px" }}>
      <div style={{ display: "flex", alignItems: "center", gap: "8px", marginBottom: "14px" }}>
        <span style={{ fontSize: "18px" }}>📎</span>
        <span style={{ fontFamily: getFont(theme, "secondary"), fontWeight: "700", fontSize: "12px", letterSpacing: "1px", color: "#fbbf24" }}>
          {isAdmin ? "SUBIR COMUNICADO (Admin)" : "PROPONER COMUNICADO"}
        </span>
      </div>

      {isAdmin && (
        <div style={{ background: "rgba(56,189,248,0.06)", border: "1px solid rgba(56,189,248,0.20)", borderRadius: "12px", padding: "12px", marginBottom: "12px" }}>
          <div style={{ fontFamily: getFont(theme, "secondary"), fontSize: "10px", color: "#7dd3fc", fontWeight: "700", letterSpacing: "1px", marginBottom: "8px" }}>
            PLANTILLAS RÁPIDAS
          </div>
          <div style={{ display: "flex", gap: "7px", flexWrap: "wrap" }}>
            {plantillasAdmin.map(tpl => (
              <button
                key={tpl.id}
                type="button"
                onClick={() => aplicarPlantilla(tpl)}
                style={{ padding: "7px 9px", borderRadius: "999px", border: "1px solid rgba(56,189,248,0.35)", background: "rgba(56,189,248,0.12)", color: "#bae6fd", fontFamily: getFont(theme, "secondary"), fontSize: "10px", fontWeight: "700", cursor: "pointer" }}
              >
                {tpl.label}
              </button>
            ))}
          </div>
          <div style={{ fontFamily: getFont(theme, "secondary"), fontSize: "9px", color: "rgba(226,232,240,0.45)", marginTop: "8px", lineHeight: "1.5" }}>
            Selecciona una plantilla para llenar título, descripción y vigencia. Puedes ajustar cualquier dato antes de publicar.
          </div>
        </div>
      )}
      
      <input
        type="text"
        placeholder="Título del comunicado *"
        value={titulo}
        onChange={(e) => {
          const v = e.target.value;
          setTitulo(v);
          if (v.trim()) ensureFechaInicio();
        }}
        maxLength={120}
        style={{ width: "100%", background: "#060e1a", border: "1px solid #1e3a5f", borderRadius: "8px", padding: "10px 12px", color: "rgba(255,255,255,0.9)", fontFamily: getFont(theme, "secondary"), fontSize: "12px", marginBottom: "8px", boxSizing: "border-box", outline: "none" }}
      />
      
      <input
        type="text"
        placeholder="Descripción breve (opcional)"
        value={detalle}
        onChange={(e) => setDetalle(e.target.value)}
        maxLength={200}
        style={{ width: "100%", background: "#060e1a", border: "1px solid #1e3a5f", borderRadius: "8px", padding: "10px 12px", color: "rgba(255,255,255,0.9)", fontFamily: getFont(theme, "secondary"), fontSize: "12px", marginBottom: "10px", boxSizing: "border-box", outline: "none" }}
      />

      {/* Fechas de vigencia: solo fechas, sin horas */}
      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "8px", marginBottom: "10px" }}>
        <div>
          <div style={{ fontSize: "10px", color: "rgba(255,255,255,0.4)", fontFamily: getFont(theme, "secondary"), marginBottom: "4px", letterSpacing: "1px" }}>FECHA INICIO *</div>
          <input
            type="date"
            value={fechaInicio}
            onChange={(e) => setFechaInicio(e.target.value)}
            style={{ width: "100%", background: "#060e1a", border: "1px solid #1e3a5f", borderRadius: "8px", padding: "10px 8px", color: "rgba(255,255,255,0.9)", fontFamily: getFont(theme, "secondary"), fontSize: "11px", boxSizing: "border-box", outline: "none" }}
          />
        </div>
        <div>
          <div style={{ fontSize: "10px", color: "rgba(255,255,255,0.4)", fontFamily: getFont(theme, "secondary"), marginBottom: "4px", letterSpacing: "1px" }}>FECHA FIN *</div>
          <input
            type="date"
            value={fechaFin}
            min={fechaInicio || undefined}
            onChange={(e) => setFechaFin(e.target.value)}
            style={{ width: "100%", background: "#060e1a", border: "1px solid #1e3a5f", borderRadius: "8px", padding: "10px 8px", color: "rgba(255,255,255,0.9)", fontFamily: getFont(theme, "secondary"), fontSize: "11px", boxSizing: "border-box", outline: "none" }}
          />
        </div>
      </div>
      <div style={{ background: "rgba(255,255,255,0.035)", border: "1px solid rgba(255,255,255,0.08)", borderRadius: "8px", padding: "8px 10px", marginBottom: "10px", fontFamily: getFont(theme, "secondary"), fontSize: "10px", color: "rgba(226,232,240,0.48)", lineHeight: "1.5" }}>
        La fecha de inicio se llena automáticamente con el día actual al escribir el título. El comunicado permanecerá vigente hasta finalizar la fecha fin seleccionada.
      </div>

      {/* Zona de archivo */}
      <div
        onClick={() => inputRef.current?.click()}
        style={{ border: "2px dashed #1e3a5f", borderRadius: "10px", padding: "16px", textAlign: "center", cursor: "pointer", marginBottom: "10px", background: archivo ? "#22c55e08" : "transparent", borderColor: archivo ? "#22c55e55" : "#1e3a5f", transition: "all 0.2s" }}
      >
        {preview && preview !== "pdf" && (
          <img src={preview} alt="preview" style={{ maxWidth: "100%", maxHeight: "160px", objectFit: "contain", borderRadius: "6px", marginBottom: "8px", display: "block", margin: "0 auto 8px" }} />
        )}
        {preview === "pdf" && <div style={{ fontSize: "40px", marginBottom: "6px" }}>📄</div>}
        <div style={{ fontFamily: getFont(theme, "secondary"), fontSize: "11px", color: archivo ? "#22c55e" : "rgba(255,255,255,0.35)" }}>
          {archivo ? `✓ ${archivo.name}` : "Toca aquí para seleccionar JPG, PNG o PDF (máx. 10 MB)"}
        </div>
        <input ref={inputRef} type="file" accept="image/jpeg,image/png,image/webp,application/pdf" onChange={onFileChange} style={{ display: "none" }} />
      </div>
      
      {!isAdmin && (
        <div style={{ background: "#fbbf2411", border: "1px solid #fbbf2433", borderRadius: "8px", padding: "10px 12px", marginBottom: "10px", fontSize: "10px", color: "#fbbf24", fontFamily: getFont(theme, "secondary"), lineHeight: "1.6" }}>
          Info Tu comunicado será enviado a revisión y aparecerá después de ser aprobado por un administrador.
        </div>
      )}
      
      {error && (
        <div style={{ fontFamily: getFont(theme, "secondary"), fontSize: "11px", color: "#f87171", marginBottom: "8px", padding: "8px 12px", background: "#ef444411", borderRadius: "7px" }}>
          ⚠️ {error}
        </div>
      )}
      {exito && (
        <div style={{ fontFamily: getFont(theme, "secondary"), fontSize: "11px", color: "#22c55e", marginBottom: "8px", padding: "8px 12px", background: "#22c55e11", borderRadius: "7px" }}>
          Validado {isAdmin ? "Comunicado publicado correctamente" : "Comunicado enviado a revisión"}
        </div>
      )}
      
      <button
        onClick={handleSubir}
        disabled={subiendo}
        style={{ width: "100%", padding: "11px", background: subiendo ? "#0a1628" : "linear-gradient(135deg,#fbbf24,#f59e0b)", border: "none", borderRadius: "9px", color: subiendo ? "rgba(255,255,255,0.4)" : "#0a1628", fontFamily: getFont(theme, "secondary"), fontWeight: "700", fontSize: "12px", cursor: subiendo ? "not-allowed" : "pointer", letterSpacing: "0.5px" }}
      >
        {subiendo ? "Procesando Subiendo..." : isAdmin ? "📤 PUBLICAR COMUNICADO" : "📤 ENVIAR A REVISIÓN"}
      </button>
    </div>
  );
}

// ─── SECCIÓN COMUNICADOS (con sub-tabs: Ver / Proponer) ──────────────────────
function ComunicadosSection({ isAdmin, comunicados, onReload, setVisorItem, onDownloadItem, downloadingItemUrl, timeAgo, isPdf }) {
  const theme = React.useContext(ThemeContext);
  const [subTab, setSubTab] = useState("ver"); // "ver" | "proponer"
  const [pendientes, setPendientes] = useState([]);
  const [confirmId, setConfirmId] = useState(null); // id del comunicado a eliminar
  const [eliminando, setEliminando] = useState(false); // estado de eliminación en progreso
  const [selectedIndex, setSelectedIndex] = useState(0); // comunicado destacado en vista grande

  const formatDateTime = (timestamp) => {
    const d = new Date(toMs(timestamp));
    return d.toLocaleString("es-MX", { year: "numeric", month: "short", day: "numeric", hour: "2-digit", minute: "2-digit" });
  };

  // Normaliza aprobado para boolean, string o número.
  // Esto evita que Supabase lo regrese como "true"/"false" y rompa los filtros.
  const isComunicadoAprobado = (value) =>
    value === true || value === "true" || value === 1 || value === "1";

  // Filtrar comunicados para mostrar
  const ahora = Date.now();
  const vigentes = comunicados.filter(c => {
    if (!isComunicadoAprobado(c.aprobado)) return false;
    // Si no hay fecha_fin, mostrar siempre
    if (!c.fecha_fin) return true;
    const fin = toMs(c.fecha_fin);
    // Si no se puede parsear la fecha, mostrar de todas formas
    if (!fin || isNaN(fin)) return true;
    return fin > ahora;
  });

  useEffect(() => {
    if (!vigentes.length) {
      if (selectedIndex !== 0) setSelectedIndex(0);
      return;
    }
    if (selectedIndex > vigentes.length - 1) setSelectedIndex(0);
  }, [vigentes.length, selectedIndex]);

  const comunicadoActivo = vigentes[selectedIndex] || null;
  const totalVigentes = vigentes.length;
  const irAnterior = () => {
    if (totalVigentes < 2) return;
    setSelectedIndex(prev => (prev - 1 + totalVigentes) % totalVigentes);
  };
  const irSiguiente = () => {
    if (totalVigentes < 2) return;
    setSelectedIndex(prev => (prev + 1) % totalVigentes);
  };
  const abrirComunicadoActivo = () => {
    if (!comunicadoActivo) return;
    setVisorItem(comunicadoActivo, vigentes, selectedIndex);
  };

  const cargarPendientes = () => {
    if (!isAdmin) return;
    // Cargar y filtrar en cliente para soportar false, "false", 0 o null.
    // .eq("aprobado", false) puede fallar si el campo no es boolean puro.
    sb.from("comunicados")
      .select("*")
      .order("created_at", { ascending: false })
      .then(({ data, error }) => {
        if (error) {
          console.error("Error cargando pendientes:", error);
          return;
        }
        if (data) setPendientes(data.filter(c => !isComunicadoAprobado(c.aprobado)));
      });
  };

  // Cargar pendientes (solo admin)
  useEffect(() => {
    cargarPendientes();
  }, [isAdmin]);

  const [procesando, setProcesando] = useState(null); // id del que se está procesando

  const aprobar = async (id) => {
    if (procesando) return;
    setProcesando(id);

    const { data, error } = await sb
      .from("comunicados")
      .update({ aprobado: true })
      .eq("id", id)
      .select("*"); // confirma que Supabase realmente actualizó la fila

    setProcesando(null);

    if (error) {
      console.error("Error al aprobar comunicado:", error);
      alert("Error al aprobar: " + error.message);
      return;
    }

    if (!data || data.length === 0) {
      alert("No se pudo aprobar el comunicado. Revisa las políticas RLS de Supabase para UPDATE en la tabla comunicados.");
      cargarPendientes();
      return;
    }

    // Replica a Noticias sin aprobación adicional.
    if (data?.[0]) {
      await syncComunicadoToNoticia(data[0], { processMedia: true });
    }

    // UI inmediata: lo quitamos de pendientes sin esperar realtime.
    setPendientes(prev => prev.filter(p => p.id !== id));

    // Recarga diferida para evitar que vuelva visualmente como pendiente.
    if (onReload) {
      setTimeout(() => {
        onReload();
        cargarPendientes();
      }, 500);
    }
  };

  const rechazar = async (id) => {
    setProcesando(id);
    const com = pendientes.find(p => p.id === id);
    if (com?.archivo_url) {
      try {
        const pathParts = com.archivo_url.split("/comunicados/");
        if (pathParts[1]) {
          await sb.storage.from("comunicados").remove([`comunicados/${pathParts[1]}`]);
        }
      } catch {}
    }
    const { error } = await sb.from("comunicados").delete().eq("id", id);
    setProcesando(null);
    if (error) { alert("Error al rechazar: " + error.message); return; }
    setPendientes(prev => prev.filter(p => p.id !== id));
    onReload();
  };

  const pedirEliminar = (id) => setConfirmId(id);

  const eliminar = async (id) => {
    if (eliminando) return;
    setEliminando(true);

    const com = vigentes.find(v => v.id === id) || comunicados.find(c => c.id === id);

    // 1. Eliminar archivo de storage si existe
    if (com?.archivo_url) {
      try {
        const path = com.archivo_url.split("/comunicados/")[1];
        if (path) await sb.storage.from("comunicados").remove([`comunicados/${path}`]);
      } catch (err) {
        console.error("Error al eliminar archivo:", err);
      }
    }

    // 2. Delete con .select() para confirmar que Supabase realmente eliminó la fila
    const { data: deleted, error } = await sb
      .from("comunicados")
      .delete()
      .eq("id", id)
      .select();

    if (error) {
      console.error("Error al eliminar comunicado:", error);
      alert("Error al eliminar el comunicado: " + error.message);
      setEliminando(false);
      setConfirmId(null);
      return;
    }

    // 3. Si no se eliminó ninguna fila, probablemente hay un problema de RLS
    if (!deleted || deleted.length === 0) {
      alert("No se pudo eliminar el comunicado.\n\nVerifica que la política RLS de la tabla 'comunicados' en Supabase permita DELETE al rol anon o al usuario actual.");
      setEliminando(false);
      setConfirmId(null);
      return;
    }

    // 4. Cerrar modal y recargar
    setEliminando(false);
    setConfirmId(null);
    onReload();
  };

  const handleSubidoExitoso = () => {
    onReload();
    cargarPendientes();
    setSubTab("ver");
  };



  return (
    <>
      {/* Sub-tabs: Ver / Proponer */}
      <div style={{ display: "flex", gap: "6px", marginBottom: "16px", background: "#060e1a", borderRadius: "12px", padding: "4px", border: "1px solid #1e3a5f" }}>
        <button
          onClick={() => setSubTab("ver")}
          style={{ flex: 1, padding: "10px 8px", borderRadius: "9px", border: "none", background: subTab === "ver" ? "linear-gradient(135deg,#fbbf24,#f59e0b)" : "transparent", color: subTab === "ver" ? "#0a1628" : "#475569", fontFamily: getFont(theme, "secondary"), fontSize: "11px", fontWeight: "700", cursor: "pointer", letterSpacing: "0.5px", transition: "all 0.2s", display: "flex", alignItems: "center", justifyContent: "center", gap: "5px" }}
        >
          📋 VER COMUNICADOS
          {vigentes.length > 0 && (
            <span style={{ background: subTab === "ver" ? "rgba(10,22,40,0.3)" : "#fbbf24", color: subTab === "ver" ? "#0a1628" : "#0a1628", borderRadius: "10px", padding: "1px 6px", fontSize: "9px", fontWeight: "700" }}>
              {vigentes.length}
            </span>
          )}
        </button>
        <button
          onClick={() => setSubTab("proponer")}
          style={{ flex: 1, padding: "10px 8px", borderRadius: "9px", border: "none", background: subTab === "proponer" ? "linear-gradient(135deg,#38bdf8,#0ea5e9)" : "transparent", color: subTab === "proponer" ? "#0a1628" : "#475569", fontFamily: getFont(theme, "secondary"), fontSize: "11px", fontWeight: "700", cursor: "pointer", letterSpacing: "0.5px", transition: "all 0.2s", display: "flex", alignItems: "center", justifyContent: "center", gap: "5px" }}
        >
          {isAdmin ? "📤 PUBLICAR" : "✉️ PROPONER"}
          {isAdmin && pendientes.length > 0 && (
            <span style={{ background: "#f97316", color: "#fff", borderRadius: "10px", padding: "1px 6px", fontSize: "9px", fontWeight: "700" }}>
              {pendientes.length}
            </span>
          )}
        </button>
      </div>

      {/* ── MODAL CONFIRMACIÓN ELIMINAR ── position:fixed cubre toda la pantalla sin necesitar portal */}
      {confirmId && (
        <div
          onClick={() => !eliminando && setConfirmId(null)}
          style={{ position: "fixed", inset: 0, zIndex: 99999, background: "rgba(0,0,0,0.80)", display: "flex", alignItems: "center", justifyContent: "center", padding: "20px" }}
        >
          <div onClick={e => e.stopPropagation()} style={{ background: "#0d1b2e", border: "1px solid rgba(239,68,68,0.4)", borderRadius: "16px", padding: "24px", maxWidth: "320px", width: "100%", textAlign: "center" }}>
            <div style={{ fontSize: "40px", marginBottom: "12px" }}>{eliminando ? "Procesando" : "Eliminar️"}</div>
            <div style={{ fontFamily: getFont(theme, "secondary"), fontWeight: "700", fontSize: "14px", color: "#fff", marginBottom: "8px" }}>
              {eliminando ? "Eliminando comunicado..." : "¿Eliminar comunicado?"}
            </div>
            <div style={{ fontFamily: getFont(theme, "secondary"), fontSize: "11px", color: "rgba(255,255,255,0.45)", marginBottom: "22px", lineHeight: "1.5" }}>
              {eliminando 
                ? "Por favor espera mientras se elimina el archivo y el registro."
                : <>Esta acción es permanente.<br/>Se eliminará el archivo y no podrá recuperarse.</>
              }
            </div>
            <div style={{ display: "flex", gap: "10px" }}>
              <button
                onClick={() => setConfirmId(null)}
                disabled={eliminando}
                style={{ 
                  flex: 1, 
                  padding: "12px", 
                  background: "transparent", 
                  border: "1px solid #1e3a5f", 
                  borderRadius: "10px", 
                  color: eliminando ? "rgba(255,255,255,0.3)" : "rgba(255,255,255,0.6)", 
                  fontFamily: getFont(theme, "secondary"), 
                  fontSize: "12px", 
                  fontWeight: "700", 
                  cursor: eliminando ? "not-allowed" : "pointer",
                  opacity: eliminando ? 0.5 : 1
                }}
              >Cancelar</button>
              <button
                onClick={() => eliminar(confirmId)}
                disabled={eliminando}
                style={{ 
                  flex: 1, 
                  padding: "12px", 
                  background: eliminando ? "#0a1628" : "linear-gradient(135deg,#ef4444,#dc2626)", 
                  border: "none", 
                  borderRadius: "10px", 
                  color: eliminando ? "rgba(255,255,255,0.4)" : "#fff", 
                  fontFamily: getFont(theme, "secondary"), 
                  fontSize: "12px", 
                  fontWeight: "700", 
                  cursor: eliminando ? "not-allowed" : "pointer",
                  opacity: eliminando ? 0.7 : 1
                }}
              >{eliminando ? "Eliminando..." : "Sí, eliminar"}</button>
            </div>
          </div>
        </div>
      )}

      {/* ── SUB-TAB: VER COMUNICADOS ── */}
      {subTab === "ver" && (
        <>
          {vigentes.length === 0 ? (
            <div style={{ textAlign: "center", padding: "50px 20px", border: "1px dashed #1e3a5f", borderRadius: "14px", color: "rgba(255,255,255,0.25)", fontFamily: getFont(theme, "secondary"), fontSize: "12px" }}>
              <div style={{ fontSize: "36px", marginBottom: "10px" }}>📭</div>
              Sin comunicados vigentes en este momento
            </div>
          ) : (
            <>
              {comunicadoActivo && (
                <div style={{ background: "linear-gradient(135deg, rgba(255,255,255,0.08), rgba(255,255,255,0.04))", border: "1px solid rgba(255,255,255,0.12)", borderRadius: "16px", overflow: "hidden", marginBottom: "14px" }}>
                  <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", gap: "12px", padding: "14px 14px 10px" }}>
                    <div style={{ flex: 1, minWidth: 0 }}>
                      <div style={{ fontFamily: getFont(theme, "secondary"), fontWeight: "700", fontSize: "14px", color: "rgba(255,255,255,0.95)", marginBottom: "4px" }}>{comunicadoActivo.titulo}</div>
                      {comunicadoActivo.detalle && <div style={{ fontFamily: getFont(theme, "secondary"), fontSize: "11px", color: "rgba(255,255,255,0.55)", lineHeight: "1.5", marginBottom: "6px" }}>{comunicadoActivo.detalle}</div>}
                      <div style={{ display: "flex", flexWrap: "wrap", gap: "8px", alignItems: "center" }}>
                        <span style={{ fontFamily: getFont(theme, "secondary"), fontSize: "10px", color: "#fbbf24", fontWeight: "700" }}>Documento {selectedIndex + 1} de {totalVigentes}</span>
                        <span style={{ fontFamily: getFont(theme, "secondary"), fontSize: "10px", color: "rgba(255,255,255,0.35)" }}>🕐 Vence: {formatDateTime(comunicadoActivo.fecha_fin)}</span>
                      </div>
                    </div>
                    <div style={{ display: "flex", gap: "8px", flexWrap: "wrap", justifyContent: "flex-end" }}>
                      <button onClick={abrirComunicadoActivo} style={{ padding: "9px 12px", background: "rgba(56,189,248,0.12)", border: "1px solid rgba(56,189,248,0.35)", borderRadius: "10px", color: "#38bdf8", fontFamily: getFont(theme, "secondary"), fontSize: "11px", fontWeight: "700", cursor: "pointer" }}>Pantalla completa</button>
                      <a href={comunicadoActivo.archivo_url} target="_blank" rel="noreferrer" style={{ padding: "9px 12px", background: "rgba(251,191,36,0.10)", border: "1px solid rgba(251,191,36,0.35)", borderRadius: "10px", color: "#fbbf24", fontFamily: getFont(theme, "secondary"), fontSize: "11px", fontWeight: "700", textDecoration: "none" }}>Abrir</a>
                      {onDownloadItem ? (<button onClick={() => onDownloadItem(comunicadoActivo)} disabled={downloadingItemUrl === comunicadoActivo.archivo_url} style={{ padding: "9px 12px", background: downloadingItemUrl === comunicadoActivo.archivo_url ? "rgba(100,116,139,.18)" : "rgba(34,197,94,0.10)", border: "1px solid rgba(34,197,94,0.35)", borderRadius: "10px", color: downloadingItemUrl === comunicadoActivo.archivo_url ? "#94a3b8" : "#22c55e", fontFamily: getFont(theme, "secondary"), fontSize: "11px", fontWeight: "700", cursor: downloadingItemUrl === comunicadoActivo.archivo_url ? "not-allowed" : "pointer" }}>{downloadingItemUrl === comunicadoActivo.archivo_url ? "Preparando descarga…" : "Descargar con marca de agua"}</button>) : (<a href={comunicadoActivo.archivo_url} download style={{ padding: "9px 12px", background: "rgba(34,197,94,0.10)", border: "1px solid rgba(34,197,94,0.35)", borderRadius: "10px", color: "#22c55e", fontFamily: getFont(theme, "secondary"), fontSize: "11px", fontWeight: "700", textDecoration: "none" }}>Descargar</a>)}
                    </div>
                  </div>

                  <div style={{ position: "relative", width: "100%", minHeight: "480px", maxHeight: "70vh", background: "#06101d", borderTop: "1px solid rgba(255,255,255,0.08)", display: "flex", alignItems: "center", justifyContent: "center" }}>
                    {isPdf(comunicadoActivo.archivo_url) ? (
                      <iframe src={comunicadoActivo.archivo_url} title={comunicadoActivo.titulo} style={{ width: "100%", height: "68vh", border: "none", background: "#fff" }} />
                    ) : (
                      <img src={comunicadoActivo.archivo_url} alt={comunicadoActivo.titulo} style={{ width: "100%", height: "68vh", objectFit: "contain", display: "block", background: "#061428" }} loading="lazy" />
                    )}

                    {totalVigentes > 1 && (
                      <>
                        <button onClick={irAnterior} style={{ position: "absolute", left: "12px", top: "50%", transform: "translateY(-50%)", width: "46px", height: "46px", borderRadius: "50%", border: "1px solid rgba(255,255,255,0.18)", background: "rgba(10,22,40,0.82)", color: "#fff", fontSize: "24px", cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", backdropFilter: "blur(8px)", zIndex: 2 }} aria-label="Comunicado anterior">‹</button>
                        <button onClick={irSiguiente} style={{ position: "absolute", right: "12px", top: "50%", transform: "translateY(-50%)", width: "46px", height: "46px", borderRadius: "50%", border: "1px solid rgba(255,255,255,0.18)", background: "rgba(10,22,40,0.82)", color: "#fff", fontSize: "24px", cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", backdropFilter: "blur(8px)", zIndex: 2 }} aria-label="Siguiente comunicado">›</button>
                        <div style={{ position: "absolute", bottom: "12px", left: "50%", transform: "translateX(-50%)", background: "rgba(10,22,40,0.72)", border: "1px solid rgba(255,255,255,0.10)", borderRadius: "999px", padding: "6px 12px", fontFamily: getFont(theme, "secondary"), fontSize: "10px", color: "rgba(255,255,255,0.85)", zIndex: 2 }}>
                          Usa las flechas para cambiar de archivo
                        </div>
                      </>
                    )}
                  </div>
                </div>
              )}

              <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(180px, 1fr))", gap: "10px" }}>
                {vigentes.map((c, idx) => {
                  const activo = idx === selectedIndex;
                  return (
                    <div
                      key={c.id}
                      onClick={() => setSelectedIndex(idx)}
                      style={{ background: activo ? "rgba(251,191,36,0.12)" : "rgba(255,255,255,0.07)", border: `1px solid ${activo ? "rgba(251,191,36,0.45)" : "rgba(255,255,255,0.10)"}`, borderRadius: "12px", overflow: "hidden", cursor: "pointer", transition: "transform 0.15s, border-color 0.15s", position: "relative", boxShadow: activo ? "0 0 0 1px rgba(251,191,36,0.18) inset" : "none" }}
                      onMouseEnter={(e) => { e.currentTarget.style.transform = "scale(1.02)"; if (!activo) e.currentTarget.style.borderColor = "rgba(251,191,36,0.4)"; }}
                      onMouseLeave={(e) => { e.currentTarget.style.transform = "scale(1)"; e.currentTarget.style.borderColor = activo ? "rgba(251,191,36,0.45)" : "rgba(255,255,255,0.1)"; }}
                    >
                      <div style={{ width: "100%", aspectRatio: "4/3", background: "#060e1a", display: "flex", alignItems: "center", justifyContent: "center", overflow: "hidden" }}>
                        {isPdf(c.archivo_url) ? (
                          <div style={{ textAlign: "center" }}>
                            <div style={{ fontSize: "38px" }}>📄</div>
                            <div style={{ fontFamily: getFont(theme, "secondary"), fontSize: "9px", color: "rgba(255,255,255,0.4)", marginTop: "4px" }}>PDF</div>
                          </div>
                        ) : (
                          <img src={c.archivo_url} alt={c.titulo} style={{ width: "100%", height: "100%", objectFit: "cover" }} loading="lazy" />
                        )}
                      </div>
                      <div style={{ padding: "8px 10px" }}>
                        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", gap: "6px", marginBottom: "3px" }}>
                          <div style={{ fontFamily: getFont(theme, "secondary"), fontWeight: "700", fontSize: "11px", color: "rgba(255,255,255,0.9)", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap", flex: 1 }}>{c.titulo}</div>
                          {activo && <span style={{ fontFamily: getFont(theme, "secondary"), fontSize: "9px", fontWeight: "700", color: "#fbbf24" }}>ACTIVO</span>}
                        </div>
                        {c.detalle && <div style={{ fontFamily: getFont(theme, "secondary"), fontSize: "10px", color: "rgba(255,255,255,0.4)", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap", marginBottom: "4px" }}>{c.detalle}</div>}
                        <div style={{ fontFamily: getFont(theme, "secondary"), fontSize: "9px", color: "rgba(255,255,255,0.25)" }}>🕐 Vence: {formatDateTime(c.fecha_fin)}</div>
                      </div>
                      {isAdmin && (
                        <button
                          onClick={(e) => { e.stopPropagation(); pedirEliminar(c.id); }}
                          style={{ position: "absolute", top: "6px", right: "6px", minWidth: "28px", height: "28px", padding: "0 8px", background: "rgba(239,68,68,0.85)", border: "1px solid rgba(239,68,68,0.6)", borderRadius: "999px", color: "#fff", fontSize: "11px", cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", backdropFilter: "blur(4px)", fontFamily: getFont(theme, "secondary"), fontWeight: "700" }}
                          title="Eliminar comunicado"
                        >Eliminar</button>
                      )}
                    </div>
                  );
                })}
              </div>
              <div style={{ textAlign: "center", padding: "16px", color: "rgba(255,255,255,0.3)", fontFamily: getFont(theme, "secondary"), fontSize: "10px" }}>
                Vista previa ampliada activa. Selecciona una tarjeta o usa las flechas laterales para cambiar de archivo.
              </div>
            </>
          )}
        </>
      )}

      {/* ── SUB-TAB: PROPONER / PUBLICAR ── */}
      {subTab === "proponer" && (
        <>
          {/* Descripción contextual */}
          <div style={{ background: isAdmin ? "rgba(56,189,248,0.06)" : "rgba(251,191,36,0.06)", border: `1px solid ${isAdmin ? "rgba(56,189,248,0.2)" : "rgba(251,191,36,0.2)"}`, borderRadius: "12px", padding: "12px 14px", marginBottom: "16px", display: "flex", alignItems: "flex-start", gap: "10px" }}>
            <span style={{ fontSize: "20px", flexShrink: 0 }}>{isAdmin ? "📤" : "✉️"}</span>
            <div>
              <div style={{ fontFamily: getFont(theme, "secondary"), fontWeight: "700", fontSize: "12px", color: isAdmin ? "#38bdf8" : "#fbbf24", marginBottom: "3px", letterSpacing: "0.5px" }}>
                {isAdmin ? "PUBLICAR COMUNICADO OFICIAL" : "PROPONER COMUNICADO"}
              </div>
              <div style={{ fontFamily: getFont(theme, "secondary"), fontSize: "10px", color: "rgba(255,255,255,0.45)", lineHeight: "1.5" }}>
                {isAdmin
                  ? "Tus comunicados se publican de inmediato y aparecen en la sección Ver Comunicados."
                  : "Tu propuesta será revisada por un administrador antes de ser visible para la comunidad."}
              </div>
            </div>
          </div>

          <SubirComunicadoPanel onSubido={handleSubidoExitoso} isAdmin={isAdmin} />

          {/* ── PENDIENTES DE APROBACIÓN (solo admin) ── */}
          {isAdmin && (
            <div style={{ marginTop: "24px" }}>
              <div style={{ display: "flex", alignItems: "center", gap: "8px", marginBottom: "12px" }}>
                <div style={{ flex: 1, height: "1px", background: "#1e3a5f" }} />
                <div style={{ display: "flex", alignItems: "center", gap: "6px", fontFamily: getFont(theme, "secondary"), fontSize: "10px", color: "#f97316", fontWeight: "700", letterSpacing: "1px", whiteSpace: "nowrap" }}>
                  Procesando SOLICITUDES PENDIENTES
                  {pendientes.length > 0 && (
                    <span style={{ background: "#f97316", color: "#fff", borderRadius: "8px", padding: "1px 7px", fontSize: "10px" }}>{pendientes.length}</span>
                  )}
                </div>
                <div style={{ flex: 1, height: "1px", background: "#1e3a5f" }} />
              </div>

              {pendientes.length === 0 ? (
                <div style={{ textAlign: "center", padding: "24px", border: "1px dashed #1e3a5f", borderRadius: "12px", color: "rgba(255,255,255,0.25)", fontFamily: getFont(theme, "secondary"), fontSize: "11px" }}>
                  Sin solicitudes pendientes
                </div>
              ) : (
                pendientes.map((p) => (
                  <div key={p.id} style={{ background: "rgba(249,115,22,0.07)", border: "1px solid rgba(249,115,22,0.25)", borderLeft: "3px solid #f97316", borderRadius: "12px", padding: "12px 14px", marginBottom: "10px" }}>
                    {/* Info del comunicado */}
                    <div style={{ display: "flex", gap: "10px", marginBottom: "10px" }}>
                      {/* Thumbnail */}
                      <div style={{ flexShrink: 0, width: "64px", height: "64px", borderRadius: "8px", overflow: "hidden", background: "#060e1a", border: "1px solid #1e3a5f", display: "flex", alignItems: "center", justifyContent: "center" }}>
                        {isPdf(p.archivo_url) ? (
                          <div style={{ textAlign: "center" }}>
                            <div style={{ fontSize: "24px" }}>📄</div>
                            <div style={{ fontFamily: getFont(theme, "secondary"), fontSize: "8px", color: "rgba(255,255,255,0.4)" }}>PDF</div>
                          </div>
                        ) : (
                          <img src={p.archivo_url} alt="preview" style={{ width: "100%", height: "100%", objectFit: "cover" }} />
                        )}
                      </div>
                      {/* Datos */}
                      <div style={{ flex: 1, minWidth: 0 }}>
                        <div style={{ fontFamily: getFont(theme, "secondary"), fontWeight: "700", fontSize: "12px", color: "rgba(255,255,255,0.95)", marginBottom: "3px", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{p.titulo}</div>
                        {p.detalle && <div style={{ fontSize: "11px", color: "rgba(255,255,255,0.5)", marginBottom: "5px", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{p.detalle}</div>}
                        <div style={{ fontSize: "9px", color: "rgba(255,255,255,0.3)", fontFamily: getFont(theme, "secondary"), lineHeight: "1.6" }}>
                          <div>📅 Inicio: {formatDateTime(p.fecha_inicio)}</div>
                          <div>⏰ Fin: {formatDateTime(p.fecha_fin)}</div>
                        </div>
                      </div>
                    </div>
                    {/* Acciones: 3 botones */}
                    <div style={{ display: "flex", gap: "6px" }}>
                      <button
                        onClick={() => setVisorItem(p)}
                        disabled={procesando === p.id}
                        style={{ flex: 1, padding: "8px 4px", background: "rgba(56,189,248,0.12)", border: "1px solid rgba(56,189,248,0.4)", borderRadius: "8px", color: "#38bdf8", fontFamily: getFont(theme, "secondary"), fontSize: "10px", fontWeight: "700", cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", gap: "4px" }}
                      >
                        👁 VER
                      </button>
                      <button
                        onClick={() => aprobar(p.id)}
                        disabled={procesando !== null}
                        style={{ flex: 1, padding: "8px 4px", background: procesando === p.id ? "rgba(34,197,94,0.3)" : "rgba(34,197,94,0.12)", border: "1px solid rgba(34,197,94,0.5)", borderRadius: "8px", color: "#22c55e", fontFamily: getFont(theme, "secondary"), fontSize: "10px", fontWeight: "700", cursor: procesando !== null ? "not-allowed" : "pointer", display: "flex", alignItems: "center", justifyContent: "center", gap: "4px", opacity: procesando !== null && procesando !== p.id ? 0.5 : 1 }}
                      >
                        {procesando === p.id ? "Procesando" : "✓"} APROBAR
                      </button>
                      <button
                        onClick={() => rechazar(p.id)}
                        disabled={procesando !== null}
                        style={{ flex: 1, padding: "8px 4px", background: "rgba(239,68,68,0.12)", border: "1px solid rgba(239,68,68,0.5)", borderRadius: "8px", color: "#ef4444", fontFamily: getFont(theme, "secondary"), fontSize: "10px", fontWeight: "700", cursor: procesando !== null ? "not-allowed" : "pointer", display: "flex", alignItems: "center", justifyContent: "center", gap: "4px", opacity: procesando !== null && procesando !== p.id ? 0.5 : 1 }}
                      >
                        ✕ RECHAZAR
                      </button>
                    </div>
                  </div>
                ))
              )}
            </div>
          )}
        </>
      )}
    </>
  );
}

// ─── TAB: NOTICIAS ────────────────────────────────────────────────────────────
function NoticiasAdminPublisher({ onPublished }) {
  const theme = React.useContext(ThemeContext);
  const [titulo, setTitulo] = useState("");
  const [categoria, setCategoria] = useState("comunicado");
  const [fecha, setFecha] = useState(() => new Date().toISOString().slice(0, 10));
  const [texto, setTexto] = useState("");
  const [files, setFiles] = useState([]);
  const [mediaUrls, setMediaUrls] = useState([]);
  const [pdfUrls, setPdfUrls] = useState([]);
  const [busy, setBusy] = useState(false);
  const [msg, setMsg] = useState(null);
  const inputRef = useRef(null);

  const allowed = ["image/jpeg", "image/png", "image/webp", "application/pdf"];
  const setNotice = (text, color = "#2563eb") => { setMsg({ text, color }); setTimeout(() => setMsg(null), 3500); };

  const onFiles = (e) => {
    const selected = Array.from(e.target.files || []);
    const bad = selected.find(f => !allowed.includes(f.type));
    if (bad) return setNotice("Solo se permiten JPG, PNG, WEBP y PDF.", "#ef4444");
    const tooLarge = selected.find(f => f.size > 15 * 1024 * 1024);
    if (tooLarge) return setNotice("Cada archivo debe pesar máximo 15 MB.", "#ef4444");
    setFiles(selected);
    setMediaUrls(selected.filter(f => f.type.startsWith("image/")).map(f => URL.createObjectURL(f)));
    setPdfUrls(selected.filter(f => f.type === "application/pdf").map(f => f.name));
  };

  const uploadFiles = async () => {
    const uploadedImages = [];
    const uploadedPdfs = [];
    for (const file of files) {
      const ext = sanitizeStorageName(file.name.split(".").pop() || (file.type === "application/pdf" ? "pdf" : "jpg"));
      const path = `noticias/${Date.now()}_${Math.random().toString(36).slice(2)}_${sanitizeStorageName(file.name)}`;
      const { error } = await sb.storage.from("noticias").upload(path, file, { contentType: file.type, upsert: false });
      if (error) throw error;
      const { data: { publicUrl } } = sb.storage.from("noticias").getPublicUrl(path);
      if (file.type === "application/pdf") uploadedPdfs.push({ url: publicUrl, type: file.type, path });
      else uploadedImages.push(publicUrl);
    }
    return { uploadedImages, uploadedPdfs };
  };

  const procesar = async () => {
    if (!files.length) return setNotice("Selecciona una imagen o PDF para procesar.", "#f97316");
    setBusy(true);
    try {
      const { uploadedImages, uploadedPdfs } = await uploadFiles();
      let allImages = [...uploadedImages];
      let extracted = "";
      for (const img of uploadedImages) {
        const r = await callMediaProcessor({ action: "image_ocr", sourceUrl: img, fileType: "image/*", title: titulo, bucketPath: "noticias/ocr" });
        if (r?.text) extracted += (extracted ? "\n\n" : "") + r.text;
      }
      for (const pdf of uploadedPdfs) {
        const r = await callMediaProcessor({ action: "pdf_to_images_ocr", sourceUrl: pdf.url, fileType: pdf.type, title: titulo, bucketPath: "noticias/pdf" });
        allImages = [...allImages, ...parseJsonArray(r?.image_urls)];
        if (r?.text) extracted += (extracted ? "\n\n" : "") + r.text;
      }
      setMediaUrls(allImages);
      setPdfUrls(uploadedPdfs.map(p => p.url));
      if (extracted.trim()) setTexto(prev => [prev, extracted.trim()].filter(Boolean).join("\n\n"));
      setNotice(extracted.trim() ? "Texto extraído. Revísalo antes de publicar." : "Archivos cargados. OCR no devolvió texto o el servicio no está configurado.", extracted.trim() ? "#22c55e" : "#f97316");
      setFiles([]);
      if (inputRef.current) inputRef.current.value = "";
    } catch (e) {
      console.error(e);
      setNotice("No se pudo procesar. Verifica el bucket 'noticias' y la API de OCR/PDF.", "#ef4444");
    } finally {
      setBusy(false);
    }
  };

  const publicar = async () => {
    if (!titulo.trim()) return setNotice("Escribe un título.", "#ef4444");
    setBusy(true);
    try {
      // Si el admin no presionó procesar, subimos los archivos al publicar.
      let images = mediaUrls.filter(u => typeof u === "string" && !u.startsWith("blob:"));
      let pdfs = pdfUrls.filter(u => typeof u === "string" && u.startsWith("http"));
      if (files.length) {
        const up = await uploadFiles();
        images = [...images, ...up.uploadedImages];
        pdfs = [...pdfs, ...up.uploadedPdfs.map(p => p.url)];
      }
      const payload = {
        tipo: categoria,
        titulo: titulo.trim(),
        detalle: texto.trim() || null,
        icono: categoria === "comunicado" ? "document" : "dispatch-news",
        color: categoria === "comunicado" ? "#2563eb" : "#0ea5e9",
        origen: categoria === "comunicado" ? "comunicados" : "admin_noticias",
        fecha_publicacion: fecha || new Date().toISOString().slice(0, 10),
        texto_extraido: texto.trim() || null,
        media_urls: images,
        pdf_urls: pdfs,
        archivo_url: images[0] || pdfs[0] || null,
        archivo_tipo: images[0] ? "image/jpeg" : (pdfs[0] ? "application/pdf" : null),
        ocultar_en_feed: false,
      };
      const { data, error } = await sb.from("noticias").insert(payload).select("*").single();
      if (error) throw error;
      setTitulo(""); setTexto(""); setFiles([]); setMediaUrls([]); setPdfUrls([]);
      if (inputRef.current) inputRef.current.value = "";
      setNotice("Noticia publicada.", "#22c55e");
      onPublished && onPublished(data);
    } catch (e) {
      console.error(e);
      setNotice("No se pudo publicar. Aplica la migración SQL de noticias extendidas.", "#ef4444");
    } finally {
      setBusy(false);
    }
  };

  return (
    <div style={{ background:"rgba(255,255,255,0.07)", border:"1px solid rgba(148,163,184,0.22)", borderRadius:"14px", padding:"14px", marginBottom:"16px" }}>
      <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", gap:"8px", marginBottom:"12px", flexWrap:"wrap" }}>
        <div>
          <div style={{ fontFamily:getFont(theme,"secondary"), fontSize:"12px", color:"rgba(255,255,255,0.92)", fontWeight:800 }}>Panel admin de Noticias</div>
          <div style={{ fontFamily:getFont(theme,"secondary"), fontSize:"10px", color:"rgba(255,255,255,0.48)", marginTop:"2px" }}>Sube imágenes o PDF, procesa OCR y edita el texto antes de publicar.</div>
        </div>
        <Badge color="#2563eb" small>Solo administrador</Badge>
      </div>
      {msg && <div style={{ padding:"9px 10px", borderRadius:"9px", background:msg.color+"18", border:`1px solid ${msg.color}55`, color:msg.color, fontFamily:getFont(theme,"secondary"), fontSize:"11px", marginBottom:"10px" }}>{msg.text}</div>}
      <div style={{ display:"grid", gridTemplateColumns:"1fr 150px", gap:"8px", marginBottom:"8px" }}>
        <input value={titulo} onChange={e=>setTitulo(e.target.value)} placeholder="Título de la noticia o comunicado" style={{ background:"rgba(2,6,23,0.68)", border:"1px solid rgba(148,163,184,0.28)", borderRadius:"10px", padding:"11px 12px", color:"#fff", fontFamily:getFont(theme,"secondary"), fontSize:"12px" }} />
        <select value={categoria} onChange={e=>setCategoria(e.target.value)} style={{ background:"rgba(2,6,23,0.68)", border:"1px solid rgba(148,163,184,0.28)", borderRadius:"10px", padding:"11px 12px", color:"#fff", fontFamily:getFont(theme,"secondary"), fontSize:"12px" }}>
          <option value="comunicado">Comunicado</option>
          <option value="acceso">Accesos</option>
          <option value="terminal">Terminales</option>
          <option value="incidente">Incidente</option>
          <option value="accidente">Accidente</option>
          <option value="patio">Patios</option>
          <option value="carril">Carriles</option>
        </select>
      </div>
      <input type="date" value={fecha} onChange={e=>setFecha(e.target.value)} style={{ width:"100%", boxSizing:"border-box", background:"rgba(2,6,23,0.68)", border:"1px solid rgba(148,163,184,0.28)", borderRadius:"10px", padding:"10px 12px", color:"#fff", fontFamily:getFont(theme,"secondary"), fontSize:"12px", marginBottom:"8px" }} />
      <input ref={inputRef} type="file" accept="image/jpeg,image/png,image/webp,application/pdf" multiple onChange={onFiles} style={{ width:"100%", color:"rgba(255,255,255,0.7)", marginBottom:"8px", fontFamily:getFont(theme,"secondary"), fontSize:"11px" }} />
      {(mediaUrls.length > 0 || pdfUrls.length > 0) && <div style={{ display:"flex", gap:"8px", flexWrap:"wrap", marginBottom:"8px" }}>
        {mediaUrls.map((u,i)=><img key={u+i} src={u} alt="preview" style={{ width:"82px", height:"62px", objectFit:"cover", borderRadius:"8px", border:"1px solid rgba(255,255,255,.14)" }} />)}
        {pdfUrls.map((u,i)=><div key={u+i} style={{ width:"82px", height:"62px", borderRadius:"8px", border:"1px solid rgba(255,255,255,.14)", display:"flex", alignItems:"center", justifyContent:"center", color:"#cbd5e1", fontSize:"10px", fontFamily:getFont(theme,"secondary") }}>PDF</div>)}
      </div>}
      <textarea value={texto} onChange={e=>setTexto(e.target.value)} placeholder="Texto extraído o descripción editable antes de publicar…" rows={5} style={{ width:"100%", boxSizing:"border-box", background:"rgba(2,6,23,0.68)", border:"1px solid rgba(148,163,184,0.28)", borderRadius:"10px", padding:"11px 12px", color:"#fff", fontFamily:getFont(theme,"secondary"), fontSize:"12px", resize:"vertical", marginBottom:"10px" }} />
      <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:"8px" }}>
        <button onClick={procesar} disabled={busy || !files.length} style={{ padding:"11px", borderRadius:"10px", border:"1px solid rgba(37,99,235,.5)", background:"rgba(37,99,235,.14)", color:"#93c5fd", fontFamily:getFont(theme,"secondary"), fontSize:"12px", fontWeight:800, cursor:busy?"wait":"pointer" }}>{busy ? "Procesando…" : "Convertir / extraer texto"}</button>
        <button onClick={publicar} disabled={busy} style={{ padding:"11px", borderRadius:"10px", border:"1px solid #2563eb", background:"#2563eb", color:"#fff", fontFamily:getFont(theme,"secondary"), fontSize:"12px", fontWeight:900, cursor:busy?"wait":"pointer" }}>Publicar en Noticias</button>
      </div>
    </div>
  );
}


// ─── REPORTE AUTOMÁTICO EN NOTICIAS: JPEG visible y descargable ───────────────
const getNoticiasAutoReportCache = () => {
  if (typeof window === "undefined") return {};
  window.__cmNoticiasAutoReportCache = window.__cmNoticiasAutoReportCache || {};
  return window.__cmNoticiasAutoReportCache;
};

function NoticiasAutoJpegReport() {
  const theme = React.useContext(ThemeContext);
  const reportCacheRef = useRef(getNoticiasAutoReportCache());
  const [jpegUrl, setJpegUrl] = useState(() => reportCacheRef.current.jpegUrl || null);
  const [generatedAt, setGeneratedAt] = useState(() => reportCacheRef.current.generatedAt ? new Date(reportCacheRef.current.generatedAt) : null);
  const [loading, setLoading] = useState(false);
  const [downloading, setDownloading] = useState(false);
  const [downloadFormat, setDownloadFormat] = useState("jpeg");
  const [nextRunAt, setNextRunAt] = useState(null);
  const [error, setError] = useState("");
  const objectUrlRef = useRef(reportCacheRef.current.jpegUrl || null);
  const canvasRef = useRef(reportCacheRef.current.canvas || null);
  if (canvasRef.current && reportCacheRef.current.groups) canvasRef.current.__reportGroups = reportCacheRef.current.groups;

  const optLabel = (opts, id, fallback = "Sin dato") => (opts.find(o => o.id === id)?.label || fallback);
  const optColor = (opts, id, fallback = "#94a3b8") => (opts.find(o => o.id === id)?.color || fallback);
  const terminalName = (id) => TODAS_TERMINALES.find(t => t.id === id)?.name || id || "General";
  const clean = (txt) => String(txt ?? "").replace(/\s+/g, " ").trim();

  const cargarSnapshot = useCallback(async () => {
    const [accesosRes, vialidadesRes, rutasRes, terminalsRes, patiosRes, carrilesRes] = await Promise.all([
      sb.from("accesos").select("*"),
      sb.from("vialidades").select("*"),
      sb.from("rutas_fiscales").select("*"),
      sb.from("terminals").select("*"),
      sb.from("patios").select("*"),
      sb.from("carriles").select("*")
    ]);
    const accesos = { ...mkAccesos() };
    (accesosRes.data || []).forEach(r => { accesos[r.id] = { status:r.status, retornos:r.retornos || "none" }; });
    const vialidades = { ...mkVialidades() };
    (vialidadesRes.data || []).forEach(r => { vialidades[r.id] = { status:r.status }; });
    const rutas = { ...mkRutasFiscales() };
    (rutasRes.data || []).forEach(r => { rutas[r.id] = { status:r.status }; });
    const terminalMap = Object.fromEntries((terminalsRes.data || []).map(r => [r.id, r]));
    const patioMap = Object.fromEntries((patiosRes.data || []).map(r => [r.id, r]));
    const carrilesRows = carrilesRes.data || [];
    const carrilesExpo = carrilesRows.find(r => r.id === "expo_impo")?.data || mkCarrilesState();
    const segundo = { ...mkSegundoIngreso(), ...(carrilesRows.find(r => r.id === "segundo_acceso")?.data || {}) };
    const confinada = { ...mkConfinadaState(), ...(carrilesRows.find(r => r.id === "confinada_acceso")?.data || {}) };

    return [
      { title:"Accesos", rows: ACCESOS_PRINCIPALES.map(a => {
        const st = accesos[a.id] || {};
        const retorno = optLabel(RETORNO_OPTIONS, st.retornos || "none", "Sin retorno");
        return { name:a.label, status:optLabel(ACCESO_STATUS_OPTIONS, st.status, st.status || "Sin dato"), detail:retorno !== "Sin Retornos" ? retorno : a.zona || "", color:optColor(ACCESO_STATUS_OPTIONS, st.status) };
      })},
      { title:"Vialidades", rows: VIALIDADES.map(v => {
        const st = vialidades[v.id] || {};
        return { name:v.name, status:optLabel(VIALIDAD_STATUS_OPTIONS, st.status, st.status || "Sin dato"), detail:"", color:optColor(VIALIDAD_STATUS_OPTIONS, st.status) };
      })},
      { title:"Rutas fiscales", rows: RUTAS_FISCALES.map(r => {
        const st = rutas[r.id] || {};
        return { name:r.name, status:optLabel(RUTA_FISCAL_STATUS_OPTIONS, st.status, st.status || "Sin dato"), detail:r.zona ? `Zona ${r.zona}` : "", color:optColor(RUTA_FISCAL_STATUS_OPTIONS, st.status) };
      })},
      { title:"Terminales", rows: [...TERMINALS_NORTE.map(t => ({ ...t, zona:"Norte" })), ...TERMINALS_SUR.map(t => ({ ...t, zona:"Sur" }))].map(t => {
        const st = terminalMap[t.id] || { status:"libre" };
        return { name:t.name, status:optLabel(TERMINAL_STATUS_OPTIONS, st.status, st.status || "Sin dato"), detail:`Zona ${t.zona}`, color:optColor(TERMINAL_STATUS_OPTIONS, st.status) };
      })},
      { title:"Patios", rows: PATIOS_REGULADORES.map(p => {
        const st = patioMap[p.id] || { status:"libre" };
        return { name:p.name, status:optLabel(PATIO_STATUS_OPTIONS, st.status, st.status || "Sin dato"), detail:"", color:optColor(PATIO_STATUS_OPTIONS, st.status) };
      })},
      { title:"Carriles Expo / Impo", rows: ACCESOS_CARRILES.flatMap(acc => acc.carriles.map(c => {
        const st = carrilesExpo[c.id] || { abierto:true };
        return { name:`${acc.label} · ${c.label}`, status:st.abierto === false ? "Cerrado" : "Abierto", detail:c.flujo || "", color:st.abierto === false ? "#ef4444" : "#22c55e" };
      }))},
      { title:"2° Acceso y confinada", rows: [
        ...ACCESOS_SEGUNDO.flatMap(acc => acc.carriles.map(c => {
          const st = segundo[c.id] || {};
          const flags = [terminalName(st.terminal), st.retornos ? "Con retornos" : "", st.expo ? `Expo ${st.expo}` : "", st.impo ? `Impo ${st.impo}` : ""].filter(Boolean).join(" · ");
          const laneOpt = getCarrilEstadoOpt(st);
          return { name:`${acc.label} · ${c.label}`, status:laneOpt.label, detail:flags, color:laneOpt.color };
        })),
        ...CONFINADA_CARRILES.map(c => {
          const st = confinada[c.id] || {};
          const flags = [terminalName(st.terminal), st.transferencia ? "Transferencia" : "", st.retornos ? "Con retornos" : "", st.expo ? `Expo ${st.expo}` : "", st.impo ? `Impo ${st.impo}` : ""].filter(Boolean).join(" · ");
          const laneOpt = getCarrilEstadoOpt(st);
          return { name:`Confinada · ${c.label}`, status:laneOpt.label, detail:flags, color:laneOpt.color };
        })
      ]}
    ];
  }, []);

  const loadImage = (src) => new Promise((resolve, reject) => {
    const img = new Image();
    img.onload = () => resolve(img);
    img.onerror = reject;
    img.src = src;
  });

  const loadJsPdf = () => new Promise((resolve, reject) => {
    if (window.jspdf?.jsPDF) return resolve(window.jspdf.jsPDF);
    const existing = document.querySelector('script[src*="jspdf.umd.min.js"]');
    if (existing) {
      existing.addEventListener("load", () => resolve(window.jspdf.jsPDF));
      existing.addEventListener("error", reject);
      return;
    }
    const script = document.createElement("script");
    script.src = "https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.1/jspdf.umd.min.js";
    script.onload = () => resolve(window.jspdf.jsPDF);
    script.onerror = reject;
    document.head.appendChild(script);
  });

  const drawCanvasWatermark = async (ctx, w, startY, areaH) => {
    try {
      const wm = await loadImage(CM_REPORT_WATERMARK);
      const wmW = Math.min(610, w * 0.64);
      const wmH = wmW * (wm.height / wm.width);
      const centerY = startY + areaH / 2;
      ctx.save();
      if ("filter" in ctx) ctx.filter = "grayscale(1)";
      ctx.globalAlpha = 0.14;
      ctx.drawImage(wm, (w - wmW) / 2, centerY - wmH / 2, wmW, wmH);
      ctx.restore();
    } catch {}
  };

  const buildReportCanvas = useCallback(async () => {
    const groups = await cargarSnapshot();
    const scale = 2;
    const w = 1080;
    const pad = 42;
    const headerH = 150;
    const footerH = 58;
    const sectionGap = 24;
    const titleGap = 34;
    const rowBaseH = 32;
    const detailExtraH = 14;
    const rowsCount = groups.reduce((n, g) => n + g.rows.length, 0);
    const totalDetails = groups.reduce((n, g) => n + g.rows.filter(r => clean(r.detail)).length, 0);
    const h = headerH + footerH + groups.length * (titleGap + sectionGap) + rowsCount * rowBaseH + totalDetails * detailExtraH + 48;
    const canvas = document.createElement("canvas");
    canvas.width = w * scale;
    canvas.height = h * scale;
    canvas.style.width = w + "px";
    canvas.style.height = h + "px";
    const ctx = canvas.getContext("2d");
    ctx.scale(scale, scale);

    const line = (x1, y1, x2, y2, color = "#cbd5e1", width = 1) => {
      ctx.beginPath();
      ctx.moveTo(x1, y1);
      ctx.lineTo(x2, y2);
      ctx.strokeStyle = color;
      ctx.lineWidth = width;
      ctx.stroke();
    };
    const wrapText = (text, x, y, maxWidth, lineHeight, maxLines = 1) => {
      const words = clean(text).split(" ");
      let lineText = "";
      let lineNo = 0;
      for (let i = 0; i < words.length; i++) {
        const test = lineText ? `${lineText} ${words[i]}` : words[i];
        if (ctx.measureText(test).width > maxWidth && lineText) {
          ctx.fillText(lineNo + 1 === maxLines ? `${lineText}…` : lineText, x, y + lineNo * lineHeight);
          lineNo += 1;
          lineText = words[i];
          if (lineNo >= maxLines) return;
        } else {
          lineText = test;
        }
      }
      if (lineNo < maxLines) ctx.fillText(lineText, x, y + lineNo * lineHeight);
    };

    const now = new Date();
    const selectedCount = groups.length;

    ctx.fillStyle = "#f3f4f6";
    ctx.fillRect(0, 0, w, h);

    ctx.fillStyle = "#03152f";
    ctx.fillRect(0, 0, w, 116);
    ctx.fillStyle = "#ffffff";
    ctx.font = "700 30px Arial";
    ctx.fillText("Reporte operativo", pad, 56);
    ctx.font = "400 18px Arial";
    ctx.fillText("Conect Manzanillo", pad, 92);

    ctx.textAlign = "right";
    ctx.font = "400 17px Arial";
    ctx.fillStyle = "rgba(255,255,255,0.92)";
    ctx.fillText(`Generado: ${now.toLocaleString("es-MX", { dateStyle:"medium", timeStyle:"short" })}`, w - pad, 56);
    ctx.fillText(`${selectedCount} secciones · ${rowsCount} registros`, w - pad, 92);
    ctx.textAlign = "left";

    await drawCanvasWatermark(ctx, w, headerH, h - headerH - footerH);

    let y = headerH + 10;
    groups.forEach((g) => {
      line(pad, y, w - pad, y, "#cbd5e1", 1.1);
      y += 22;
      ctx.fillStyle = "#0f172a";
      ctx.font = "700 21px Arial";
      ctx.fillText(g.title, pad, y);
      ctx.textAlign = "right";
      ctx.fillStyle = "#64748b";
      ctx.font = "400 16px Arial";
      ctx.fillText(`${g.rows.length} registros`, w - pad, y);
      ctx.textAlign = "left";
      y += 22;

      g.rows.forEach((r) => {
        const detail = clean(r.detail);
        ctx.fillStyle = "#1f2937";
        ctx.font = "400 17px Arial";
        wrapText(r.name, pad + 10, y, 640, 18, 1);
        ctx.textAlign = "right";
        ctx.fillStyle = r.color || "#64748b";
        ctx.font = "700 17px Arial";
        ctx.fillText(clean(r.status).slice(0, 32), w - pad, y);
        ctx.textAlign = "left";
        y += 14;
        if (detail) {
          ctx.fillStyle = "#94a3b8";
          ctx.font = "400 12px Arial";
          wrapText(detail, pad + 10, y, 700, 13, 1);
          y += 11;
        }
        y += 10;
        line(pad + 10, y, w - pad, y, "#d7dde5", 1);
        y += 18;
      });
      y += 16;
    });

    ctx.fillStyle = "#64748b";
    ctx.font = "400 14px Arial";
    ctx.fillText("Conect Manzanillo · Reporte generado desde la web", pad, h - 24);
    ctx.textAlign = "right";
    ctx.fillText("Vista previa JPEG con marca de agua", w - pad, h - 24);
    ctx.textAlign = "left";

    return { canvas, now, groups, rowsCount };
  }, [cargarSnapshot]);

  const buildPreviewCanvas = useCallback(async () => {
    const groups = await cargarSnapshot();
    const scale = 2;
    const w = 1080;
    const pad = 42;
    const rowH = 44;
    const sectionH = 58;
    const headerH = 150;
    const footerH = 56;
    const rowsCount = groups.reduce((n, g) => n + g.rows.length, 0);
    const h = headerH + footerH + groups.length * sectionH + rowsCount * rowH + 40;
    const canvas = document.createElement("canvas");
    canvas.width = w * scale;
    canvas.height = h * scale;
    canvas.style.width = w + "px";
    canvas.style.height = h + "px";
    const ctx = canvas.getContext("2d");
    ctx.scale(scale, scale);

    const roundRect = (x,y,ww,hh,r) => {
      ctx.beginPath();
      ctx.moveTo(x+r,y); ctx.arcTo(x+ww,y,x+ww,y+hh,r); ctx.arcTo(x+ww,y+hh,x,y+hh,r); ctx.arcTo(x,y+hh,x,y,r); ctx.arcTo(x,y,x+ww,y,r); ctx.closePath();
    };
    const wrapText = (text, x, y, maxWidth, lineHeight, maxLines = 1) => {
      const words = clean(text).split(" ");
      let line = "";
      let lineNo = 0;
      for (let i=0; i<words.length; i++) {
        const test = line ? line + " " + words[i] : words[i];
        if (ctx.measureText(test).width > maxWidth && line) {
          ctx.fillText(lineNo + 1 === maxLines ? line + "…" : line, x, y + lineNo * lineHeight);
          lineNo++;
          line = words[i];
          if (lineNo >= maxLines) return;
        } else line = test;
      }
      if (lineNo < maxLines) ctx.fillText(line, x, y + lineNo * lineHeight);
    };

    const now = new Date();
    const grad = ctx.createLinearGradient(0, 0, 0, h);
    grad.addColorStop(0, "#07152a");
    grad.addColorStop(1, "#0b2440");
    ctx.fillStyle = grad;
    ctx.fillRect(0, 0, w, h);

    try {
      const wm = await loadImage(CM_REPORT_WATERMARK);
      const wmW = Math.min(560, w * 0.54);
      const wmH = wmW * (wm.height / wm.width);
      ctx.save();
      if ("filter" in ctx) ctx.filter = "grayscale(1) brightness(1.8)";
      ctx.globalAlpha = 0.08;
      for (let cy = headerH + 440; cy < h - footerH; cy += 980) {
        ctx.drawImage(wm, (w - wmW) / 2, cy - wmH / 2, wmW, wmH);
      }
      ctx.restore();
    } catch {}

    ctx.fillStyle = "#ffffff";
    ctx.font = "900 34px Arial";
    ctx.fillText("Reporte operativo", pad, 62);
    ctx.font = "700 18px Arial";
    ctx.fillStyle = "#93c5fd";
    ctx.fillText("Conect Manzanillo · Noticias", pad, 94);
    ctx.font = "400 17px Arial";
    ctx.fillStyle = "#cbd5e1";
    ctx.fillText(`Generado automáticamente: ${now.toLocaleString("es-MX")}`, pad, 124);
    ctx.textAlign = "right";
    ctx.fillStyle = "#38bdf8";
    ctx.font = "900 18px Arial";
    ctx.fillText(`${rowsCount} registros`, w - pad, 62);
    ctx.textAlign = "left";

    let y = headerH;
    groups.forEach(g => {
      ctx.fillStyle = "rgba(56,189,248,0.14)";
      roundRect(pad, y, w - pad*2, 42, 14); ctx.fill();
      ctx.strokeStyle = "rgba(56,189,248,0.36)"; ctx.lineWidth = 1; ctx.stroke();
      ctx.fillStyle = "#7dd3fc";
      ctx.font = "900 18px Arial";
      ctx.fillText(g.title.toUpperCase(), pad + 18, y + 27);
      ctx.textAlign = "right";
      ctx.fillStyle = "#94a3b8";
      ctx.font = "700 14px Arial";
      ctx.fillText(`${g.rows.length} registros`, w - pad - 18, y + 27);
      ctx.textAlign = "left";
      y += sectionH;
      g.rows.forEach((r, idx) => {
        ctx.fillStyle = idx % 2 ? "rgba(255,255,255,0.035)" : "rgba(255,255,255,0.065)";
        roundRect(pad, y - 6, w - pad*2, rowH - 6, 10); ctx.fill();
        ctx.fillStyle = "#f8fafc";
        ctx.font = "800 16px Arial";
        wrapText(r.name, pad + 16, y + 17, 560, 17, 1);
        if (r.detail) {
          ctx.fillStyle = "#94a3b8";
          ctx.font = "400 13px Arial";
          wrapText(r.detail, pad + 16, y + 34, 670, 14, 1);
        }
        ctx.textAlign = "right";
        ctx.fillStyle = r.color || "#94a3b8";
        ctx.font = "900 16px Arial";
        ctx.fillText(clean(r.status).slice(0, 32), w - pad - 16, y + 22);
        ctx.textAlign = "left";
        y += rowH;
      });
    });
    ctx.fillStyle = "#64748b";
    ctx.font = "400 14px Arial";
    ctx.fillText("Vista web. Al descargar se convierte al formato formal de Reporte.", pad, h - 26);
    return { canvas, now, groups, rowsCount };
  }, [cargarSnapshot]);

  const generarJpeg = useCallback(async () => {
    setLoading(true);
    setError("");
    try {
      const { canvas, now, groups } = await buildPreviewCanvas();
      canvasRef.current = canvas;
      canvasRef.current.__reportGroups = groups;
      const blob = await new Promise(resolve => canvas.toBlob(resolve, "image/jpeg", 0.92));
      if (!blob) throw new Error("No se pudo crear el JPEG");
      const previousUrl = reportCacheRef.current.jpegUrl;
      const url = URL.createObjectURL(blob);
      objectUrlRef.current = url;
      reportCacheRef.current.jpegUrl = url;
      reportCacheRef.current.generatedAt = now.toISOString();
      reportCacheRef.current.canvas = canvas;
      reportCacheRef.current.groups = groups;
      if (previousUrl && previousUrl !== url) setTimeout(() => URL.revokeObjectURL(previousUrl), 1500);
      setJpegUrl(url);
      setGeneratedAt(now);
    } catch (e) {
      console.error(e);
      setError("No se pudo generar el reporte. Revisa tablas operativas y permisos de lectura.");
    } finally {
      setLoading(false);
    }
  }, [buildPreviewCanvas]);

  const downloadCanvasAsJpeg = async (canvas, now) => {
    const blob = await new Promise(resolve => canvas.toBlob(resolve, "image/jpeg", 0.92));
    if (!blob) throw new Error("No se pudo crear el JPEG");
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `reporte-operativo-conect-${now.toISOString().slice(0,10)}.jpeg`;
    document.body.appendChild(a);
    a.click();
    a.remove();
    setTimeout(() => URL.revokeObjectURL(url), 1200);
  };

  const downloadCanvasAsPdf = async (canvas, now, groups = null) => {
    const jsPDF = await loadJsPdf();
    const reportGroups = groups || (await cargarSnapshot());
    const doc = new jsPDF({ orientation: "portrait", unit: "mm", format: "letter" });
    const pageW = doc.internal.pageSize.getWidth();
    const pageH = doc.internal.pageSize.getHeight();
    const left = 16;
    const right = pageW - 16;
    const stamp = now.toLocaleString("es-MX", { dateStyle:"medium", timeStyle:"short" });
    const totalItems = reportGroups.reduce((sum, g) => sum + g.rows.length, 0);
    const selectedCount = reportGroups.length;
    let y = 18;

    const drawWatermark = () => {
      try {
        const size = 118;
        doc.addImage(CM_REPORT_WATERMARK, "PNG", (pageW - size) / 2, (pageH - size) / 2 + 8, size, size, undefined, "FAST");
      } catch {}
    };

    const addPageHeader = () => {
      drawWatermark();
      doc.setFillColor(3, 21, 47);
      doc.rect(0, 0, pageW, 30, "F");
      doc.setTextColor(255,255,255);
      doc.setFont("helvetica", "bold");
      doc.setFontSize(15);
      doc.text("Reporte operativo", left, 15);
      doc.setFont("helvetica", "normal");
      doc.setFontSize(8.5);
      doc.setTextColor(241, 245, 249);
      doc.text("Conect Manzanillo", left, 22);
      doc.text(`Generado: ${stamp}`, right, 15, { align:"right" });
      doc.text(`${selectedCount} secciones · ${totalItems} registros`, right, 22, { align:"right" });
      y = 42;
    };

    const checkPage = (needed = 8) => {
      if (y + needed > pageH - 15) {
        doc.addPage();
        addPageHeader();
      }
    };

    addPageHeader();
    const statusX = pageW - 48;

    reportGroups.forEach((g) => {
      checkPage(12);
      doc.setDrawColor(203, 213, 225);
      doc.setLineWidth(0.25);
      doc.line(left, y, right, y);
      y += 5;
      doc.setFont("helvetica", "bold");
      doc.setFontSize(11);
      doc.setTextColor(15, 23, 42);
      doc.text(cleanPdfText(g.title), left, y);
      doc.setFont("helvetica", "normal");
      doc.setFontSize(8.3);
      doc.setTextColor(100, 116, 139);
      doc.text(`${g.rows.length} registros`, right, y, { align:"right" });
      y += 5;

      g.rows.forEach((item) => {
        const detail = cleanPdfText(item.detail || "");
        const rgb = hexToRgb(item.color || "#64748b") || { r: 100, g: 116, b: 139 };
        const rowHeight = detail ? 8.8 : 5.8;
        checkPage(detail ? 10 : 7);
        doc.setFont("helvetica", "normal");
        doc.setFontSize(9.2);
        doc.setTextColor(15, 23, 42);
        doc.text(cleanPdfText(item.name).slice(0, 84), left + 2, y);
        doc.setFont("helvetica", "bold");
        doc.setTextColor(rgb.r, rgb.g, rgb.b);
        doc.text(cleanPdfText(item.status).slice(0, 28), statusX, y);
        if (detail) {
          doc.setFont("helvetica", "normal");
          doc.setFontSize(7.6);
          doc.setTextColor(148, 163, 184);
          doc.text(detail.slice(0, 98), left + 2, y + 3.4);
        }
        doc.setDrawColor(226, 232, 240);
        doc.setLineWidth(0.12);
        doc.line(left + 2, y + rowHeight - 3.7, right, y + rowHeight - 3.7);
        y += rowHeight;
      });
      y += 3;
    });

    const pages = doc.internal.getNumberOfPages();
    for (let i = 1; i <= pages; i++) {
      doc.setPage(i);
      doc.setFont("helvetica", "normal");
      doc.setFontSize(8);
      doc.setTextColor(100, 116, 139);
      doc.text(`Página ${i} de ${pages}`, right, pageH - 9, { align:"right" });
      doc.text("Conect Manzanillo · Reporte generado desde la web", left, pageH - 9);
    }

    doc.save(`reporte-operativo-conect-${now.toISOString().slice(0,10)}.pdf`);
  };

  const descargarReporte = async () => {
    setDownloading(true);
    setError("");
    try {
      const built = await buildReportCanvas();
      const canvas = built.canvas;
      const now = built.now;
      const groups = built.groups;
      if (downloadFormat === "pdf") await downloadCanvasAsPdf(canvas, now, groups);
      else await downloadCanvasAsJpeg(canvas, now);
    } catch (e) {
      console.error(e);
      setError("No se pudo descargar el reporte en el formato seleccionado.");
    } finally {
      setDownloading(false);
    }
  };

  useEffect(() => {
    let timeoutId = null;
    let cancelled = false;
    const scheduleNext = () => {
      if (cancelled) return;
      const now = Date.now();
      const next = (Math.floor(now / (10 * 60 * 1000)) + 1) * 10 * 60 * 1000;
      setNextRunAt(new Date(next));
      timeoutId = setTimeout(async () => {
        if (cancelled) return;
        await generarJpeg();
        scheduleNext();
      }, Math.max(1000, next - now));
    };
    scheduleNext();
    return () => {
      cancelled = true;
      if (timeoutId) clearTimeout(timeoutId);
      // No revocar aquí: el reporte debe mantenerse visible al cambiar de sección.
      // El objectURL anterior se libera solo cuando se genera un nuevo corte.
    };
  }, [generarJpeg]);

  return (
    <div style={{ background:"linear-gradient(135deg,rgba(37,99,235,.16),rgba(2,6,23,.72))", border:"1px solid rgba(56,189,248,.26)", borderRadius:"15px", padding:"14px", marginBottom:"16px" }}>
      <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", gap:"10px", flexWrap:"wrap", marginBottom:"10px" }}>
        <div>
          <div style={{ color:"#fff", fontFamily:getFont(theme,"secondary"), fontWeight:900, fontSize:"14px" }}>Reporte automático del puerto</div>
          <div style={{ color:"rgba(226,232,240,.62)", fontFamily:getFont(theme,"secondary"), fontSize:"11px", marginTop:"3px" }}>Vista web en fondo oscuro. Las descargas JPEG/PDF se convierten al formato formal del apartado Reporte.</div>
          {generatedAt && <div style={{ color:"rgba(147,197,253,.86)", fontFamily:getFont(theme,"secondary"), fontSize:"10px", marginTop:"5px" }}>Último reporte automático: {generatedAt.toLocaleString("es-MX")}</div>}
          {nextRunAt && <div style={{ color:"rgba(251,191,36,.86)", fontFamily:getFont(theme,"secondary"), fontSize:"10px", marginTop:"3px" }}>Próximo automático: {nextRunAt.toLocaleTimeString("es-MX", { hour:"2-digit", minute:"2-digit" })}</div>}
        </div>
        <div style={{ display:"flex", gap:"7px", flexWrap:"wrap", alignItems:"center" }}>
          <button onClick={generarJpeg} disabled={loading} style={{ padding:"9px 10px", borderRadius:"9px", border:"1px solid rgba(56,189,248,.45)", background:"rgba(56,189,248,.12)", color:"#7dd3fc", fontFamily:getFont(theme,"secondary"), fontSize:"10px", fontWeight:900, cursor:loading?"wait":"pointer" }}>{loading ? "Generando…" : "Generar ahora"}</button>
          <select value={downloadFormat} onChange={e=>setDownloadFormat(e.target.value)} disabled={downloading} style={{ padding:"9px 10px", borderRadius:"9px", border:"1px solid rgba(148,163,184,.35)", background:"rgba(2,6,23,.72)", color:"#e2e8f0", fontFamily:getFont(theme,"secondary"), fontSize:"10px", fontWeight:800, outline:"none" }}>
            <option value="jpeg">Descargar como JPEG</option>
            <option value="pdf">Descargar como PDF</option>
          </select>
          <button onClick={descargarReporte} disabled={downloading} style={{ padding:"9px 10px", borderRadius:"9px", border:"1px solid rgba(34,197,94,.4)", background:downloading ? "rgba(100,116,139,.18)" : "rgba(34,197,94,.12)", color:downloading ? "#94a3b8" : "#86efac", fontFamily:getFont(theme,"secondary"), fontSize:"10px", fontWeight:900, cursor:downloading?"not-allowed":"pointer" }}>{downloading ? "Descargando…" : "Descargar"}</button>
        </div>
      </div>
      {error && <div style={{ padding:"9px 10px", borderRadius:"9px", background:"rgba(239,68,68,.12)", border:"1px solid rgba(239,68,68,.35)", color:"#fca5a5", fontFamily:getFont(theme,"secondary"), fontSize:"11px", marginBottom:"10px" }}>{error}</div>}
      {jpegUrl ? <img src={jpegUrl} alt="Reporte operativo automático" style={{ width:"100%", borderRadius:"12px", border:"1px solid rgba(255,255,255,.14)", background:"#061428", display:"block" }} /> : <div style={{ textAlign:"center", padding:"24px", border:"1px dashed rgba(148,163,184,.35)", borderRadius:"12px", color:"rgba(255,255,255,.42)", fontFamily:getFont(theme,"secondary"), fontSize:"11px" }}>{loading ? "Generando imagen del reporte…" : "El reporte automático aparecerá en el próximo corte de 10 minutos. También puedes generarlo ahora."}</div>}
    </div>
  );
}

function NoticiasAdminCleanup({ onCleaned }) {
  const theme = React.useContext(ThemeContext);
  const today = new Date().toISOString().slice(0, 10);
  const [open, setOpen] = useState(false);
  const [fechaInicio, setFechaInicio] = useState(today);
  const [fechaFin, setFechaFin] = useState(today);
  const [origen, setOrigen] = useState("todos");
  const [tipo, setTipo] = useState("todos");
  const [confirmacion, setConfirmacion] = useState("");
  const [busy, setBusy] = useState(false);
  const [msg, setMsg] = useState(null);

  const setNotice = (text, color = "#2563eb") => {
    setMsg({ text, color });
    setTimeout(() => setMsg(null), 5000);
  };

  const limpiar = async () => {
    if (!fechaInicio || !fechaFin) return setNotice("Selecciona fecha de inicio y fecha de fin.", "#f97316");
    if (fechaInicio > fechaFin) return setNotice("La fecha de inicio no puede ser mayor que la fecha de fin.", "#ef4444");
    if (confirmacion.trim().toUpperCase() !== "LIMPIAR") return setNotice("Escribe LIMPIAR para confirmar la eliminación.", "#f97316");

    setBusy(true);
    try {
      const inicio = new Date(`${fechaInicio}T00:00:00`);
      const finExclusivo = new Date(`${fechaFin}T00:00:00`);
      finExclusivo.setDate(finExclusivo.getDate() + 1);
      const inicioIso = inicio.toISOString();
      const finIso = finExclusivo.toISOString();

      // Primero se consultan los IDs y después se eliminan por lote. Es más confiable
      // que hacer un DELETE directo con filtros cuando Supabase/RLS no devuelve count.
      let q = sb.from("noticias").select("id,tipo,origen,titulo,created_at").gte("created_at", inicioIso).lt("created_at", finIso).limit(1000);
      if (origen !== "todos") q = q.eq("origen", origen);
      if (tipo !== "todos") q = q.eq("tipo", tipo);
      const { data: filas, error: selectError } = await q;
      if (selectError) throw selectError;
      const ids = (filas || []).map(r => r.id).filter(Boolean);
      if (!ids.length) {
        setNotice("No se encontraron noticias para ese rango/filtro. Prueba origen 'Todos' y tipo 'Todos'.", "#f97316");
        return;
      }

      let eliminadas = 0;
      for (let i = 0; i < ids.length; i += 100) {
        const batch = ids.slice(i, i + 100);
        const { data: deleted, error: deleteError } = await sb.from("noticias").delete().in("id", batch).select("id");
        if (deleteError) throw deleteError;
        eliminadas += deleted?.length || batch.length;
      }

      setConfirmacion("");
      setNotice(`Limpieza realizada. Registros eliminados: ${eliminadas}.`, "#22c55e");
      onCleaned && onCleaned();
    } catch (e) {
      console.error(e);
      setNotice(`No se pudo limpiar noticias: ${e?.message || "verifica permisos DELETE/RLS en Supabase."}`, "#ef4444");
    } finally {
      setBusy(false);
    }
  };

  const prepararLimpiezaMovimientos = () => {
    setOrigen("sistema");
    setTipo("todos");
    setConfirmacion("");
    setNotice("Filtro preparado para movimientos automáticos del sistema. Revisa fechas y escribe LIMPIAR.", "#38bdf8");
  };

  return (
    <div style={{ background:"rgba(239,68,68,0.07)", border:"1px solid rgba(239,68,68,0.25)", borderRadius:"14px", padding:"12px", marginBottom:"16px" }}>
      <button onClick={() => setOpen(v => !v)} style={{ width:"100%", padding:"10px 12px", borderRadius:"10px", border:"1px solid rgba(239,68,68,0.35)", background:"rgba(127,29,29,0.22)", color:"#fca5a5", fontFamily:getFont(theme,"secondary"), fontSize:"11px", fontWeight:900, cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"space-between", gap:"10px" }}>
        <span>🧹 Limpiar noticias por rango</span>
        <span>{open ? "Ocultar" : "Abrir"}</span>
      </button>

      {open && (
        <div style={{ marginTop:"12px" }}>
          <div style={{ color:"rgba(255,255,255,0.55)", fontFamily:getFont(theme,"secondary"), fontSize:"10px", lineHeight:1.5, marginBottom:"10px" }}>
            Elimina noticias dentro del rango seleccionado. Para limpiar movimientos automáticos, usa origen Sistema con tipo Todos; los comunicados/admin se conservan si filtras por otro origen.
          </div>
          {msg && <div style={{ padding:"9px 10px", borderRadius:"9px", background:msg.color+"18", border:`1px solid ${msg.color}55`, color:msg.color, fontFamily:getFont(theme,"secondary"), fontSize:"11px", marginBottom:"10px" }}>{msg.text}</div>}
          <button onClick={prepararLimpiezaMovimientos} disabled={busy} style={{ marginBottom:"10px", padding:"8px 10px", borderRadius:"9px", border:"1px solid rgba(56,189,248,0.35)", background:"rgba(56,189,248,0.10)", color:"#7dd3fc", fontFamily:getFont(theme,"secondary"), fontSize:"10px", fontWeight:900, cursor:busy ? "wait" : "pointer" }}>Preparar limpieza de movimientos automáticos</button>
          <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fit,minmax(150px,1fr))", gap:"8px", marginBottom:"8px" }}>
            <label style={{ display:"grid", gap:"5px", color:"rgba(255,255,255,.65)", fontFamily:getFont(theme,"secondary"), fontSize:"10px", fontWeight:700 }}>
              Fecha inicio
              <input type="date" value={fechaInicio} onChange={e=>setFechaInicio(e.target.value)} style={{ background:"rgba(2,6,23,0.68)", border:"1px solid rgba(148,163,184,0.28)", borderRadius:"9px", padding:"10px", color:"#fff", fontFamily:getFont(theme,"secondary"), fontSize:"11px" }} />
            </label>
            <label style={{ display:"grid", gap:"5px", color:"rgba(255,255,255,.65)", fontFamily:getFont(theme,"secondary"), fontSize:"10px", fontWeight:700 }}>
              Fecha fin
              <input type="date" value={fechaFin} onChange={e=>setFechaFin(e.target.value)} style={{ background:"rgba(2,6,23,0.68)", border:"1px solid rgba(148,163,184,0.28)", borderRadius:"9px", padding:"10px", color:"#fff", fontFamily:getFont(theme,"secondary"), fontSize:"11px" }} />
            </label>
            <label style={{ display:"grid", gap:"5px", color:"rgba(255,255,255,.65)", fontFamily:getFont(theme,"secondary"), fontSize:"10px", fontWeight:700 }}>
              Origen
              <select value={origen} onChange={e=>setOrigen(e.target.value)} style={{ background:"rgba(2,6,23,0.68)", border:"1px solid rgba(148,163,184,0.28)", borderRadius:"9px", padding:"10px", color:"#fff", fontFamily:getFont(theme,"secondary"), fontSize:"11px" }}>
                <option value="todos">Todos</option>
                <option value="sistema">Sistema</option>
                <option value="admin_noticias">Admin noticias</option>
                <option value="comunicados">Comunicados</option>
              </select>
            </label>
            <label style={{ display:"grid", gap:"5px", color:"rgba(255,255,255,.65)", fontFamily:getFont(theme,"secondary"), fontSize:"10px", fontWeight:700 }}>
              Tipo
              <select value={tipo} onChange={e=>setTipo(e.target.value)} style={{ background:"rgba(2,6,23,0.68)", border:"1px solid rgba(148,163,184,0.28)", borderRadius:"9px", padding:"10px", color:"#fff", fontFamily:getFont(theme,"secondary"), fontSize:"11px" }}>
                <option value="todos">Todos</option>
                <option value="comunicado">Comunicado</option>
                <option value="acceso">Acceso</option>
                <option value="terminal">Terminal</option>
                <option value="incidente">Incidente</option>
                <option value="accidente">Accidente</option>
                <option value="patio">Patio</option>
                <option value="carril">Carril</option>
                <option value="vialidad">Vialidad</option>
                <option value="ruta_fiscal">Ruta fiscal</option>
                <option value="resuelto">Resuelto</option>
              </select>
            </label>
          </div>
          <div style={{ display:"grid", gridTemplateColumns:"1fr auto", gap:"8px", alignItems:"center" }}>
            <input value={confirmacion} onChange={e=>setConfirmacion(e.target.value)} placeholder="Escribe LIMPIAR para confirmar" style={{ background:"rgba(2,6,23,0.68)", border:"1px solid rgba(148,163,184,0.28)", borderRadius:"9px", padding:"10px", color:"#fff", fontFamily:getFont(theme,"secondary"), fontSize:"11px" }} />
            <button onClick={limpiar} disabled={busy} style={{ padding:"10px 12px", borderRadius:"9px", border:"1px solid rgba(239,68,68,0.45)", background:busy ? "rgba(100,116,139,.18)" : "linear-gradient(135deg,#ef4444,#b91c1c)", color:"#fff", fontFamily:getFont(theme,"secondary"), fontSize:"11px", fontWeight:900, cursor:busy ? "wait" : "pointer" }}>{busy ? "Limpiando…" : "Eliminar"}</button>
          </div>
        </div>
      )}
    </div>
  );
}

function NoticiasTab({ isAdmin }) {
  const theme = React.useContext(ThemeContext);
  const [noticias,      setNoticias]      = useState([]);
  const [comunicados,   setComunicados]   = useState([]);
  const [loading,       setLoading]       = useState(true);
  const [filtro,        setFiltro]        = useState("todos");
  const [visorItem,     setVisorItem]     = useState(null);
  const [visorItems,    setVisorItems]    = useState([]);
  const [visorIndex,    setVisorIndex]    = useState(0);
  const [downloadingItemUrl, setDownloadingItemUrl] = useState("");
  const [seccion,       setSeccion]       = useState("noticias"); // "noticias" | "comunicados"

  const isComunicadoAprobado = (value) =>
    value === true || value === "true" || value === 1 || value === "1";

  const cargarNoticias = useCallback(() => {
    setLoading(true);
    return sb.from("noticias").select("*").order("created_at", { ascending: false }).limit(150)
      .then(({ data, error }) => {
        if (error) console.error("Error cargando noticias:", error);
        if (data) setNoticias(data);
        setLoading(false);
      });
  }, []);

  const cargarComunicados = useCallback(() => {
    sb.from("comunicados")
      .select("*")
      .order("created_at", { ascending: false })
      .limit(100)
      .then(async ({ data, error }) => {
        if (error) console.error("Error cargando comunicados:", error);
        if (data) {
          const aprobados = data.filter(c => isComunicadoAprobado(c.aprobado));
          setComunicados(aprobados);
          // Sincronización idempotente hacia Noticias.
          for (const c of aprobados.slice(0, 25)) {
            const n = await syncComunicadoToNoticia(c, { processMedia: false });
            if (n) setNoticias(prev => prev.some(x => x.id === n.id) ? prev : [n, ...prev].slice(0, 120));
          }
        }
      });
  }, []);

  useEffect(() => {
    cargarNoticias();
    cargarComunicados();
    const chan = sb.channel("noticias-comunicados-rt")
      .on("postgres_changes", { event: "INSERT", schema: "public", table: "noticias" }, ({ new: r }) => {
        if (r) setNoticias(prev => prev.some(x => x.id === r.id) ? prev : [r, ...prev].slice(0, 150));
      })
      .on("postgres_changes", { event: "UPDATE", schema: "public", table: "noticias" }, ({ new: r }) => {
        if (r) setNoticias(prev => prev.map(x => x.id === r.id ? r : x));
      })
      .on("postgres_changes", { event: "INSERT", schema: "public", table: "comunicados" }, async ({ new: r }) => {
        const aprobado = isComunicadoAprobado(r?.aprobado);
        if (r && aprobado) {
          setComunicados(prev => prev.some(c => c.id === r.id) ? prev : [r, ...prev].slice(0, 80));
          const n = await syncComunicadoToNoticia(r, { processMedia: true });
          if (n) setNoticias(prev => prev.some(x => x.id === n.id) ? prev : [n, ...prev].slice(0, 150));
        }
      })
      .on("postgres_changes", { event: "UPDATE", schema: "public", table: "comunicados" }, async ({ new: r }) => {
        const aprobado = isComunicadoAprobado(r?.aprobado);
        if (r && aprobado) {
          setComunicados(prev => prev.some(c => c.id === r.id) ? prev.map(c => c.id === r.id ? r : c) : [r, ...prev].slice(0, 80));
          const n = await syncComunicadoToNoticia(r, { processMedia: true });
          if (n) setNoticias(prev => prev.some(x => x.id === n.id) ? prev : [n, ...prev].slice(0, 150));
        }
      })
      .on("postgres_changes", { event: "DELETE", schema: "public", table: "comunicados" }, ({ old: r }) => {
        if (r?.id) setComunicados(prev => prev.filter(c => c.id !== r.id));
      })
      .subscribe();
    return () => sb.removeChannel(chan);
  }, [cargarNoticias, cargarComunicados]);

  const FILTROS = [
    { id: "todos",      label: "Todos",       icon: "news" },
    { id: "comunicado", label: "Comunicados", icon: "document" },
    { id: "admin",      label: "Admin",       icon: "dispatch-news" },
    { id: "incidente",  label: "Incidentes",  icon: "alert" },
    { id: "accidente",  label: "Accidentes",  icon: "crash" },
  ];

  const isNoticiaListaParaMostrar = (n) => {
    if (!isNoticiaVisibleEnFeed(n)) return false;
    const created = new Date(n?.created_at).getTime();
    if (!Number.isFinite(created)) return false;
    const hasContent = Boolean(
      String(n?.titulo || "").trim() ||
      String(n?.detalle || "").trim() ||
      String(n?.archivo_url || "").trim() ||
      parseJsonArray(n?.media_urls).length ||
      parseJsonArray(n?.pdf_urls).length
    );
    return hasContent;
  };

  const noticiasVisibles = noticias.filter(isNoticiaListaParaMostrar);
  const filtered = filtro === "todos" ? noticiasVisibles : noticiasVisibles.filter(n => n.tipo === filtro || (filtro === "admin" && String(n.origen || "").toLowerCase().includes("admin_noticias")));

  const timeAgo = (ts) => {
    const t = new Date(ts).getTime();
    if (!Number.isFinite(t)) return "";
    const d = Date.now() - t;
    if (d < 0) return "programada";
    if (d < 60000)    return "hace un momento";
    if (d < 3600000)  return `hace ${Math.floor(d/60000)}min`;
    if (d < 86400000) return `hace ${Math.floor(d/3600000)}h`;
    return `hace ${Math.floor(d/86400000)}d`;
  };

  const isPdf = (url) => url?.toLowerCase().endsWith(".pdf");
  const getMedia = (n) => [...parseJsonArray(n.media_urls), ...(n.archivo_url && !isPdf(n.archivo_url) ? [n.archivo_url] : [])].filter(Boolean);
  const getPdfs = (n) => [...parseJsonArray(n.pdf_urls), ...(n.archivo_url && isPdf(n.archivo_url) ? [n.archivo_url] : [])].filter(Boolean);

  const openVisor = useCallback((item, items = null, index = 0) => {
    const list = Array.isArray(items) && items.length ? items : [item].filter(Boolean);
    setVisorItems(list);
    setVisorIndex(index || 0);
    setVisorItem(list[index || 0] || item || null);
  }, []);

  const loadJsPdf = useCallback(() => new Promise((resolve, reject) => {
    if (window.jspdf?.jsPDF) return resolve(window.jspdf.jsPDF);
    const existing = document.querySelector('script[src*="jspdf.umd.min.js"]');
    if (existing) {
      existing.addEventListener("load", () => resolve(window.jspdf.jsPDF));
      existing.addEventListener("error", reject);
      return;
    }
    const script = document.createElement("script");
    script.src = "https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.1/jspdf.umd.min.js";
    script.onload = () => resolve(window.jspdf.jsPDF);
    script.onerror = reject;
    document.head.appendChild(script);
  }), []);

  const loadPdfJs = useCallback(() => new Promise((resolve, reject) => {
    const finish = () => {
      if (!window.pdfjsLib) return reject(new Error("PDF.js no disponible"));
      try {
        window.pdfjsLib.GlobalWorkerOptions.workerSrc = "https://cdnjs.cloudflare.com/ajax/libs/pdf.js/4.5.136/pdf.worker.min.mjs";
      } catch {}
      resolve(window.pdfjsLib);
    };
    if (window.pdfjsLib) return finish();
    const existing = document.querySelector('script[src*="pdf.min.mjs"], script[src*="pdf.min.js"]');
    if (existing) {
      existing.addEventListener("load", finish);
      existing.addEventListener("error", reject);
      return;
    }
    const script = document.createElement("script");
    script.type = "module";
    script.src = "https://cdnjs.cloudflare.com/ajax/libs/pdf.js/4.5.136/pdf.min.mjs";
    script.onload = finish;
    script.onerror = reject;
    document.head.appendChild(script);
  }), []);

  const loadImageWithCors = useCallback((src) => new Promise((resolve, reject) => {
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => resolve(img);
    img.onerror = reject;
    img.src = src;
  }), []);

  const fileBaseName = useCallback((item, fallbackExt = "jpg") => {
    const raw = String(item?.titulo || item?.detalle || "archivo").toLowerCase()
      .normalize("NFD").replace(/[̀-ͯ]/g, "")
      .replace(/[^a-z0-9]+/g, "-")
      .replace(/^-+|-+$/g, "") || "archivo";
    return `${raw}-con-marca-de-agua.${fallbackExt}`;
  }, []);

  const triggerBlobDownload = useCallback((blob, filename) => {
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = filename;
    document.body.appendChild(a);
    a.click();
    a.remove();
    setTimeout(() => URL.revokeObjectURL(url), 1500);
  }, []);

  const paintReportWatermark = useCallback(async (ctx, width, height) => {
    const wm = await loadImageWithCors(CM_REPORT_WATERMARK);
    const ratio = wm.height / wm.width;
    const wmW = Math.min(width * 0.62, 1300);
    const wmH = wmW * ratio;
    ctx.save();
    ctx.globalAlpha = 0.16;
    ctx.drawImage(wm, (width - wmW) / 2, (height - wmH) / 2, wmW, wmH);
    ctx.restore();
  }, [loadImageWithCors]);

  const downloadNewsImageWithWatermark = useCallback(async (item) => {
    const img = await loadImageWithCors(item.archivo_url);
    const canvas = document.createElement("canvas");
    canvas.width = img.naturalWidth || img.width;
    canvas.height = img.naturalHeight || img.height;
    const ctx = canvas.getContext("2d");
    ctx.fillStyle = "#ffffff";
    ctx.fillRect(0, 0, canvas.width, canvas.height);
    ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
    await paintReportWatermark(ctx, canvas.width, canvas.height);
    const isPng = /\.png(\?|$)/i.test(String(item.archivo_url || ""));
    const mime = isPng ? "image/png" : "image/jpeg";
    const ext = isPng ? "png" : "jpeg";
    const blob = await new Promise(resolve => canvas.toBlob(resolve, mime, 0.95));
    if (!blob) throw new Error("No se pudo crear la imagen con marca de agua");
    triggerBlobDownload(blob, fileBaseName(item, ext));
  }, [fileBaseName, loadImageWithCors, paintReportWatermark, triggerBlobDownload]);

  const downloadNewsPdfWithWatermark = useCallback(async (item) => {
    const [pdfjsLib, jsPDF] = await Promise.all([loadPdfJs(), loadJsPdf()]);
    const res = await fetch(item.archivo_url);
    if (!res.ok) throw new Error("No se pudo descargar el PDF original");
    const data = await res.arrayBuffer();
    const sourcePdf = await pdfjsLib.getDocument({ data }).promise;
    let doc = null;

    for (let pageNo = 1; pageNo <= sourcePdf.numPages; pageNo++) {
      const page = await sourcePdf.getPage(pageNo);
      const viewport = page.getViewport({ scale: 2 });
      const pageCanvas = document.createElement("canvas");
      pageCanvas.width = Math.ceil(viewport.width);
      pageCanvas.height = Math.ceil(viewport.height);
      const pctx = pageCanvas.getContext("2d");
      pctx.fillStyle = "#ffffff";
      pctx.fillRect(0, 0, pageCanvas.width, pageCanvas.height);
      await page.render({ canvasContext: pctx, viewport }).promise;
      await paintReportWatermark(pctx, pageCanvas.width, pageCanvas.height);
      const orientation = viewport.width > viewport.height ? "landscape" : "portrait";
      if (!doc) doc = new jsPDF({ orientation, unit: "mm", format: "letter" });
      else doc.addPage("letter", orientation);
      const pageW = doc.internal.pageSize.getWidth();
      const pageH = doc.internal.pageSize.getHeight();
      const margin = 8;
      const usableW = pageW - margin * 2;
      const usableH = pageH - margin * 2;
      const imgRatio = pageCanvas.height / pageCanvas.width;
      let renderW = usableW;
      let renderH = renderW * imgRatio;
      if (renderH > usableH) {
        renderH = usableH;
        renderW = renderH / imgRatio;
      }
      const dx = (pageW - renderW) / 2;
      const dy = (pageH - renderH) / 2;
      const imgData = pageCanvas.toDataURL("image/jpeg", 0.95);
      doc.addImage(imgData, "JPEG", dx, dy, renderW, renderH, undefined, "FAST");
    }

    const blob = doc.output("blob");
    triggerBlobDownload(blob, fileBaseName(item, "pdf"));
  }, [fileBaseName, loadJsPdf, loadPdfJs, paintReportWatermark, triggerBlobDownload]);

  const downloadItemWithWatermark = useCallback(async (item) => {
    if (!item?.archivo_url) return;
    setDownloadingItemUrl(item.archivo_url);
    try {
      if (isPdf(item.archivo_url) || item?.archivo_tipo === "application/pdf") await downloadNewsPdfWithWatermark(item);
      else await downloadNewsImageWithWatermark(item);
    } catch (e) {
      console.error(e);
      alert("No se pudo descargar el archivo con marca de agua. Verifica el origen del archivo y vuelve a intentarlo.");
    } finally {
      setDownloadingItemUrl("");
    }
  }, [downloadNewsImageWithWatermark, downloadNewsPdfWithWatermark, isPdf]);

  return (
    <div style={{ padding:"16px", paddingBottom:"80px", minHeight:"100vh" }}>
      {visorItem && <VisorFullscreen item={visorItem} items={visorItems} currentIndex={visorIndex} onNavigate={(nextIndex) => {
        if (!visorItems[nextIndex]) return;
        setVisorIndex(nextIndex);
        setVisorItem(visorItems[nextIndex]);
      }} onDownload={downloadItemWithWatermark} downloading={downloadingItemUrl === visorItem?.archivo_url} onClose={() => {
        setVisorItem(null);
        setVisorItems([]);
        setVisorIndex(0);
      }} />}

      <div style={{ background:"linear-gradient(135deg,#0d1b2e,#0a2540)", border:"1px solid rgba(255,255,255,0.15)", borderRadius:"14px", padding:"16px", marginBottom:"16px", textAlign:"center" }}>
        <div style={{ display:"flex", justifyContent:"center", marginBottom:"8px" }}><AppIcon name="dispatch-news" size={34} active={true} /></div>
        <div style={{ color:"rgba(255,255,255,0.95)", fontFamily:getFont(theme, "secondary"), fontWeight:"700", fontSize:"14px", letterSpacing:"1px" }}>Noticias del puerto</div>
        <div style={{ color:"rgba(255,255,255,0.5)", fontSize:"11px", marginTop:"4px", fontFamily:getFont(theme, "secondary") }}>Actualizaciones oficiales y operativas, sin ruido de votos automáticos.</div>
        <div style={{ display:"flex", alignItems:"center", justifyContent:"center", gap:"16px", marginTop:"8px" }}>
          <span style={{ fontSize:"10px", color:"#93c5fd", fontFamily:getFont(theme, "secondary") }}>{noticiasVisibles.length} noticias visibles</span>
          <span style={{ fontSize:"10px", color:"#fbbf24", fontFamily:getFont(theme, "secondary") }}>{comunicados.filter(c => isComunicadoAprobado(c.aprobado)).length} comunicados</span>
        </div>
      </div>

      <div style={{ display:"flex", gap:"8px", marginBottom:"16px" }}>
        <button onClick={() => setSeccion("noticias")} style={{ flex:1, padding:"10px", borderRadius:"10px", border:`1px solid ${seccion==="noticias"?"#38bdf8":"#1e3a5f"}`, background: seccion==="noticias"?"#38bdf822":"#0a1628", color: seccion==="noticias"?"#38bdf8":"#94a3b8", fontFamily:getFont(theme, "secondary"), fontSize:"11px", fontWeight:"700", cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center", gap:"6px" }}>
          <AppIcon name="news" size={16} active={seccion==="noticias"} /> Noticias
        </button>
        <button onClick={() => setSeccion("comunicados")} style={{ flex:1, padding:"10px", borderRadius:"10px", border:`1px solid ${seccion==="comunicados"?"#fbbf24":"#1e3a5f"}`, background: seccion==="comunicados"?"#fbbf2422":"#0a1628", color: seccion==="comunicados"?"#fbbf24":"#94a3b8", fontFamily:getFont(theme, "secondary"), fontSize:"11px", fontWeight:"700", cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center", gap:"6px" }}>
          <AppIcon name="document" size={16} active={seccion==="comunicados"} /> Comunicados
        </button>
      </div>

      {seccion === "noticias" && (
        <>
          <NoticiasAutoJpegReport />
          {isAdmin && <NoticiasAdminCleanup onCleaned={cargarNoticias} />}
          {isAdmin && <NoticiasAdminPublisher onPublished={(n)=>setNoticias(prev=>[n,...prev].slice(0,150))} />}
          <div style={{ display:"flex", gap:"5px", flexWrap:"wrap", marginBottom:"16px" }}>
            {FILTROS.map(f => (
              <button key={f.id} onClick={() => setFiltro(f.id)} style={{ padding:"6px 10px", borderRadius:"10px", border:`1px solid ${filtro===f.id?"#38bdf8":"#1e3a5f"}`, background: filtro===f.id?"#38bdf822":"#0a1628", color: filtro===f.id?"#38bdf8":"#94a3b8", fontFamily:getFont(theme, "secondary"), fontSize:"10px", cursor:"pointer", fontWeight: filtro===f.id?"700":"500", display:"flex", alignItems:"center", gap:"4px" }}>
                <AppIcon name={f.icon} size={15} active={filtro === f.id} /> {f.label}
              </button>
            ))}
          </div>
          {loading && <div style={{ textAlign:"center", padding:"40px", color:"rgba(255,255,255,0.3)", fontFamily:getFont(theme, "secondary"), fontSize:"12px" }}>Cargando noticias...</div>}
          {!loading && filtered.length === 0 && <div style={{ textAlign:"center", padding:"40px", border:"1px dashed #1e3a5f", borderRadius:"12px", color:"rgba(255,255,255,0.35)", fontFamily:getFont(theme, "secondary"), fontSize:"12px" }}>Sin noticias visibles para este filtro.</div>}
          {filtered.map((n) => {
            const media = getMedia(n);
            const pdfs = getPdfs(n);
            const origen = n.origen || (n.tipo === "comunicado" ? "comunicados" : "sistema");
            return (
              <div key={n.id} style={{ background:"rgba(255,255,255,0.08)", backdropFilter:"blur(12px)", WebkitBackdropFilter:"blur(12px)", border:`1px solid ${n.color || "#1e3a5f"}33`, borderLeft:`3px solid ${n.color || "#38bdf8"}`, borderRadius:"12px", padding:"12px 14px", marginBottom:"10px" }}>
                <div style={{ display:"flex", alignItems:"flex-start", gap:"10px" }}>
                  <div style={{ width:"34px", height:"34px", flexShrink:0, background:(n.color||"#38bdf8")+"22", border:`1px solid ${n.color||"#38bdf8"}44`, borderRadius:"9px", display:"flex", alignItems:"center", justifyContent:"center" }}><AppIcon name={n.icono || "news"} size={18} active={true} /></div>
                  <div style={{ flex:1, minWidth:0 }}>
                    <div style={{ display:"flex", alignItems:"center", gap:"6px", flexWrap:"wrap", marginBottom:"3px" }}>
                      <div style={{ color:"rgba(255,255,255,0.95)", fontFamily:getFont(theme, "secondary"), fontWeight:"700", fontSize:"12px" }}>{n.titulo}</div>
                      {origen === "comunicados" && <Badge color="#2563eb" small>Origen: Comunicados</Badge>}
                    </div>
                    {n.detalle && <div style={{ whiteSpace:"pre-wrap", color:"rgba(255,255,255,0.58)", fontSize:"11px", lineHeight:1.5, marginBottom:"8px" }}>{n.detalle}</div>}
                    {media.length > 0 && <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fill,minmax(92px,1fr))", gap:"8px", marginBottom:"8px" }}>
                      {media.slice(0, 8).map((u,i)=><button key={u+i} onClick={()=>openVisor({ ...n, archivo_url:u, archivo_tipo:"image/jpeg" }, media.slice(0, 8).map((mu)=>({ ...n, archivo_url:mu, archivo_tipo:"image/jpeg" })), i)} style={{ padding:0, border:"1px solid rgba(255,255,255,.12)", borderRadius:"9px", overflow:"hidden", background:"#061428", cursor:"pointer" }}><img src={u} alt={n.titulo} style={{ width:"100%", height:"76px", objectFit:"cover", display:"block" }} /></button>)}
                    </div>}
                    {pdfs.length > 0 && <div style={{ display:"flex", gap:"6px", flexWrap:"wrap", marginBottom:"8px" }}>{pdfs.map((u,i)=><button key={u+i} onClick={()=>openVisor({ ...n, archivo_url:u, archivo_tipo:"application/pdf" }, pdfs.map((pu)=>({ ...n, archivo_url:pu, archivo_tipo:"application/pdf" })), i)} style={{ padding:"6px 9px", borderRadius:"8px", background:"rgba(37,99,235,.14)", border:"1px solid rgba(37,99,235,.35)", color:"#93c5fd", fontSize:"10px", fontFamily:getFont(theme,"secondary"), textDecoration:"none", fontWeight:700, cursor:"pointer" }}>Ver PDF {i+1}</button>)}</div>}
                    <div style={{ display:"flex", alignItems:"center", gap:"6px", flexWrap:"wrap" }}>
                      <span style={{ fontSize:"9px", color:"rgba(255,255,255,0.35)", fontFamily:getFont(theme, "secondary") }}>{timeAgo(n.created_at)}</span>
                      <span style={{ width:"3px", height:"3px", background:"#334155", borderRadius:"50%" }} />
                      <span style={{ fontSize:"9px", color:(n.color||"#38bdf8"), fontFamily:getFont(theme, "secondary"), fontWeight:"700", textTransform:"uppercase" }}>{n.tipo}</span>
                      <span style={{ width:"3px", height:"3px", background:"#334155", borderRadius:"50%" }} />
                      <span style={{ fontSize:"9px", color:"rgba(255,255,255,.42)", fontFamily:getFont(theme,"secondary") }}>Origen: {origen === "comunicados" ? "Comunicados" : "Sistema"}</span>
                    </div>
                  </div>
                </div>
              </div>
            );
          })}
          {filtered.length > 0 && <div style={{ textAlign:"center", padding:"16px", color:"rgba(255,255,255,0.3)", fontFamily:getFont(theme, "secondary"), fontSize:"10px" }}>— Mostrando {filtered.length} noticias —</div>}
        </>
      )}

      {seccion === "comunicados" && (
        <ComunicadosSection 
          isAdmin={isAdmin}
          comunicados={comunicados}
          onReload={cargarComunicados}
          setVisorItem={openVisor}
          onDownloadItem={downloadItemWithWatermark}
          downloadingItemUrl={downloadingItemUrl}
          timeAgo={timeAgo}
          isPdf={isPdf}
        />
      )}
    </div>
  );
}


