function StarRating({ value=0, onRate=null, small=false }) {
  const theme = React.useContext(ThemeContext);
  const rounded = Math.round(Number(value || 0));
  return <div style={{ display:"inline-flex", gap: small ? "1px" : "3px", alignItems:"center" }}>
    {[1,2,3,4,5].map(n => (
      <button key={n} onClick={() => onRate && onRate(n)} disabled={!onRate} style={{ background:"transparent", border:"none", padding: small ? "0 1px" : "1px 2px", cursor:onRate?"pointer":"default", color:n<=rounded?"#fbbf24":"rgba(255,255,255,0.22)", fontSize:small?"13px":"18px", lineHeight:1, fontFamily:getFont(theme,"secondary") }}>★</button>
    ))}
  </div>;
}

function PosturasTab({ authUser, myId, setActive, isAdmin=false }) {
  const theme = React.useContext(ThemeContext);
  const [sub, setSub] = useState("posturas");
  const [vista, setVista] = useState("postular");
  const [trabajadores, setTrabajadores] = useState([]);
  const [empresas, setEmpresas] = useState([]);
  const [ratings, setRatings] = useState([]);
  const [quejas, setQuejas] = useState([]);
  const [loading, setLoading] = useState(false);
  const [q, setQ] = useState("");
  const [filtroEstatus, setFiltroEstatus] = useState("todos");
  const [filtroAlcance, setFiltroAlcance] = useState("todos");
  const [filtroEstrellas, setFiltroEstrellas] = useState("todos");
  const [pageTrab, setPageTrab] = useState(1);
  const [pageEmp, setPageEmp] = useState(1);
  const [msg, setMsg] = useState(null);
  const [showReminder, setShowReminder] = useState(false);
  const [pisForm, setPisForm] = useState({ asipona:"MANZANILLO", tipo:"DEA", id:"" });
  const [pisLoading, setPisLoading] = useState(false);
  const [pisResult, setPisResult] = useState(null);
  const [pisEmailCopied, setPisEmailCopied] = useState(false);
  const [pisCopiedField, setPisCopiedField] = useState("");
  const [pisContactMessage, setPisContactMessage] = useState("");
  const [pisContactUnlocked, setPisContactUnlocked] = useState(false);
  const [pisUnlockRequested, setPisUnlockRequested] = useState(false);
  const [pisUnlockSeconds, setPisUnlockSeconds] = useState(0);
  const [pisHistory, setPisHistory] = useState(() => {
    try { return JSON.parse(localStorage.getItem("cm_pis_verificaciones") || "[]"); } catch { return []; }
  });
  const PAGE_SIZE = 8;

  const emptyTrab = { nombre_completo:"", edad:"", licencia:"Federal tipo B - Carga general", maniobra:"Full", alcance:"Local", telefono_llamadas:"", telefono_whatsapp:"", correo:"", disponible:true };
  const emptyEmp = { razon_social:"", rfc:"", tipo_empresa:"Transportista", ubicacion:"", contacto_tecnico:"", representante:"", correo:"", telefono:"", whatsapp:"", estatus:"tiene_trabajo", alcance:"Local" };
  const [trabForm, setTrabForm] = useState(emptyTrab);
  const [empForm, setEmpForm] = useState(emptyEmp);
  const [editingTrabId, setEditingTrabId] = useState(null);
  const [editingEmpId, setEditingEmpId] = useState(null);

  const card = { background:"rgba(255,255,255,0.06)", border:"1px solid rgba(255,255,255,0.12)", borderRadius:"15px", padding:"16px", boxShadow:"0 10px 26px rgba(0,0,0,0.18)" };
  const input = { width:"100%", boxSizing:"border-box", background:"rgba(3,10,22,0.72)", border:"1px solid rgba(56,189,248,0.22)", borderRadius:"10px", padding:"11px 12px", color:"rgba(255,255,255,0.92)", fontFamily:getFont(theme,"secondary"), fontSize:"12px", outline:"none" };
  const label = { fontFamily:getFont(theme,"secondary"), fontSize:"9px", color:"rgba(255,255,255,0.45)", fontWeight:"800", letterSpacing:"1px", textTransform:"uppercase", marginBottom:"5px" };
  const btn = (color="#38bdf8") => ({ border:`1px solid ${color}66`, background:`${color}18`, color, borderRadius:"10px", padding:"10px 13px", fontFamily:getFont(theme,"secondary"), fontSize:"11px", fontWeight:"800", cursor:"pointer" });

  const avgFor = (type, id) => {
    const rows = ratings.filter(r => r.profile_type === type && String(r.profile_id) === String(id));
    if (!rows.length) return { avg:0, count:0 };
    return { avg: rows.reduce((a,r)=>a+Number(r.stars||0),0)/rows.length, count: rows.length };
  };
  const commentsFor = (id) => ratings.filter(r => r.profile_type === "trabajador" && String(r.profile_id) === String(id) && (r.comment || "").trim());

  const loadPosturas = async () => {
    setLoading(true);
    try {
      const [{ data:t }, { data:e }, { data:r }, { data:qj }] = await Promise.all([
        sb.from("posturas_trabajadores").select("*").eq("activo", true).order("updated_at", { ascending:false }),
        sb.from("posturas_empresas").select("*").eq("activo", true).order("updated_at", { ascending:false }),
        sb.from("posturas_ratings").select("*").order("created_at", { ascending:false }),
        sb.from("posturas_quejas").select("*").order("created_at", { ascending:false }),
      ]);
      setTrabajadores(t || []); setEmpresas(e || []); setRatings(r || []); setQuejas(qj || []);
      const myProfiles = [...(t||[]), ...(e||[])].filter(x => (authUser?.id && x.user_id === authUser.id) || x.device_id === myId);
      const stale = myProfiles.some(x => Date.now() - new Date(x.updated_at || x.created_at || Date.now()).getTime() > 90*24*60*60*1000);
      setShowReminder(!!authUser && stale);
    } catch (e) {
      setMsg({ type:"err", text:"No se pudieron cargar posturas. Verifica que las tablas existan en Supabase." });
    }
    setLoading(false);
  };
  useEffect(() => { loadPosturas(); }, [authUser?.id, myId]);

  useEffect(() => {
    if (!pisResult) return undefined;
    const resetTimer = setTimeout(() => {
      setPisForm({ asipona:"MANZANILLO", tipo:"DEA", id:"" });
      setPisResult(null);
      setPisContactMessage("");
      setPisEmailCopied(false);
      setPisCopiedField("");
      setPisContactUnlocked(false);
      setPisUnlockRequested(false);
      setPisUnlockSeconds(0);
    }, 120000);
    return () => clearTimeout(resetTimer);
  }, [pisResult?.checked_at, pisResult?.status]);

  useEffect(() => {
    if (!pisResult || !pisUnlockRequested || pisContactUnlocked) return undefined;
    setPisUnlockSeconds(30);
    const unlockStartedAt = Date.now();
    const interval = setInterval(() => {
      const remaining = Math.max(0, 30 - Math.floor((Date.now() - unlockStartedAt) / 1000));
      setPisUnlockSeconds(remaining);
      if (remaining <= 0) {
        setPisContactUnlocked(true);
        clearInterval(interval);
      }
    }, 500);
    const unlockTimer = setTimeout(() => {
      setPisContactUnlocked(true);
      setPisUnlockSeconds(0);
    }, 30000);
    return () => {
      clearInterval(interval);
      clearTimeout(unlockTimer);
    };
  }, [pisResult?.checked_at, pisResult?.status, pisUnlockRequested, pisContactUnlocked]);

  const canEdit = (row) => !!authUser && row.user_id === authUser.id;
  const requireLogin = () => { setMsg({ type:"err", text:"Para guardar y editar tu perfil, primero crea o inicia sesión en Más info." }); return false; };

  const saveTrab = async () => {
    if (!authUser) return requireLogin();
    if (!trabForm.nombre_completo.trim() || !trabForm.edad || !trabForm.telefono_llamadas.trim() || !trabForm.telefono_whatsapp.trim()) { setMsg({type:"err", text:"Completa nombre, edad, teléfono de llamadas y WhatsApp."}); return; }
    const payload = { ...trabForm, edad:Number(trabForm.edad), user_id:authUser.id, device_id:myId, updated_at:new Date().toISOString(), activo:true };
    const res = editingTrabId ? await sb.from("posturas_trabajadores").update(payload).eq("id", editingTrabId) : await sb.from("posturas_trabajadores").insert(payload);
    if (res.error) setMsg({type:"err", text:res.error.message}); else { setMsg({type:"ok", text:"Perfil de trabajador guardado."}); setTrabForm(emptyTrab); setEditingTrabId(null); loadPosturas(); }
  };
  const saveEmp = async () => {
    if (!authUser) return requireLogin();
    if (!empForm.razon_social.trim() || !empForm.rfc.trim() || !empForm.correo.includes("@") || !empForm.representante.trim()) { setMsg({type:"err", text:"Completa razón social, RFC, representante y correo obligatorio."}); return; }
    const payload = { ...empForm, user_id:authUser.id, device_id:myId, updated_at:new Date().toISOString(), activo:true };
    const res = editingEmpId ? await sb.from("posturas_empresas").update(payload).eq("id", editingEmpId) : await sb.from("posturas_empresas").insert(payload);
    if (res.error) setMsg({type:"err", text:res.error.message}); else { setMsg({type:"ok", text:"Perfil de empresa guardado."}); setEmpForm(emptyEmp); setEditingEmpId(null); loadPosturas(); }
  };
  const rate = async (type, id, stars, comment="") => {
    const payload = { profile_type:type, profile_id:id, user_id:authUser?.id || null, device_id:myId, stars, comment: type === "trabajador" ? comment.trim() : null };
    const { error } = await sb.from("posturas_ratings").insert(payload);
    if (error) setMsg({type:"err", text:error.message}); else { setMsg({type:"ok", text:"Calificación registrada."}); loadPosturas(); }
  };
  const sendQueja = async (empresa) => {
    const texto = prompt(`Escribe tu queja sobre ${empresa.razon_social}. El admin la revisará antes de publicarla.`);
    if (!texto || !texto.trim()) return;
    const { error } = await sb.from("posturas_quejas").insert({ empresa_id:empresa.id, device_id:myId, user_id:authUser?.id || null, comentario:texto.trim(), aprobado:false });
    if (error) setMsg({type:"err", text:error.message}); else setMsg({type:"ok", text:"Queja enviada a revisión del administrador."});
  };
  const approveQueja = async (id, aprobado=true) => { await sb.from("posturas_quejas").update({ aprobado }).eq("id", id); loadPosturas(); };

  const adminTargetLabel = (row, type) => type === "trabajador" ? (row.nombre_completo || "Trabajador") : (row.razon_social || "Empresa");
  const adminDeleteProfile = async (row, type) => {
    if (!isAdmin) return;
    const name = adminTargetLabel(row, type);
    if (!confirm(`¿Borrar/ocultar el perfil de ${name}?`)) return;
    const table = type === "trabajador" ? "posturas_trabajadores" : "posturas_empresas";
    const { error } = await sb.from(table).update({ activo:false, updated_at:new Date().toISOString() }).eq("id", row.id);
    if (error) setMsg({type:"err", text:error.message});
    else {
      setMsg({type:"ok", text:`Perfil de ${name} borrado/oculto.`});
      auditLog({ action:"posturas_borrar_perfil", section:`posturas_${type}`, entityId:row.id, before:row, after:{ summary:`Admin borró perfil ${name}`, profile_type:type, target_device_id:row.device_id || null, target_user_id:row.user_id || null }, actor:"Admin" });
      loadPosturas();
    }
  };
  const adminWarnProfile = async (row, type) => {
    if (!isAdmin) return;
    const name = adminTargetLabel(row, type);
    const message = prompt(`Mensaje de advertencia para ${name}:`, `Tu perfil de ${type === "trabajador" ? "trabajador" : "empresa"} requiere revisión. Actualiza o corrige tu información.`);
    if (!message || !message.trim()) return;
    if (!row.device_id && !row.user_id) { setMsg({type:"err", text:"Este perfil no tiene device_id ni cuenta asociada para enviar advertencia."}); return; }
    const payload = { device_id:row.device_id || myId, user_id:row.user_id || null, message:message.trim(), type:"advertencia", read:false, created_at:new Date().toISOString() };
    const { error } = await sb.from("admin_user_messages").insert(payload);
    if (error) setMsg({type:"err", text:error.message});
    else {
      setMsg({type:"ok", text:`Advertencia enviada a ${name}.`});
      auditLog({ action:"posturas_advertencia", section:`posturas_${type}`, entityId:row.id, after:{ summary:`Admin envió advertencia a ${name}`, profile_type:type, target_device_id:row.device_id || null, target_user_id:row.user_id || null }, actor:"Admin" });
    }
  };
  const adminSanctionProfile = async (row, type, sanctionType) => {
    if (!isAdmin) return;
    const name = adminTargetLabel(row, type);
    const reason = prompt(`${sanctionType === "ban" ? "Motivo de baneo" : "Motivo de bloqueo"} para ${name}:`, sanctionType === "ban" ? "Baneo indefinido por administración." : "Bloqueo temporal por administración.");
    if (reason === null) return;
    let until_at = null;
    if (sanctionType === "temp_block") {
      const hours = Number(prompt("Horas de bloqueo:", "24") || "24");
      until_at = new Date(Date.now() + Math.max(1, hours) * 60 * 60 * 1000).toISOString();
    }
    if (!row.device_id && !row.user_id) { setMsg({type:"err", text:"Este perfil no tiene device_id ni cuenta asociada para sancionar."}); return; }
    const payload = { device_id:row.device_id || myId, user_id:row.user_id || null, type:sanctionType, reason:reason || (sanctionType === "ban" ? "Baneo indefinido" : "Bloqueo temporal"), actions:["web","vote","report"], until_at, active:true, created_at:new Date().toISOString() };
    const { error } = await sb.from("admin_user_sanctions").insert(payload);
    if (error) setMsg({type:"err", text:error.message});
    else {
      setMsg({type:"ok", text:`${sanctionType === "ban" ? "Baneo" : "Bloqueo"} aplicado a ${name}.`});
      auditLog({ action:sanctionType === "ban" ? "posturas_baneo" : "posturas_bloqueo", section:`posturas_${type}`, entityId:row.id, after:{ summary:`Admin aplicó ${sanctionType === "ban" ? "baneo" : "bloqueo"} a ${name}`, profile_type:type, target_device_id:row.device_id || null, target_user_id:row.user_id || null, until_at }, actor:"Admin" });
    }
  };
  const AdminProfileActions = ({ row, type }) => !isAdmin ? null : <div style={{ marginTop:"12px", padding:"10px", border:"1px solid rgba(251,191,36,0.28)", background:"rgba(251,191,36,0.06)", borderRadius:"12px" }}>
    <div style={{ color:"#fbbf24", fontFamily:getFont(theme,"secondary"), fontSize:"10px", fontWeight:"900", letterSpacing:"1px", marginBottom:"7px" }}>ADMIN · GESTIÓN DEL PERFIL</div>
    <div style={{ color:"rgba(255,255,255,0.48)", fontFamily:getFont(theme,"secondary"), fontSize:"9px", lineHeight:1.5, marginBottom:"8px" }}>
      ID perfil: {row.id}<br/>Cuenta: {row.user_id || "Sin cuenta"}<br/>Dispositivo: {row.device_id || "Sin device_id"}
    </div>
    <div style={{ display:"flex", gap:"7px", flexWrap:"wrap" }}>
      <button onClick={()=>adminWarnProfile(row, type)} style={btn("#fbbf24")}>Advertencia</button>
      <button onClick={()=>adminSanctionProfile(row, type, "temp_block")} style={btn("#f97316")}>Procesando Bloquear</button>
      <button onClick={()=>adminSanctionProfile(row, type, "ban")} style={btn("#ef4444")}>⛔ Baneo</button>
      <button onClick={()=>adminDeleteProfile(row, type)} style={btn("#94a3b8")}>Eliminar️ Borrar perfil</button>
    </div>
  </div>;

  const filterRows = (rows, type) => {
    const term = q.trim().toLowerCase();
    return rows.filter(row => {
      const rating = avgFor(type, row.id).avg;
      const statusTxt = type === "trabajador" ? (row.disponible ? "disponible" : "no disponible") : (row.estatus === "tiene_trabajo" ? "tiene trabajo" : "lleno");
      const hay = !term || JSON.stringify(row).toLowerCase().includes(term) || statusTxt.includes(term);
      const okStatus = filtroEstatus === "todos" || (type === "trabajador" ? String(row.disponible) === filtroEstatus : row.estatus === filtroEstatus);
      const okAlcance = filtroAlcance === "todos" || row.alcance === filtroAlcance;
      const okStars = filtroEstrellas === "todos" || rating >= Number(filtroEstrellas);
      return hay && okStatus && okAlcance && okStars;
    });
  };
  const trabFiltrados = filterRows(trabajadores, "trabajador");
  const empFiltradas = filterRows(empresas, "empresa");
  const paginate = (rows, page) => rows.slice((page-1)*PAGE_SIZE, page*PAGE_SIZE);

  const ProfileHeader = () => (
    <div style={{ ...card, marginBottom:"14px", display:"flex", justifyContent:"space-between", gap:"12px", alignItems:"center", flexWrap:"wrap" }}>
      <div>
        <div style={{ fontFamily:getFont(theme,"title"), fontSize:"20px", color:"#fff", fontWeight:"900" }}>🤝 Posturas</div>
        <div style={{ fontFamily:getFont(theme,"secondary"), fontSize:"11px", color:"rgba(255,255,255,0.52)", marginTop:"3px" }}>Perfiles de trabajadores y empresas visibles para la comunidad.</div>
      </div>
      <button onClick={() => setActive && setActive("tutorial")} style={btn(authUser ? "#22c55e" : "#fbbf24")}>{authUser ? "👤 Cuenta activa" : "👤 Crear cuenta / iniciar sesión"}</button>
    </div>
  );

  const Filters = () => <div style={{ ...card, marginBottom:"14px" }}>
    <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fit,minmax(170px,1fr))", gap:"10px" }}>
      <input value={q} onChange={e=>{setQ(e.target.value); setPageTrab(1); setPageEmp(1);}} placeholder="Buscar por nombre, RFC, licencia, ciudad..." style={input} />
      <select value={filtroEstatus} onChange={e=>setFiltroEstatus(e.target.value)} style={input}><option value="todos">Todos los estatus</option><option value="true">Trabajador disponible</option><option value="false">Trabajador no disponible</option><option value="tiene_trabajo">Empresa con trabajo</option><option value="lleno">Empresa llena</option></select>
      <select value={filtroAlcance} onChange={e=>setFiltroAlcance(e.target.value)} style={input}><option value="todos">Local / foráneo</option>{POSTURAS_ALCANCE.map(x=><option key={x} value={x}>{x}</option>)}</select>
      <select value={filtroEstrellas} onChange={e=>setFiltroEstrellas(e.target.value)} style={input}><option value="todos">Todas las estrellas</option><option value="5">5 estrellas</option><option value="4">4+ estrellas</option><option value="3">3+ estrellas</option></select>
    </div>
  </div>;

  const TrabCard = ({ row }) => {
    const r = avgFor("trabajador", row.id);
    const [myStars, setMyStars] = useState(0);
    const [comment, setComment] = useState("");
    return <div style={card}>
      <div style={{ display:"flex", justifyContent:"space-between", gap:"10px", alignItems:"flex-start" }}>
        <div><div style={{ color:"#fff", fontFamily:getFont(theme,"secondary"), fontWeight:"900", fontSize:"14px" }}>{row.nombre_completo}</div><div style={{ color:"rgba(255,255,255,0.45)", fontSize:"11px", marginTop:"4px" }}>{row.edad} años · {row.licencia}</div></div>
        <span style={{ padding:"5px 9px", borderRadius:"999px", background:row.disponible?"#22c55e18":"#ef444418", color:row.disponible?"#22c55e":"#ef4444", fontSize:"10px", fontWeight:"900" }}>{row.disponible?"Disponible":"No disponible"}</span>
      </div>
      <div style={{ marginTop:"9px", color:"rgba(255,255,255,0.64)", fontSize:"11px", lineHeight:1.7 }}>{row.maniobra} · {row.alcance}<br/>📞 {row.telefono_llamadas} · WhatsApp: {row.telefono_whatsapp}{row.correo ? <><br/>✉️ {row.correo}</> : null}</div>
      <div style={{ marginTop:"10px", display:"flex", alignItems:"center", gap:"8px", flexWrap:"wrap" }}><StarRating value={r.avg} small /> <span style={{ color:"rgba(255,255,255,0.45)", fontSize:"10px" }}>{r.avg ? r.avg.toFixed(1) : "Sin calificaciones"} · {r.count}</span></div>
      {canEdit(row) && <button onClick={()=>{setTrabForm({...row, edad:String(row.edad||"")}); setEditingTrabId(row.id); setVista("postular"); window.scrollTo({top:0, behavior:"smooth"});}} style={{...btn("#a78bfa"), marginTop:"10px"}}>👤 Editar mi perfil</button>}
      <AdminProfileActions row={row} type="trabajador" />
      <div style={{ marginTop:"12px", paddingTop:"10px", borderTop:"1px solid rgba(255,255,255,0.08)" }}>
        <div style={{ color:"rgba(255,255,255,0.55)", fontSize:"10px", fontWeight:"800", marginBottom:"6px" }}>Calificar trabajo</div>
        <StarRating value={myStars} onRate={setMyStars} />
        <textarea value={comment} onChange={e=>setComment(e.target.value)} placeholder="Comentario opcional sobre su trabajo" style={{...input, marginTop:"7px", minHeight:"54px"}} />
        <button disabled={!myStars} onClick={()=>rate("trabajador", row.id, myStars, comment)} style={{...btn("#fbbf24"), opacity:myStars?1:.45, marginTop:"7px"}}>Guardar calificación</button>
      </div>
      {commentsFor(row.id).slice(0,3).map(c => <div key={c.id} style={{ marginTop:"8px", color:"rgba(255,255,255,0.58)", fontSize:"10px", background:"rgba(255,255,255,0.04)", borderRadius:"8px", padding:"8px" }}>★ {c.stars} · {c.comment}</div>)}
    </div>;
  };

  const EmpresaCard = ({ row }) => {
    const r = avgFor("empresa", row.id);
    const [myStars, setMyStars] = useState(0);
    const aprobadas = quejas.filter(q => q.empresa_id === row.id && q.aprobado);
    return <div style={card}>
      <div style={{ display:"flex", justifyContent:"space-between", gap:"10px", alignItems:"flex-start" }}>
        <div><div style={{ color:"#fff", fontFamily:getFont(theme,"secondary"), fontWeight:"900", fontSize:"14px" }}>{row.razon_social}</div><div style={{ color:"rgba(255,255,255,0.45)", fontSize:"11px", marginTop:"4px" }}>{row.tipo_empresa} · RFC {row.rfc}</div></div>
        <span style={{ padding:"5px 9px", borderRadius:"999px", background:row.estatus==="tiene_trabajo"?"#22c55e18":"#ef444418", color:row.estatus==="tiene_trabajo"?"#22c55e":"#ef4444", fontSize:"10px", fontWeight:"900" }}>{row.estatus==="tiene_trabajo"?"Tiene trabajo":"Lleno"}</span>
      </div>
      <div style={{ marginTop:"9px", color:"rgba(255,255,255,0.64)", fontSize:"11px", lineHeight:1.7 }}>{row.ubicacion} · {row.alcance}<br/>Representante: {row.representante}<br/>Contacto técnico: {row.contacto_tecnico || "No especificado"}<br/>✉️ {row.correo}{row.telefono ? ` · 📞 ${row.telefono}` : ""}</div>
      <div style={{ marginTop:"10px", display:"flex", alignItems:"center", gap:"8px", flexWrap:"wrap" }}><StarRating value={r.avg} small /> <span style={{ color:"rgba(255,255,255,0.45)", fontSize:"10px" }}>{r.avg ? r.avg.toFixed(1) : "Sin calificaciones"} · {r.count}</span></div>
      {canEdit(row) && <button onClick={()=>{setEmpForm({...row}); setEditingEmpId(row.id); setVista("empresario"); window.scrollTo({top:0, behavior:"smooth"});}} style={{...btn("#a78bfa"), marginTop:"10px"}}>👤 Editar empresa</button>}
      <AdminProfileActions row={row} type="empresa" />
      <div style={{ marginTop:"12px", display:"flex", gap:"8px", alignItems:"center", flexWrap:"wrap", borderTop:"1px solid rgba(255,255,255,0.08)", paddingTop:"10px" }}><span style={{ color:"rgba(255,255,255,0.5)", fontSize:"10px", fontWeight:"800" }}>Calificar empresa</span><StarRating value={myStars} onRate={setMyStars} /><button disabled={!myStars} onClick={()=>rate("empresa", row.id, myStars)} style={{...btn("#fbbf24"), opacity:myStars?1:.45}}>Guardar</button><button onClick={()=>sendQueja(row)} style={btn("#ef4444")}>Queja</button></div>
      {aprobadas.slice(0,2).map(c => <div key={c.id} style={{ marginTop:"8px", color:"rgba(255,255,255,0.58)", fontSize:"10px", background:"rgba(239,68,68,0.08)", border:"1px solid rgba(239,68,68,0.22)", borderRadius:"8px", padding:"8px" }}>Queja aprobada: {c.comentario}</div>)}
    </div>;
  };

  const WorkerForm = () => <div style={card}>
    <div style={{ fontFamily:getFont(theme,"title"), color:"#fff", fontSize:"17px", fontWeight:"900", marginBottom:"6px" }}>Postular como trabajador</div>
    <div style={{ color:"rgba(255,255,255,0.52)", fontFamily:getFont(theme,"secondary"), fontSize:"11px", marginBottom:"14px", lineHeight:1.6 }}>Para guardar y editar tu perfil necesitas crear usuario en Más info. Todos podrán ver tu perfil público.</div>
    <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fit,minmax(220px,1fr))", gap:"10px" }}>
      <div><div style={label}>Nombre completo</div><input style={input} value={trabForm.nombre_completo} onChange={e=>setTrabForm(f=>({...f,nombre_completo:e.target.value}))}/></div>
      <div><div style={label}>Edad</div><input type="number" style={input} value={trabForm.edad} onChange={e=>setTrabForm(f=>({...f,edad:e.target.value}))}/></div>
      <div><div style={label}>Tipo de licencia</div><select style={input} value={trabForm.licencia} onChange={e=>setTrabForm(f=>({...f,licencia:e.target.value}))}>{POSTURAS_LICENCIAS.map(x=><option key={x}>{x}</option>)}</select></div>
      <div><div style={label}>Tipo de maniobra</div><select style={input} value={trabForm.maniobra} onChange={e=>setTrabForm(f=>({...f,maniobra:e.target.value}))}>{POSTURAS_MANIOBRAS.map(x=><option key={x}>{x}</option>)}</select></div>
      <div><div style={label}>Labora</div><select style={input} value={trabForm.alcance} onChange={e=>setTrabForm(f=>({...f,alcance:e.target.value}))}>{POSTURAS_ALCANCE.map(x=><option key={x}>{x}</option>)}</select></div>
      <div><div style={label}>Teléfono llamadas</div><input style={input} value={trabForm.telefono_llamadas} onChange={e=>setTrabForm(f=>({...f,telefono_llamadas:e.target.value}))}/></div>
      <div><div style={label}>WhatsApp</div><input style={input} value={trabForm.telefono_whatsapp} onChange={e=>setTrabForm(f=>({...f,telefono_whatsapp:e.target.value}))}/></div>
      <div><div style={label}>Correo opcional</div><input style={input} value={trabForm.correo||""} onChange={e=>setTrabForm(f=>({...f,correo:e.target.value}))}/></div>
      <div><div style={label}>Estatus</div><select style={input} value={String(trabForm.disponible)} onChange={e=>setTrabForm(f=>({...f,disponible:e.target.value==="true"}))}><option value="true">Disponible para laborar</option><option value="false">No disponible</option></select></div>
    </div>
    <div style={{ display:"flex", gap:"8px", marginTop:"14px", flexWrap:"wrap" }}><button onClick={saveTrab} style={btn("#22c55e")}>{editingTrabId?"Actualizar perfil":"Guardar perfil"}</button>{editingTrabId && <button onClick={()=>{setEditingTrabId(null); setTrabForm(emptyTrab);}} style={btn("#94a3b8")}>Cancelar edición</button>}</div>
  </div>;

  const CompanyForm = () => <div style={card}>
    <div style={{ fontFamily:getFont(theme,"title"), color:"#fff", fontSize:"17px", fontWeight:"900", marginBottom:"6px" }}>Empresario</div>
    <div style={{ color:"rgba(255,255,255,0.52)", fontFamily:getFont(theme,"secondary"), fontSize:"11px", marginBottom:"14px", lineHeight:1.6 }}>Registra empresa, contactos y disponibilidad de trabajo. Las quejas requieren aprobación admin antes de mostrarse.</div>
    <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fit,minmax(220px,1fr))", gap:"10px" }}>
      <div><div style={label}>Razón social / nombre</div><input style={input} value={empForm.razon_social} onChange={e=>setEmpForm(f=>({...f,razon_social:e.target.value}))}/></div>
      <div><div style={label}>RFC</div><input style={input} value={empForm.rfc} onChange={e=>setEmpForm(f=>({...f,rfc:e.target.value.toUpperCase()}))}/></div>
      <div><div style={label}>Tipo de empresa</div><select style={input} value={empForm.tipo_empresa} onChange={e=>setEmpForm(f=>({...f,tipo_empresa:e.target.value}))}>{POSTURAS_TIPO_EMPRESA.map(x=><option key={x}>{x}</option>)}</select></div>
      <div><div style={label}>Ubicación</div><input style={input} value={empForm.ubicacion} onChange={e=>setEmpForm(f=>({...f,ubicacion:e.target.value}))}/></div>
      <div><div style={label}>Contacto técnico</div><input style={input} value={empForm.contacto_tecnico||""} onChange={e=>setEmpForm(f=>({...f,contacto_tecnico:e.target.value}))}/></div>
      <div><div style={label}>Representante</div><input style={input} value={empForm.representante} onChange={e=>setEmpForm(f=>({...f,representante:e.target.value}))}/></div>
      <div><div style={label}>Correo obligatorio</div><input style={input} value={empForm.correo} onChange={e=>setEmpForm(f=>({...f,correo:e.target.value}))}/></div>
      <div><div style={label}>Teléfono</div><input style={input} value={empForm.telefono||""} onChange={e=>setEmpForm(f=>({...f,telefono:e.target.value}))}/></div>
      <div><div style={label}>WhatsApp</div><input style={input} value={empForm.whatsapp||""} onChange={e=>setEmpForm(f=>({...f,whatsapp:e.target.value}))}/></div>
      <div><div style={label}>Trabajo</div><select style={input} value={empForm.estatus} onChange={e=>setEmpForm(f=>({...f,estatus:e.target.value}))}><option value="tiene_trabajo">Tiene trabajo</option><option value="lleno">Se encuentra lleno</option></select></div>
      <div><div style={label}>Alcance</div><select style={input} value={empForm.alcance} onChange={e=>setEmpForm(f=>({...f,alcance:e.target.value}))}>{POSTURAS_ALCANCE.map(x=><option key={x}>{x}</option>)}</select></div>
    </div>
    <div style={{ display:"flex", gap:"8px", marginTop:"14px", flexWrap:"wrap" }}><button onClick={saveEmp} style={btn("#22c55e")}>{editingEmpId?"Actualizar empresa":"Guardar empresa"}</button>{editingEmpId && <button onClick={()=>{setEditingEmpId(null); setEmpForm(emptyEmp);}} style={btn("#94a3b8")}>Cancelar edición</button>}</div>
  </div>;

  const savePisHistory = (entry) => {
    const next = [entry, ...pisHistory].slice(0, 12);
    setPisHistory(next);
    try { localStorage.setItem("cm_pis_verificaciones", JSON.stringify(next)); } catch {}
  };

  const verifyPisDocument = async () => {
    const id = String(pisForm.id || "").trim();
    if (!pisForm.asipona || !pisForm.tipo || !id) {
      setPisResult({ ok:false, status:"incompleto", message:"Selecciona ASIPONA, tipo de documento y escribe el ID." });
      return;
    }
    if (!/^\d+$/.test(id)) {
      setPisResult({ ok:false, status:"id_invalido", message:"El ID debe ser numérico." });
      return;
    }

    setPisLoading(true);
    setPisResult(null);

    const payload = {
      asipona: String(pisForm.asipona || "").trim().toUpperCase(),
      tipo: String(pisForm.tipo || "").trim().toUpperCase(),
      id,
    };

    const pickMessage = (result) => String(
      result?.mensaje ?? result?.message ?? result?.resultado ?? result?.result ?? result?.error_description ?? ""
    ).trim();

    try {
      const { data, error } = await sb.functions.invoke(PIS_EDGE_FUNCTION, { body: payload });
      if (error) throw error;

      const result = data || {};
      const message = pickMessage(result);
      const looksLikeTemplate = /hello\s+undefined/i.test(message) || (message === "Hello undefined!");

      if (looksLikeTemplate) {
        const fallback = {
          ok:false,
          valid:false,
          status:"backend_template",
          message:"La función smooth-service todavía tiene el código de ejemplo de Supabase. Debes reemplazar el index.ts de esa función con el código de consulta PIS/SEMAR.",
          detail:message,
          raw:result,
          query:payload,
          checked_at:new Date().toISOString(),
        };
        setPisResult(fallback);
        setPisContactMessage(`Hola, solicito información específica sobre boletinaje. Consulta realizada: ${payload.asipona} · ${payload.tipo}-${payload.id}. No fue posible validar desde Conect Manzanillo.`);
        return;
      }

      const valid = result?.valido === true || result?.valor === true || result?.valid === true || /(?:^|\s)(válido|valido)\.?$/i.test(message);
      const normalized = {
        ok: result?.ok !== false,
        valid,
        status: valid ? "valido" : "no_valido",
        message: message || (valid ? `${payload.tipo} válido.` : "Documento no válido o no encontrado."),
        raw: result,
        query: payload,
        checked_at: new Date().toISOString(),
      };

      setPisContactUnlocked(false);
      setPisUnlockRequested(false);
      setPisUnlockSeconds(0);
      setPisResult(normalized);
      setPisContactMessage(`Hola, solicito información específica sobre boletinaje. Consulta realizada en PIS/SEMAR: ${payload.asipona} · ${payload.tipo}-${payload.id}. Resultado mostrado: ${normalized.message}`);
      savePisHistory(normalized);
      auditLog({ action:"pis_verificacion_documento", section:"posturas_boletinados", entityId:`${payload.asipona}-${payload.tipo}-${payload.id}`, after:{ summary:`Consulta PIS ${payload.asipona} ${payload.tipo} ${payload.id}`, valid:normalized.valid, message:normalized.message }, actor:authUser?.email || myId || "Usuario" });
    } catch (e) {
      const fallback = {
        ok:false,
        valid:false,
        status:"backend_no_configurado",
        message:"No se pudo consultar PIS/SEMAR desde la app. Revisa que la Edge Function smooth-service esté desplegada, pública y con el código correcto.",
        detail:e?.message || String(e),
        query:payload,
        checked_at:new Date().toISOString(),
      };
      setPisContactUnlocked(false);
      setPisUnlockRequested(false);
      setPisUnlockSeconds(0);
      setPisResult(fallback);
      setPisContactMessage(`Hola, solicito información específica sobre boletinaje. Consulta realizada: ${payload.asipona} · ${payload.tipo}-${payload.id}. No fue posible validar desde Conect Manzanillo.`);
    } finally {
      setPisLoading(false);
    }
  };

  const copyPisText = async (value, field) => {
    const text = String(value || "").trim();
    if (!text) return;
    try {
      await navigator.clipboard.writeText(text);
    } catch {
      const temp = document.createElement("textarea");
      temp.value = text;
      temp.setAttribute("readonly", "");
      temp.style.position = "fixed";
      temp.style.left = "-9999px";
      document.body.appendChild(temp);
      temp.select();
      try { document.execCommand("copy"); } catch {}
      temp.remove();
    }
    setPisCopiedField(field);
    if (field === "email") setPisEmailCopied(true);
    setTimeout(() => {
      setPisCopiedField("");
      if (field === "email") setPisEmailCopied(false);
    }, 1800);
  };

  const copyPisEmail = () => copyPisText(PIS_ASIPONA_EMAIL, "email");

  const BoletinadosTab = () => (
    <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fit, minmax(min(100%, 360px), 1fr))", gap:"14px", alignItems:"start", width:"100%", maxWidth:"100%", overflow:"hidden" }}>
      <div style={{ ...card, minWidth:0, width:"100%", boxSizing:"border-box", overflow:"hidden" }}>
        <div style={{ display:"flex", alignItems:"flex-start", gap:"10px", marginBottom:"10px", minWidth:0, flexWrap:"wrap" }}>
          <div style={{ width:"38px", height:"38px", borderRadius:"12px", background:"rgba(56,189,248,.14)", border:"1px solid rgba(56,189,248,.35)", display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0 }}><AppIcon name="document-check" size={18} active /></div>
          <div style={{ minWidth:0, flex:"1 1 220px" }}>
            <div style={{ fontFamily:getFont(theme,"title"), fontSize:"clamp(17px, 5vw, 22px)", lineHeight:1.12, color:"#fff", fontWeight:"900", overflowWrap:"anywhere" }}>Boletinados · Verificación PIS</div>
            <div style={{ fontFamily:getFont(theme,"secondary"), fontSize:"clamp(11px, 3.4vw, 13px)", color:"rgba(255,255,255,.62)", lineHeight:1.45, overflowWrap:"break-word" }}>Consulta documentos electrónicos públicos del portal PIS/SEMAR desde Conect Manzanillo.</div>
          </div>
        </div>

        <div style={{ color:"rgba(255,255,255,.70)", fontFamily:getFont(theme,"secondary"), fontSize:"clamp(11px, 3.5vw, 13px)", lineHeight:1.55, marginBottom:"13px", maxWidth:"100%", overflowWrap:"break-word" }}>
          El proceso de consulta en esta sección se gestiona a través de la plataforma PIS/SEMAR. Cabe destacar que este procedimiento cumple con todas las normativas y no infringe ninguna política, lo cual puede comprobarse de manera transparente dentro del mismo sistema.
        </div>

        <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fit, minmax(min(100%, 210px), 1fr))", gap:"10px", marginBottom:"12px", minWidth:0 }}>
          <div><div style={label}>ASIPONA</div><select style={input} value={pisForm.asipona} onChange={e=>setPisForm(f=>({...f, asipona:e.target.value}))}>{PIS_ASIPONAS.map(x=><option key={x} value={x}>{x}</option>)}</select></div>
          <div><div style={label}>Tipo</div><select style={input} value={pisForm.tipo} onChange={e=>setPisForm(f=>({...f, tipo:e.target.value}))}>{PIS_DOC_TYPES.map(x=><option key={x} value={x}>{x}</option>)}</select></div>
          <div><div style={label}>ID</div><input style={input} inputMode="numeric" placeholder="Ej. 2" value={pisForm.id} onChange={e=>setPisForm(f=>({...f, id:e.target.value.replace(/[^0-9]/g, "")}))} onKeyDown={e=>{ if(e.key === "Enter") verifyPisDocument(); }} /></div>
        </div>

        <div style={{ display:"flex", gap:"8px", flexWrap:"wrap", alignItems:"center", minWidth:0 }}>
          <button onClick={verifyPisDocument} disabled={pisLoading} style={{ ...btn("#22c55e"), opacity:pisLoading?.75:1, minWidth:"min(100%, 180px)", flex:"1 1 180px" }}>{pisLoading ? "Consultando…" : "Verificar documento"}</button>
          <button onClick={()=>{ setPisForm({ asipona:"MANZANILLO", tipo:"DEA", id:"" }); setPisResult(null); setPisContactMessage(""); setPisEmailCopied(false); setPisCopiedField(""); setPisContactUnlocked(false); setPisUnlockRequested(false); setPisUnlockSeconds(0); }} style={{ ...btn("#94a3b8"), flex:"1 1 110px" }}>Limpiar</button>
          <a href="https://pis.semar.gob.mx/#/login" target="_blank" rel="noopener noreferrer" style={{ ...btn("#38bdf8"), textDecoration:"none", display:"inline-flex", alignItems:"center", justifyContent:"center", flex:"1 1 150px" }}>Abrir PIS oficial</a>
        </div>

        {pisResult && (
          <div style={{ marginTop:"14px", borderRadius:"14px", padding:"clamp(12px, 4vw, 18px)", background:pisResult.ok ? (pisResult.valid ? "rgba(34,197,94,.12)" : "rgba(239,68,68,.12)") : "rgba(251,191,36,.10)", border:`1px solid ${pisResult.ok ? (pisResult.valid ? "rgba(34,197,94,.45)" : "rgba(239,68,68,.45)") : "rgba(251,191,36,.42)"}`, minWidth:0, overflow:"hidden", boxSizing:"border-box" }}>
            <div style={{ fontFamily:getFont(theme,"title"), fontSize:"clamp(23px, 8vw, 34px)", lineHeight:1.1, color:pisResult.ok ? (pisResult.valid ? "#22c55e" : "#ef4444") : "#fbbf24", fontWeight:"900", marginBottom:"8px", overflowWrap:"anywhere" }}>
              {pisResult.ok ? (pisResult.valid ? `${pisForm.tipo} válido.` : `${pisForm.tipo} no válido.`) : "Consulta pendiente"}
            </div>
            <div style={{ fontFamily:getFont(theme,"secondary"), fontSize:"clamp(12px, 3.5vw, 14px)", color:"rgba(255,255,255,.78)", lineHeight:1.55, overflowWrap:"break-word" }}>{pisResult.message}</div>
            {pisResult.detail && <div style={{ marginTop:"8px", fontFamily:getFont(theme,"secondary"), fontSize:"10px", color:"rgba(255,255,255,.42)", wordBreak:"break-word" }}>{pisResult.detail}</div>}
            <div style={{ marginTop:"14px", paddingTop:"12px", borderTop:"1px solid rgba(255,255,255,.12)" }}>
              <div style={{ fontFamily:getFont(theme,"secondary"), fontSize:"clamp(11px, 3.4vw, 13px)", color:"rgba(255,255,255,.76)", lineHeight:1.55, marginBottom:"10px", overflowWrap:"break-word" }}>
                Si requieres información más específica del boletinaje, como el teléfono y correo de Boletinados, primero debes seguir el canal oficial de WhatsApp de Conect Manzanillo. Presiona aceptar para abrir el canal, síguelo y regresa a esta pantalla para continuar.
              </div>

              {!pisUnlockRequested && !pisContactUnlocked && (
                <div style={{ display:"flex", gap:"8px", flexWrap:"wrap", alignItems:"center", marginBottom:"10px" }}>
                  <a
                    href={PIS_WHATSAPP_CHANNEL_URL}
                    target="_blank"
                    rel="noopener noreferrer"
                    onClick={() => { setPisUnlockRequested(true); setPisContactUnlocked(false); setPisUnlockSeconds(30); }}
                    style={{ ...btn("#25D366"), textDecoration:"none", display:"inline-flex", alignItems:"center", gap:"6px" }}
                  >
                    <AppIcon name="whatsapp" size={14} active /> Aceptar y seguir canal
                  </a>
                </div>
              )}

              {pisUnlockRequested && !pisContactUnlocked && (
                <div style={{ border:"1px dashed rgba(251,191,36,.36)", background:"rgba(251,191,36,.08)", borderRadius:"12px", padding:"10px 12px", fontFamily:getFont(theme,"secondary"), fontSize:"10px", color:"rgba(255,255,255,.70)", lineHeight:1.55, marginBottom:"10px" }}>
                  Verificando acceso al canal. Entra al canal, presiona seguir y regresa a esta pantalla para habilitar los datos de contacto.
                </div>
              )}

              {pisContactUnlocked && (
                <>
                  <div style={{ fontFamily:getFont(theme,"secondary"), fontSize:"11px", color:"rgba(255,255,255,.76)", lineHeight:1.6, marginBottom:"8px" }}>
                    Datos de contacto para información específica de boletinaje:
                  </div>
                  <div style={{ border:"1px solid rgba(56,189,248,.28)", background:"rgba(56,189,248,.08)", borderRadius:"12px", padding:"10px", marginBottom:"10px", fontFamily:getFont(theme,"secondary"), color:"rgba(255,255,255,.82)", display:"grid", gap:"8px" }}>
                    {[
                      { label:"Teléfono principal", value:PIS_ASIPONA_MAIN_PHONE, field:"mainPhone", copied:"Teléfono copiado" },
                      { label:"Extensión", value:PIS_ASIPONA_EXTENSION, field:"extension", copied:"Extensión copiada" },
                      { label:"Correo electrónico", value:PIS_ASIPONA_EMAIL, field:"email", copied:"Correo copiado" },
                    ].map(row => (
                      <div key={row.field} style={{ display:"grid", gridTemplateColumns:"minmax(120px, 1fr) minmax(0, 1.25fr) auto", alignItems:"center", gap:"8px", padding:"8px 9px", borderRadius:"10px", background:"rgba(2,6,23,.25)", border:"1px solid rgba(255,255,255,.08)", minWidth:0 }}>
                        <div style={{ fontSize:"11px", color:"rgba(255,255,255,.62)", fontWeight:"800" }}>{row.label}</div>
                        <button onClick={() => copyPisText(row.value, row.field)} style={{ minWidth:0, textAlign:"left", overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap", background:"transparent", border:"none", color:pisCopiedField === row.field ? "#22c55e" : "#ffffff", fontWeight:"900", cursor:"pointer", padding:0, fontFamily:"inherit", fontSize:"12px" }} title="Copiar">
                          {pisCopiedField === row.field ? row.copied : row.value}
                        </button>
                        <button onClick={() => copyPisText(row.value, row.field)} style={{ border:"1px solid rgba(56,189,248,.35)", background:pisCopiedField === row.field ? "rgba(34,197,94,.15)" : "rgba(56,189,248,.12)", color:pisCopiedField === row.field ? "#22c55e" : "#38bdf8", borderRadius:"999px", padding:"5px 9px", fontFamily:getFont(theme,"secondary"), fontSize:"9px", fontWeight:"900", cursor:"pointer", whiteSpace:"nowrap" }}>
                          {pisCopiedField === row.field ? "Copiado" : "Copiar"}
                        </button>
                      </div>
                    ))}
                    <div style={{ color:"rgba(255,255,255,.48)", fontSize:"10px", lineHeight:1.45 }}>Pulsa el dato o la pestaña de copiar para guardarlo en el portapapeles.</div>
                  </div>
                  <textarea
                    value={pisContactMessage}
                    onChange={e=>setPisContactMessage(e.target.value)}
                    placeholder="Escribe aquí tu consulta específica para ASIPONA..."
                    rows={3}
                    style={{ ...input, resize:"vertical", minHeight:"74px", marginBottom:"9px" }}
                  />
                  <div style={{ display:"flex", gap:"8px", flexWrap:"wrap" }}>
                    <a href={`${PIS_ASIPONA_WHATSAPP_URL}?text=${encodeURIComponent(pisContactMessage || `Hola, solicito información específica sobre boletinaje. Consulta: ${pisForm.asipona} · ${pisForm.tipo}-${pisForm.id}.`)}`} target="_blank" rel="noopener noreferrer" style={{ ...btn("#25D366"), textDecoration:"none", display:"inline-flex", alignItems:"center", gap:"6px" }}><AppIcon name="whatsapp" size={14} active /> WhatsApp ASIPONA</a>
                  </div>
                </>
              )}

              <div style={{ marginTop:"7px", fontFamily:getFont(theme,"secondary"), fontSize:"10px", color:"rgba(255,255,255,.42)" }}>
                Esta información de contacto se ocultará automáticamente 2 minutos después de la consulta.
              </div>
            </div>
          </div>
        )}
      </div>

      <div style={{ ...card, minWidth:0, width:"100%", boxSizing:"border-box", overflow:"hidden" }}>
        <div style={{ color:"#38bdf8", fontFamily:getFont(theme,"secondary"), fontWeight:"900", fontSize:"clamp(11px, 3.4vw, 12px)", letterSpacing:"1px", marginBottom:"10px", overflowWrap:"break-word" }}>ÚLTIMAS CONSULTAS EN ESTE DISPOSITIVO</div>
        {pisHistory.length === 0 ? <div style={{ color:"rgba(255,255,255,.45)", fontFamily:getFont(theme,"secondary"), fontSize:"11px", lineHeight:1.6 }}>Aún no hay consultas guardadas localmente.</div> : pisHistory.map((h, idx) => (
          <div key={idx} style={{ padding:"10px 0", borderTop:idx ? "1px solid rgba(255,255,255,.08)" : "none" }}>
            <div style={{ display:"flex", justifyContent:"space-between", gap:"8px", alignItems:"center" }}>
              <div style={{ color:"#fff", fontFamily:getFont(theme,"secondary"), fontSize:"12px", fontWeight:"900" }}>{h.query?.asipona || "ASIPONA"} · {h.query?.tipo || "DOC"}-{h.query?.id || "ID"}</div>
              <span style={{ color:h.valid ? "#22c55e" : "#ef4444", border:`1px solid ${h.valid ? "#22c55e55" : "#ef444455"}`, borderRadius:"999px", padding:"3px 7px", fontFamily:getFont(theme,"secondary"), fontSize:"9px", fontWeight:"900" }}>{h.valid ? "VÁLIDO" : "NO VÁLIDO"}</span>
            </div>
            <div style={{ marginTop:"4px", color:"rgba(255,255,255,.45)", fontFamily:getFont(theme,"secondary"), fontSize:"10px" }}>{h.checked_at ? new Date(h.checked_at).toLocaleString("es-MX") : ""}</div>
          </div>
        ))}
        {pisHistory.length > 0 && <button onClick={()=>{ setPisHistory([]); try{localStorage.removeItem("cm_pis_verificaciones");}catch{} }} style={{...btn("#ef4444"), marginTop:"12px"}}>Borrar historial local</button>}
      </div>
    </div>
  );

  const AdminQuejas = () => isAdmin ? <div style={{...card, marginTop:"14px"}}><div style={{ color:"#fff", fontWeight:"900", marginBottom:"8px" }}>Quejas pendientes de aprobación</div>{quejas.filter(x=>!x.aprobado).length===0 ? <div style={{color:"rgba(255,255,255,.45)", fontSize:"11px"}}>Sin quejas pendientes.</div> : quejas.filter(x=>!x.aprobado).map(x => <div key={x.id} style={{borderTop:"1px solid rgba(255,255,255,.1)", padding:"9px 0", color:"rgba(255,255,255,.7)", fontSize:"11px"}}>{x.comentario}<div style={{marginTop:"6px", display:"flex", gap:"6px"}}><button onClick={()=>approveQueja(x.id,true)} style={btn("#22c55e")}>Aprobar</button><button onClick={()=>approveQueja(x.id,false)} style={btn("#ef4444")}>Rechazar</button></div></div>)}</div> : null;

  return <div style={{ padding:"20px 24px", paddingBottom:"90px", maxWidth:"1120px", margin:"0 auto" }}>
    <ProfileHeader />
    {msg && <div style={{ marginBottom:"12px", padding:"11px 13px", borderRadius:"10px", background:msg.type==="ok"?"#22c55e16":"#ef444416", border:`1px solid ${msg.type==="ok"?"#22c55e55":"#ef444455"}`, color:msg.type==="ok"?"#22c55e":"#ef4444", fontFamily:getFont(theme,"secondary"), fontSize:"12px", fontWeight:"800" }}>{msg.text}</div>}
    {showReminder && <div style={{ marginBottom:"12px", padding:"13px", borderRadius:"12px", background:"#fbbf2417", border:"1px solid #fbbf2455", color:"#fbbf24", fontFamily:getFont(theme,"secondary"), fontSize:"12px", fontWeight:"800" }}>⏰ Han pasado cerca de 3 meses desde tu última actualización. Revisa tu perfil y guarda cambios para mantenerlo vigente.</div>}
    <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fit, minmax(min(100%, 170px),1fr))", gap:"8px", marginBottom:"12px", minWidth:0 }}>{[{id:"donativos", label:"Donativos", icon:"support-heart"},{id:"posturas", label:"Posturas Conect", icon:"logistics-handshake"},{id:"boletinados", label:"Boletinados", icon:"document-check"}].map(t=><button key={t.id} onClick={()=>setSub(t.id)} style={{ padding:"12px", borderRadius:"12px", border:`1px solid ${sub===t.id?"#38bdf8":"rgba(255,255,255,.12)"}`, background:sub===t.id?"rgba(56,189,248,.16)":"rgba(255,255,255,.04)", color:sub===t.id?"#38bdf8":"rgba(255,255,255,.56)", fontFamily:getFont(theme,"secondary"), fontWeight:"900", cursor:"pointer" }}><AppIcon name={t.icon} size={14} active={sub===t.id} /> {t.label}</button>)}</div>
    {sub === "donativos" && <DonativosTab embedded />}
    {sub === "boletinados" && <BoletinadosTab />}
    {sub === "posturas" && <>
      <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:"8px", marginBottom:"12px" }}>{[{id:"postular", label:"Postular", icon:"freight-truck"},{id:"empresario", label:"Empresario", icon:"office"}].map(t=><button key={t.id} onClick={()=>setVista(t.id)} style={{ padding:"11px", borderRadius:"11px", border:`1px solid ${vista===t.id?"#a78bfa":"rgba(255,255,255,.12)"}`, background:vista===t.id?"rgba(167,139,250,.16)":"rgba(255,255,255,.04)", color:vista===t.id?"#a78bfa":"rgba(255,255,255,.56)", fontFamily:getFont(theme,"secondary"), fontWeight:"900", cursor:"pointer" }}><AppIcon name={t.icon} size={14} active={vista===t.id} /> {t.label}</button>)}</div>
      {vista === "postular" ? <WorkerForm /> : <CompanyForm />}
      <Filters />
      {loading && <div style={{color:"#94a3b8", textAlign:"center", padding:"20px"}}>Cargando perfiles…</div>}
      {vista === "postular" && <><div style={{ color:"#38bdf8", fontWeight:"900", margin:"12px 0", fontFamily:getFont(theme,"secondary") }}>Trabajadores ({trabFiltrados.length})</div><div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fit,minmax(280px,1fr))", gap:"12px" }}>{paginate(trabFiltrados, pageTrab).map(row => <TrabCard key={row.id} row={row}/>)}</div><Pagination total={trabFiltrados.length} page={pageTrab} setPage={setPageTrab} pageSize={PAGE_SIZE} /></>}
      {vista === "empresario" && <><div style={{ color:"#38bdf8", fontWeight:"900", margin:"12px 0", fontFamily:getFont(theme,"secondary") }}>Empresas ({empFiltradas.length})</div><div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fit,minmax(280px,1fr))", gap:"12px" }}>{paginate(empFiltradas, pageEmp).map(row => <EmpresaCard key={row.id} row={row}/>)}</div><Pagination total={empFiltradas.length} page={pageEmp} setPage={setPageEmp} pageSize={PAGE_SIZE} /><AdminQuejas /></>}
    </>}
  </div>;
}

function Pagination({ total, page, setPage, pageSize }) {
  const pages = Math.max(1, Math.ceil(total / pageSize));
  if (pages <= 1) return null;
  return <div style={{ display:"flex", justifyContent:"center", gap:"8px", marginTop:"14px" }}><button onClick={()=>setPage(Math.max(1,page-1))} disabled={page<=1} style={{padding:"8px 11px", borderRadius:"9px", border:"1px solid rgba(255,255,255,.15)", background:"rgba(255,255,255,.05)", color:"#fff"}}>←</button><span style={{ color:"rgba(255,255,255,.55)", fontSize:"12px", padding:"8px" }}>Hoja {page} de {pages}</span><button onClick={()=>setPage(Math.min(pages,page+1))} disabled={page>=pages} style={{padding:"8px 11px", borderRadius:"9px", border:"1px solid rgba(255,255,255,.15)", background:"rgba(255,255,255,.05)", color:"#fff"}}>→</button></div>;
}

