const PATIO_DRAW_LOCAL_KEY = "cm_patio_identifica_features";
const PATIO_DRAW_TABLE = "patio_identificados";
const PATIO_POLYGON_COLORS = [
  "#00e5ff", "#22c55e", "#fbbf24", "#fb923c",
  "#ef4444", "#a855f7", "#38bdf8", "#ffffff"
];
const DEFAULT_KML_POLYGON_COLOR = "#00e5ff";
const DEFAULT_USER_POLYGON_COLOR = "#fb923c";

const makePatioFeatureId = () => `patio_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;

const normalizePatioFeatureName = (name) => sanitize(String(name || "").trim()).replace(/&#x2F;/g, "/").slice(0, 80);

const getPatioFeatureCenter = (feature) => {
  if (!feature) return [19.0788, -104.2848];
  if (feature.type === "marker" && Array.isArray(feature.coords)) return feature.coords;
  const coords = Array.isArray(feature.coords) ? feature.coords : [];
  if (!coords.length) return [19.0788, -104.2848];
  const sum = coords.reduce((acc, c) => [acc[0] + Number(c[0] || 0), acc[1] + Number(c[1] || 0)], [0, 0]);
  return [sum[0] / coords.length, sum[1] / coords.length];
};

// Evita que los usuarios apilen patios encima de patios existentes.
// Trabajamos en coordenadas Leaflet [lat, lng].
const patioOrientation = (a, b, c) => {
  const v = (b[1] - a[1]) * (c[0] - b[0]) - (b[0] - a[0]) * (c[1] - b[1]);
  if (Math.abs(v) < 1e-12) return 0;
  return v > 0 ? 1 : 2;
};

const patioOnSegment = (a, b, c) =>
  Math.min(a[0], c[0]) <= b[0] + 1e-12 && b[0] <= Math.max(a[0], c[0]) + 1e-12 &&
  Math.min(a[1], c[1]) <= b[1] + 1e-12 && b[1] <= Math.max(a[1], c[1]) + 1e-12;

const patioSegmentsIntersect = (p1, q1, p2, q2) => {
  const o1 = patioOrientation(p1, q1, p2);
  const o2 = patioOrientation(p1, q1, q2);
  const o3 = patioOrientation(p2, q2, p1);
  const o4 = patioOrientation(p2, q2, q1);
  if (o1 !== o2 && o3 !== o4) return true;
  if (o1 === 0 && patioOnSegment(p1, p2, q1)) return true;
  if (o2 === 0 && patioOnSegment(p1, q2, q1)) return true;
  if (o3 === 0 && patioOnSegment(p2, p1, q2)) return true;
  if (o4 === 0 && patioOnSegment(p2, q1, q2)) return true;
  return false;
};

const patioPointInPolygon = (point, polygon) => {
  const x = point[0], y = point[1];
  let inside = false;
  for (let i = 0, j = polygon.length - 1; i < polygon.length; j = i++) {
    const xi = polygon[i][0], yi = polygon[i][1];
    const xj = polygon[j][0], yj = polygon[j][1];
    const intersect = ((yi > y) !== (yj > y)) &&
      (x < (xj - xi) * (y - yi) / ((yj - yi) || 1e-12) + xi);
    if (intersect) inside = !inside;
  }
  return inside;
};

const patioPolygonBounds = (coords) => coords.reduce((b, c) => ({
  minLat: Math.min(b.minLat, c[0]), maxLat: Math.max(b.maxLat, c[0]),
  minLng: Math.min(b.minLng, c[1]), maxLng: Math.max(b.maxLng, c[1]),
}), { minLat: Infinity, maxLat: -Infinity, minLng: Infinity, maxLng: -Infinity });

const patioBoundsOverlap = (a, b) => !(a.maxLat < b.minLat || a.minLat > b.maxLat || a.maxLng < b.minLng || a.minLng > b.maxLng);

const patioPolygonsOverlap = (polyA = [], polyB = []) => {
  if (!Array.isArray(polyA) || !Array.isArray(polyB) || polyA.length < 3 || polyB.length < 3) return false;
  if (!patioBoundsOverlap(patioPolygonBounds(polyA), patioPolygonBounds(polyB))) return false;
  for (let i = 0; i < polyA.length; i++) {
    const a1 = polyA[i], a2 = polyA[(i + 1) % polyA.length];
    for (let j = 0; j < polyB.length; j++) {
      const b1 = polyB[j], b2 = polyB[(j + 1) % polyB.length];
      if (patioSegmentsIntersect(a1, a2, b1, b2)) return true;
    }
  }
  return patioPointInPolygon(polyA[0], polyB) || patioPointInPolygon(polyB[0], polyA);
};

const patioOverlapsExisting = (candidate, existingFeatures = []) => {
  if (!candidate || candidate.type !== "polygon") return null;
  const hit = (existingFeatures || []).find(f =>
    f && f.type === "polygon" && f.id !== candidate.id && patioPolygonsOverlap(candidate.coords, f.coords)
  );
  return hit || null;
};

function PatioIdentificaMap({ myId }) {
  const theme = React.useContext(ThemeContext);
  const L = useLeaflet();
  const mapRef = useRef(null);
  const mapInstanceRef = useRef(null);
  const drawnGroupRef = useRef(null);
  const baseTileRef = useRef(null);
  const labelTileRef = useRef(null);
  const layerByIdRef = useRef({});
  const initialFitDoneRef = useRef(false);
  const [drawReady, setDrawReady] = useState(false);
  const [tileMode, setTileMode] = useState("satellite_labels");
  const [features, setFeatures] = useState(PATIOS_KML_REFERENCIA);
  const [selectedId, setSelectedId] = useState(null);
  const [query, setQuery] = useState("");
  const [msg, setMsg] = useState(null);
  const suppressRemoteSyncRef = useRef(false);
  const dbReadyRef = useRef(false);

  const TILE_OPTIONS = [
    {
      id: "satellite_labels",
      label: "Satélite + calles",
      icon: "satellite",
      url: "https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}",
      subdomains: "",
      labelsUrl: "https://services.arcgisonline.com/ArcGIS/rest/services/Reference/World_Boundaries_and_Places/MapServer/tile/{z}/{y}/{x}",
      labelsSubdomains: "",
    },
    {
      id: "satellite",
      label: "Satélite",
      icon: "world",
      url: "https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}",
      subdomains: "",
    },
    { id: "streets", label: "Calles", icon: "map", url: "https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png", subdomains: "abc" },
    { id: "light", label: "Claro", icon: "sun", url: "https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png", subdomains: "abcd" },
    { id: "dark", label: "Oscuro", icon: "moon", url: "https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png", subdomains: "abcd" },
  ];

  const notify = (text, color = "#38bdf8") => {
    setMsg({ text, color });
    setTimeout(() => setMsg(null), 3200);
  };

  const featuresRef = useRef(features);
  useEffect(() => { featuresRef.current = features; }, [features]);

  const isValidFeature = (f) => {
    if (!f || !f.id || !f.name || !f.type) return false;
    if (f.type === "marker") return Array.isArray(f.coords) && f.coords.length === 2 && !isNaN(f.coords[0]) && !isNaN(f.coords[1]);
    return Array.isArray(f.coords) && f.coords.length >= 3;
  };

  const mergeWithKmlReference = (saved = []) => {
    const map = new Map(PATIOS_KML_REFERENCIA.filter(isValidFeature).map(f => [f.id, { ...f, source: "kml", color: f.color || DEFAULT_KML_POLYGON_COLOR }]));
    (Array.isArray(saved) ? saved : []).filter(isValidFeature).forEach(f => map.set(f.id, f));
    return Array.from(map.values());
  };

  const saveLocal = (next) => {
    try { localStorage.setItem(PATIO_DRAW_LOCAL_KEY, JSON.stringify(next.filter(isValidFeature))); } catch {}
  };

  const patioFeatureToDbRow = (feature) => ({
    id: String(feature.id),
    nombre: feature.name,
    color: feature.color || (feature.source === "kml" ? DEFAULT_KML_POLYGON_COLOR : DEFAULT_USER_POLYGON_COLOR),
    tipo: feature.type || "polygon",
    geojson: { type: feature.type || "polygon", coords: feature.coords || [] },
    // Los patios base KML sí pueden guardar color global, pero siguen protegidos contra borrado/renombrado.
    is_base_kml: feature.source === "kml",
    created_by: myId || "anon",
    updated_at: new Date().toISOString(),
  });

  const patioDbRowToFeature = (row) => {
    const geo = row?.geojson || {};
    return {
      id: String(row.id),
      name: normalizePatioFeatureName(row.nombre),
      type: row.tipo || geo.type || "polygon",
      coords: Array.isArray(geo.coords) ? geo.coords : [],
      source: row.is_base_kml ? "kml" : "usuario",
      color: row.color || DEFAULT_USER_POLYGON_COLOR,
    };
  };

  const [dbStatus, setDbStatus] = useState({ ok: false, text: "Conectando con Supabase…" });

  const upsertRemoteFeature = async (feature) => {
    if (!feature || !isValidFeature(feature)) return { ok: true };
    const row = patioFeatureToDbRow(feature);
    const { error } = await sb
      .from("patios_mapa")
      .upsert(row, { onConflict: "id" })
      .select("id")
      .single();

    if (error) {
      console.error("No se pudo guardar patio global:", error);
      setDbStatus({ ok: false, text: `Supabase error: ${error.message || error.code || "no guardó"}` });
      notify(`No se guardó globalmente: ${error.message || "revisa permisos de patios_mapa"}`, "#ef4444");
      return { ok: false, error };
    }

    setDbStatus({ ok: true, text: "Supabase conectado · guardado global activo" });
    return { ok: true };
  };

  const deleteRemoteFeature = async (id) => {
    if (!id) return { ok: true };
    const { error } = await sb
      .from("patios_mapa")
      .delete()
      .eq("id", id)
      .eq("is_base_kml", false);

    if (error) {
      console.error("No se pudo eliminar patio global:", error);
      setDbStatus({ ok: false, text: `Supabase error: ${error.message || error.code || "no eliminó"}` });
      notify(`No se eliminó globalmente: ${error.message || "revisa permisos"}`, "#ef4444");
      return { ok: false, error };
    }

    setDbStatus({ ok: true, text: "Supabase conectado · guardado global activo" });
    return { ok: true };
  };

  const persistFeatures = (next) => {
    const clean = mergeWithKmlReference(next);
    setFeatures(clean);
    saveLocal(clean);
  };

  const fetchGlobalPatios = useCallback(async (silent = false) => {
    const { data, error } = await sb
      .from("patios_mapa")
      .select("*")
      .order("updated_at", { ascending: true });

    if (error) {
      console.error("No se pudo leer patios_mapa:", error);
      setDbStatus({ ok: false, text: `Sin sincronización: ${error.message || error.code || "error Supabase"}` });
      if (!silent) notify(`No se pudo sincronizar Supabase: ${error.message || "revisa patios_mapa"}`, "#ef4444");
      return false;
    }

    dbReadyRef.current = true;
    setDbStatus({ ok: true, text: `Supabase conectado · ${(data || []).length} patio(s) global(es)` });
    const remoteFeatures = (data || []).map(patioDbRowToFeature).filter(isValidFeature);
    const merged = mergeWithKmlReference(remoteFeatures);
    setFeatures(merged);
    saveLocal(merged);
    return true;
  }, []);

  useEffect(() => {
    let alive = true;

    fetchGlobalPatios(true);

    // Respaldo de sincronización: si Realtime no está habilitado en Supabase,
    // todos los usuarios se actualizan por polling cada pocos segundos.
    const syncTimer = setInterval(async () => {
      if (!alive) return;
      await fetchGlobalPatios(true);
    }, 3000);

    const channel = sb.channel("patios-mapa-global")
      .on("postgres_changes", { event: "*", schema: "public", table: "patios_mapa" }, (payload) => {
        if (!payload) return;
        suppressRemoteSyncRef.current = true;
        setFeatures(prev => {
          const without = prev.filter(f => f.source === "kml" || f.id !== String(payload.old?.id || payload.new?.id));
          if (payload.eventType === "DELETE") return mergeWithKmlReference(without);
          const incoming = patioDbRowToFeature(payload.new);
          return mergeWithKmlReference([...without, incoming]);
        });
        setTimeout(() => { suppressRemoteSyncRef.current = false; }, 250);
      })
      .subscribe();

    return () => {
      alive = false;
      clearInterval(syncTimer);
      sb.removeChannel(channel);
    };
  }, [myId]);

  useEffect(() => {
    if (!L || drawReady || window.L?.Control?.Draw) {
      if (window.L?.Control?.Draw) setDrawReady(true);
      return;
    }
    const existingCss = document.querySelector('link[data-leaflet-draw="true"]');
    if (!existingCss) {
      const css = document.createElement("link");
      css.rel = "stylesheet";
      css.href = "https://cdnjs.cloudflare.com/ajax/libs/leaflet.draw/1.0.4/leaflet.draw.css";
      css.dataset.leafletDraw = "true";
      document.head.appendChild(css);
    }
    const existingScript = document.querySelector('script[data-leaflet-draw="true"]');
    if (existingScript) {
      existingScript.addEventListener("load", () => setDrawReady(true), { once: true });
      return;
    }
    const script = document.createElement("script");
    script.src = "https://cdnjs.cloudflare.com/ajax/libs/leaflet.draw/1.0.4/leaflet.draw.js";
    script.dataset.leafletDraw = "true";
    script.onload = () => setDrawReady(true);
    document.head.appendChild(script);
  }, [L, drawReady]);

  const layerToFeature = (layer, fallback = {}) => {
    const id = layer.options?.featureId || fallback.id || makePatioFeatureId();
    const name = normalizePatioFeatureName(layer.options?.featureName || fallback.name || "");
    if (layer instanceof L.Marker) {
      const ll = layer.getLatLng();
      return { id, name, type: "marker", coords: [ll.lat, ll.lng], source: fallback.source || "usuario" };
    }
    const latLngs = layer.getLatLngs?.();
    const ring = Array.isArray(latLngs?.[0]) ? latLngs[0] : latLngs;
    const coords = (ring || []).map(ll => [ll.lat, ll.lng]).filter(c => !isNaN(c[0]) && !isNaN(c[1]));
    return { id, name, type: "polygon", coords, source: fallback.source || "usuario", color: layer.options?.featureColor || fallback.color || DEFAULT_USER_POLYGON_COLOR };
  };

  const featureStyle = (feature) => {
    const selected = selectedId === feature.id;
    const isKml = feature.source === "kml";
    const baseColor = feature.color || (isKml ? DEFAULT_KML_POLYGON_COLOR : DEFAULT_USER_POLYGON_COLOR);
    return {
      pane: "patioPane",
      color: selected ? "#fbbf24" : baseColor,
      fillColor: baseColor,
      fillOpacity: selected ? 0.62 : (isKml ? 0.38 : 0.36),
      opacity: 1,
      weight: selected ? 6 : 4,
      lineJoin: "round",
    };
  };

  const bindLayerMeta = (layer, feature) => {
    layer.options.featureId = feature.id;
    layer.options.featureName = feature.name;
    layer.options.featureSource = feature.source || "usuario";
    if (feature.type === "polygon") layer.options.featureColor = feature.color || (feature.source === "kml" ? DEFAULT_KML_POLYGON_COLOR : DEFAULT_USER_POLYGON_COLOR);
    const safeName = sanitize(feature.name);
    layer.bindTooltip(`<b>${safeName}</b>`, {
      permanent: feature.type === "polygon",
      direction: feature.type === "polygon" ? "center" : "top",
      sticky: feature.type !== "polygon",
      className: selectedId === feature.id ? "cm-tooltip patio-label patio-label-selected" : "cm-tooltip patio-label",
    });
    layer.on("click", () => setSelectedId(feature.id));
    return layer;
  };

  const rebuildLayers = useCallback(() => {
    const map = mapInstanceRef.current;
    const group = drawnGroupRef.current;
    if (!map || !L || !group) return;
    group.clearLayers();
    layerByIdRef.current = {};
    const all = [];

    features.filter(isValidFeature).forEach(feature => {
      let layer;
      if (feature.type === "marker") {
        const selected = selectedId === feature.id;
        layer = L.marker(feature.coords, {
          featureId: feature.id,
          featureName: feature.name,
          pane: "markerPane",
          icon: L.divIcon({
            className: "cm-patio-pin",
            html: `<div class="cm-patio-pin-dot ${selected ? "selected" : ""}">📍</div><div class="cm-patio-pin-label ${selected ? "selected" : ""}">${sanitize(feature.name)}</div>`,
            iconSize: [170, 44],
            iconAnchor: [16, 32],
          })
        });
        all.push(feature.coords);
      } else {
        layer = L.polygon(feature.coords, { ...featureStyle(feature), featureId: feature.id, featureName: feature.name, featureColor: feature.color || (feature.source === "kml" ? DEFAULT_KML_POLYGON_COLOR : DEFAULT_USER_POLYGON_COLOR) });
        (feature.coords || []).forEach(c => all.push(c));
      }
      bindLayerMeta(layer, feature).addTo(group);
      layerByIdRef.current[feature.id] = layer;
    });

    group.bringToFront();
    if (!initialFitDoneRef.current && all.length) {
      initialFitDoneRef.current = true;
      map.fitBounds(L.latLngBounds(all), { padding: [30, 30], maxZoom: 15 });
    }
  }, [L, features, selectedId]);

  const applyTileMode = useCallback((mode) => {
    const map = mapInstanceRef.current;
    if (!map || !L) return;
    const option = TILE_OPTIONS.find(t => t.id === mode) || TILE_OPTIONS[0];
    if (baseTileRef.current) map.removeLayer(baseTileRef.current);
    if (labelTileRef.current) {
      map.removeLayer(labelTileRef.current);
      labelTileRef.current = null;
    }
    baseTileRef.current = L.tileLayer(option.url, {
      maxZoom: 20,
      subdomains: option.subdomains || "abc",
    }).addTo(map);
    if (option.labelsUrl) {
      labelTileRef.current = L.tileLayer(option.labelsUrl, {
        maxZoom: 20,
        subdomains: option.labelsSubdomains || "abcd",
        pane: "labelPane",
      }).addTo(map);
    }
    drawnGroupRef.current?.bringToFront?.();
  }, [L]);

  useEffect(() => {
    if (!L || !drawReady || !mapRef.current || mapInstanceRef.current) return;
    const map = L.map(mapRef.current, {
      center: [19.0848, -104.2839],
      zoom: 14,
      zoomControl: true,
      attributionControl: false,
      scrollWheelZoom: true,
      dragging: true,
      touchZoom: true,
      doubleClickZoom: true,
    });

    if (!map.getPane("labelPane")) {
      map.createPane("labelPane");
      map.getPane("labelPane").style.zIndex = 420;
      map.getPane("labelPane").style.pointerEvents = "none";
    }
    if (!map.getPane("patioPane")) {
      map.createPane("patioPane");
      map.getPane("patioPane").style.zIndex = 470;
    }

    drawnGroupRef.current = L.featureGroup().addTo(map);
    mapInstanceRef.current = map;
    applyTileMode(tileMode);

    const drawControl = new L.Control.Draw({
      position: "topright",
      draw: {
        polyline: false,
        rectangle: false,
        circle: false,
        circlemarker: false,
        polygon: {
          allowIntersection: false,
          showArea: true,
          shapeOptions: { pane: "patioPane", color: DEFAULT_USER_POLYGON_COLOR, fillColor: DEFAULT_USER_POLYGON_COLOR, fillOpacity: 0.36, weight: 4 }
        },
        marker: true
      },
      edit: { featureGroup: drawnGroupRef.current, remove: true }
    });
    map.addControl(drawControl);

    map.on(L.Draw.Event.CREATED, async (e) => {
      let name = "";
      while (!name) {
        const input = window.prompt(e.layerType === "marker" ? "Nombre obligatorio para este pin o etiqueta:" : "Nombre obligatorio para este patio:");
        if (input === null) return;
        name = normalizePatioFeatureName(input);
        if (!name) window.alert("Debes escribir un nombre para guardar el elemento.");
      }
      const layer = e.layer;
      layer.options.featureId = makePatioFeatureId();
      layer.options.featureName = name;
      if (e.layerType !== "marker") layer.options.featureColor = DEFAULT_USER_POLYGON_COLOR;
      const nextFeature = layerToFeature(layer, { name, source: "usuario", color: DEFAULT_USER_POLYGON_COLOR });
      const overlap = patioOverlapsExisting(nextFeature, featuresRef.current);
      if (overlap) {
        window.alert(`No se puede guardar: este polígono se encima con "${overlap.name}". Dibuja el patio en una zona libre.`);
        notify(`No guardado: se encimaba con ${overlap.name}.`, "#ef4444");
        return;
      }

      notify("Guardando en Supabase…", "#38bdf8");
      const saved = await upsertRemoteFeature(nextFeature);
      if (!saved.ok) {
        window.alert("El trazo NO se guardó globalmente. Revisa que la tabla patios_mapa y sus policies existan en el mismo Supabase de esta app.");
        return;
      }

      await fetchGlobalPatios(true);
      setSelectedId(nextFeature.id);
      notify(`Guardado globalmente: ${name}`, "#22c55e");
    });

    map.on(L.Draw.Event.EDITED, async (e) => {
      const edited = {};
      let protectedKmlEdits = 0;
      e.layers.eachLayer(layer => {
        const old = featuresRef.current.find(f => f.id === layer.options.featureId);
        if (old?.source === "kml" || layer.options.featureSource === "kml") {
          protectedKmlEdits += 1;
          return;
        }
        const nextFeature = layerToFeature(layer, old);
        if (isValidFeature(nextFeature)) edited[nextFeature.id] = nextFeature;
      });
      if (protectedKmlEdits) {
        notify("Los patios base del KML están protegidos contra edición de forma. Solo puedes cambiarles color.", "#fbbf24");
        setTimeout(() => rebuildLayers(), 60);
      }
      if (!Object.keys(edited).length) return;
      const next = featuresRef.current.map(f => edited[f.id] || f);
      const overlapping = Object.values(edited).map(f => [f, patioOverlapsExisting(f, next)]).find(([f, hit]) => hit);
      if (overlapping) {
        const [changed, hit] = overlapping;
        notify(`Edición cancelada: ${changed.name} se encimaba con ${hit.name}.`, "#ef4444");
        setTimeout(() => rebuildLayers(), 60);
        return;
      }
      notify("Guardando cambios en Supabase…", "#38bdf8");
      const results = await Promise.all(Object.values(edited).map(f => upsertRemoteFeature(f)));
      if (results.some(r => !r?.ok)) {
        window.alert("La edición NO se guardó globalmente. Se restaurará el mapa para evitar diferencias entre usuarios.");
        await fetchGlobalPatios(true);
        setTimeout(() => rebuildLayers(), 80);
        return;
      }
      await fetchGlobalPatios(true);
      notify("Cambios guardados globalmente.", "#22c55e");
    });

    map.on(L.Draw.Event.DELETED, async (e) => {
      const deleted = new Set();
      let protectedCount = 0;
      e.layers.eachLayer(layer => {
        const id = layer.options.featureId;
        const feature = featuresRef.current.find(f => f.id === id);
        if (feature?.source === "kml" || layer.options.featureSource === "kml") {
          protectedCount += 1;
          return;
        }
        deleted.add(id);
      });
      if (deleted.size) {
        notify("Eliminando en Supabase…", "#38bdf8");
        const results = await Promise.all(Array.from(deleted).map(id => deleteRemoteFeature(id)));
        if (results.some(r => !r?.ok)) {
          window.alert("No se pudo eliminar globalmente. Se sincronizará otra vez desde Supabase.");
          await fetchGlobalPatios(true);
          return;
        }
      }
      await fetchGlobalPatios(true);
      if (deleted.has(selectedId)) setSelectedId(null);
      if (protectedCount && deleted.size) notify("Se eliminaron tus elementos. Los patios base del KML están protegidos.", "#fbbf24");
      else if (protectedCount) notify("Los patios base del KML están protegidos y no se pueden eliminar.", "#fbbf24");
      else notify("Elemento eliminado globalmente.", "#ef4444");
    });

    setTimeout(() => {
      map.invalidateSize();
      rebuildLayers();
    }, 180);

    return () => {
      map.remove();
      mapInstanceRef.current = null;
      drawnGroupRef.current = null;
      baseTileRef.current = null;
      labelTileRef.current = null;
      layerByIdRef.current = {};
    };
  }, [L, drawReady]);

  useEffect(() => { rebuildLayers(); }, [rebuildLayers]);
  useEffect(() => { applyTileMode(tileMode); }, [tileMode, applyTileMode]);

  const selectFeature = (id) => {
    const feature = features.find(f => f.id === id);
    const map = mapInstanceRef.current;
    const layer = layerByIdRef.current[id];
    if (!feature || !map || !layer) return;
    setSelectedId(id);
    setTimeout(() => {
      if (feature.type === "marker") {
        map.setView(getPatioFeatureCenter(feature), Math.max(map.getZoom(), 17), { animate: true });
      } else if (layer.getBounds) {
        map.fitBounds(layer.getBounds(), { padding: [42, 42], maxZoom: 18 });
        layer.setStyle?.(featureStyle({ ...feature, id }));
        layer.bringToFront?.();
      }
      layer.openTooltip?.();
    }, 90);
  };

  const renameSelected = async () => {
    const feature = features.find(f => f.id === selectedId);
    if (!feature) return notify("Selecciona primero un patio o pin.", "#f97316");
    if (feature.source === "kml") return notify("Los patios base del KML no se renombran; crea un patio nuevo si necesitas uno editable.", "#fbbf24");
    const input = window.prompt("Nuevo nombre obligatorio:", feature.name);
    const name = normalizePatioFeatureName(input);
    if (!name) return notify("No se cambió el nombre: el campo no puede quedar vacío.", "#ef4444");
    const updated = { ...feature, name, source: feature.source || "usuario" };
    const saved = await upsertRemoteFeature(updated);
    if (!saved.ok) return;
    await fetchGlobalPatios(true);
    notify("Nombre actualizado globalmente.", "#22c55e");
  };


  const changeSelectedColor = async (color) => {
    const feature = features.find(f => f.id === selectedId);
    if (!feature) return notify("Selecciona primero un patio.", "#f97316");
    if (feature.type !== "polygon") return notify("El color solo aplica para polígonos.", "#f97316");

    const updated = { ...feature, color, source: feature.source || "usuario" };

    // Actualización visual inmediata en este dispositivo.
    setFeatures(prev => prev.map(f => f.id === updated.id ? updated : f));
    const layer = layerByIdRef.current[updated.id];
    if (layer?.setStyle) {
      layer.options.featureColor = color;
      layer.setStyle(featureStyle(updated));
      layer.bringToFront?.();
    }

    const saved = await upsertRemoteFeature(updated);
    if (!saved.ok) {
      await fetchGlobalPatios(true);
      return;
    }
    await fetchGlobalPatios(true);
    notify(feature.source === "kml" ? "Color del patio base actualizado globalmente." : "Color actualizado globalmente.", color);
  };


  const focusAll = () => {
    const map = mapInstanceRef.current;
    const group = drawnGroupRef.current;
    if (!map || !group) return;
    const bounds = group.getBounds?.();
    if (bounds?.isValid?.()) map.fitBounds(bounds, { padding: [34, 34], maxZoom: 15 });
  };

  const filteredFeatures = features
    .filter(isValidFeature)
    .filter(f => (f.name || "").toLowerCase().includes(query.trim().toLowerCase()))
    .sort((a, b) => String(a.name).localeCompare(String(b.name), "es"));

  return (
    <div style={{ background:"linear-gradient(180deg,rgba(251,146,60,0.10),rgba(56,189,248,0.06))", border:"1px solid rgba(251,146,60,0.26)", borderRadius:"16px", padding:"14px", margin:"18px 0", overflow:"hidden" }}>
      <style>{`
        .cm-tooltip{background:rgba(4,12,24,0.96)!important;border:1px solid rgba(56,189,248,0.35)!important;border-radius:7px!important;color:rgba(255,255,255,0.92)!important;font-family:'DM Sans',sans-serif!important;font-size:12px!important;font-weight:800!important;padding:5px 9px!important;box-shadow:0 6px 20px rgba(0,0,0,.42)!important;white-space:nowrap!important;}
        .cm-tooltip::before{display:none!important;}
        .patio-label{background:rgba(0,0,0,.78)!important;border:1px solid rgba(0,229,255,.65)!important;color:#fff!important;border-radius:8px!important;padding:4px 8px!important;font-size:11px!important;font-weight:900!important;text-shadow:0 1px 2px rgba(0,0,0,.65)!important;box-shadow:0 2px 10px rgba(0,0,0,.35)!important;}
        .patio-label-selected{border-color:#fbbf24!important;color:#fbbf24!important;box-shadow:0 0 18px rgba(251,191,36,.45)!important;}
        .cm-patio-pin{background:transparent!important;border:none!important;}
        .cm-patio-pin-dot{width:32px;height:32px;border-radius:999px;background:rgba(4,12,24,.94);border:2px solid #fb923c;display:flex;align-items:center;justify-content:center;box-shadow:0 0 0 4px rgba(251,146,60,.18),0 8px 18px rgba(0,0,0,.42);}
        .cm-patio-pin-dot.selected{border-color:#fbbf24;box-shadow:0 0 0 5px rgba(251,191,36,.25),0 0 22px rgba(251,191,36,.45);}
        .cm-patio-pin-label{position:absolute;left:38px;top:5px;white-space:nowrap;background:rgba(4,12,24,.9);border:1px solid rgba(251,146,60,.55);border-radius:8px;padding:4px 8px;color:#fb923c;font-family:'DM Sans',sans-serif;font-size:10px;font-weight:900;box-shadow:0 4px 14px rgba(0,0,0,.30);}
        .cm-patio-pin-label.selected{border-color:#fbbf24;color:#fbbf24;}
        .leaflet-draw-toolbar a{background-color:rgba(4,12,24,.94)!important;border-color:rgba(255,255,255,.16)!important;}
        .leaflet-draw-toolbar a:hover{background-color:rgba(251,146,60,.18)!important;}
        .leaflet-control-zoom a{background:rgba(4,12,24,0.94)!important;color:rgba(255,255,255,0.75)!important;border-color:rgba(255,255,255,0.12)!important;}
        @media (max-width:760px){.patio-identifica-actions{grid-template-columns:1fr!important}.patio-identifica-search{grid-template-columns:1fr!important}}
      `}</style>
      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", gap:"10px", flexWrap:"wrap", marginBottom:"10px" }}>
        <div>
          <div style={{ fontFamily:getFont(theme,"title"), color:"#fff", fontSize:"16px", fontWeight:"800" }}>🛰️ Identifica tu Patio</div>
          <div style={{ fontFamily:getFont(theme,"secondary"), color:"rgba(255,255,255,0.58)", fontSize:"11px", marginTop:"3px" }}>
            Se cargan automáticamente los polígonos del KML. Puedes dibujar, editar, cambiar color, colocar pins y buscar patios por nombre. No se permite encimar polígonos sobre patios existentes. Los patios base están protegidos; los nuevos cambios se guardan automáticamente en Supabase para todos los usuarios.
          </div>
        </div>
        <div style={{ display:"flex", gap:"6px", flexWrap:"wrap" }}>
          <span title={dbStatus.text} style={{ alignSelf:"center", padding:"6px 9px", borderRadius:"999px", border:`1px solid ${dbStatus.ok ? "rgba(34,197,94,.45)" : "rgba(239,68,68,.45)"}`, background:dbStatus.ok ? "rgba(34,197,94,.12)" : "rgba(239,68,68,.12)", color:dbStatus.ok ? "#22c55e" : "#ef4444", fontFamily:getFont(theme,"secondary"), fontSize:"10px", fontWeight:"900" }}>
            {dbStatus.ok ? "🟢 Global activo" : "🔴 Sin global"}
          </span>
          {TILE_OPTIONS.map(t => (
            <button key={t.id} onClick={() => setTileMode(t.id)} style={{ padding:"6px 9px", borderRadius:"9px", border:`1.5px solid ${tileMode===t.id ? "#fb923c" : "rgba(255,255,255,0.14)"}`, background:tileMode===t.id ? "rgba(251,146,60,0.18)" : "rgba(255,255,255,0.04)", color:tileMode===t.id ? "#fb923c" : "rgba(255,255,255,0.66)", fontFamily:getFont(theme,"secondary"), fontSize:"10px", fontWeight:"800", cursor:"pointer" }}><AppIcon name={t.icon} size={14} active={tileMode===t.id} /> {t.label}</button>
          ))}
        </div>
      </div>

      <div className="patio-identifica-actions" style={{ display:"grid", gridTemplateColumns:"1fr 1fr 1fr 1fr", gap:"8px", marginBottom:"10px" }}>
        <button onClick={focusAll} style={{ padding:"9px 10px", borderRadius:"10px", border:"1px solid rgba(0,229,255,.35)", background:"rgba(0,229,255,.10)", color:"#00e5ff", fontFamily:getFont(theme,"secondary"), fontSize:"11px", fontWeight:"800", cursor:"pointer" }}>🧭 Ver todos</button>
        <button onClick={renameSelected} style={{ padding:"9px 10px", borderRadius:"10px", border:"1px solid rgba(56,189,248,.35)", background:"rgba(56,189,248,.10)", color:"#38bdf8", fontFamily:getFont(theme,"secondary"), fontSize:"11px", fontWeight:"800", cursor:"pointer" }}>✏️ Renombrar</button>
        <label style={{ padding:"9px 10px", borderRadius:"10px", border:"1px solid rgba(251,191,36,.35)", background:"rgba(251,191,36,.10)", color:"#fbbf24", fontFamily:getFont(theme,"secondary"), fontSize:"11px", fontWeight:"800", cursor:"pointer", textAlign:"center" }}>🎨 Color
          <input type="color" value={(features.find(f => f.id === selectedId && f.type === "polygon")?.color) || DEFAULT_USER_POLYGON_COLOR} onChange={e => changeSelectedColor(e.target.value)} style={{ position:"absolute", opacity:0, width:0, height:0 }} />
        </label>
        <button onClick={() => fetchGlobalPatios(false)} style={{ padding:"9px 10px", borderRadius:"10px", border:"1px solid rgba(34,197,94,.35)", background:"rgba(34,197,94,.10)", color:"#22c55e", fontFamily:getFont(theme,"secondary"), fontSize:"11px", fontWeight:"800", cursor:"pointer" }}>🔄 Sincronizar</button>
      </div>
      <div style={{ display:"flex", gap:"7px", flexWrap:"wrap", margin:"-2px 0 10px" }}>
        {PATIO_POLYGON_COLORS.map(color => (
          <button key={color} onClick={() => changeSelectedColor(color)} title="Cambiar color del polígono seleccionado" style={{ width:"28px", height:"28px", borderRadius:"999px", border:`2px solid ${selectedId && features.find(f => f.id === selectedId)?.color === color ? "#fff" : "rgba(255,255,255,.28)"}`, background:color, cursor:"pointer", boxShadow:"0 4px 12px rgba(0,0,0,.28)" }} />
        ))}
      </div>

      <div ref={mapRef} style={{ width:"100%", minHeight:"520px", height:"clamp(520px, 68vh, 780px)", borderRadius:"14px", overflow:"hidden", border:"1px solid rgba(251,146,60,0.36)", boxShadow:"0 16px 42px rgba(0,0,0,.35)", background:"#061428" }} />
      {(!L || !drawReady) && <div style={{ textAlign:"center", color:"#94a3b8", fontFamily:getFont(theme,"secondary"), fontSize:"12px", marginTop:"8px" }}>Cargando mapa y herramientas de dibujo…</div>}

      <div className="patio-identifica-search" style={{ display:"grid", gridTemplateColumns:"1.15fr .85fr", gap:"8px", marginTop:"12px" }}>
        <input value={query} onChange={e => setQuery(e.target.value)} placeholder="Buscar patio por nombre..." style={{ width:"100%", boxSizing:"border-box", background:"rgba(255,255,255,0.07)", border:"1px solid rgba(255,255,255,0.15)", borderRadius:"11px", padding:"11px 13px", color:"#fff", outline:"none", fontFamily:getFont(theme,"secondary"), fontSize:"12px" }} />
        <select value={selectedId || ""} onChange={e => selectFeature(e.target.value)} style={{ width:"100%", boxSizing:"border-box", background:"#0a1628", border:"1px solid rgba(251,146,60,0.32)", borderRadius:"11px", padding:"11px 13px", color:"#fff", outline:"none", fontFamily:getFont(theme,"secondary"), fontSize:"12px" }}>
          <option value="">Selecciona un patio para centrar el mapa</option>
          {filteredFeatures.map(f => <option key={f.id} value={f.id}>{f.type === "marker" ? `${f.name} · Pin` : f.name}</option>)}
        </select>
      </div>

      <div style={{ display:"flex", justifyContent:"space-between", gap:"8px", flexWrap:"wrap", marginTop:"8px", fontFamily:getFont(theme,"secondary"), fontSize:"10px", color:"rgba(255,255,255,0.46)" }}>
        <span>Dibuja patios, cambia color, coloca pins y corrige vértices. La basura elimina solo elementos creados por usuarios.</span>
        <span>{features.filter(isValidFeature).length} elemento(s) registrados</span>
      </div>
      {msg && <div style={{ marginTop:"10px", padding:"9px 11px", borderRadius:"9px", background:msg.color+"18", border:`1px solid ${msg.color}55`, color:msg.color, fontFamily:getFont(theme,"secondary"), fontSize:"11px", fontWeight:"800" }}>{msg.text}</div>}
    </div>
  );
}


function PatioReguladorTab({ myId }) {
  const theme = React.useContext(ThemeContext);
  const [patios,      setPatios]      = useState(null);  // null = loading
  const [toast,       setToast]       = useState(null);
  const [changeModal, setChangeModal] = useState(null);
  const [notas,       setNotas]       = useState(() => {
    try { return JSON.parse(sessionStorage.getItem("patio_notas") || "{}"); } catch { return {}; }
  });

  const updateNota = (id, val) => {
    const next = { ...notas, [id]: val };
    setNotas(next);
    try { sessionStorage.setItem("patio_notas", JSON.stringify(next)); } catch {}
  };

  const notify = (msg, color = "#38bdf8") => { setToast({ msg, color }); setTimeout(() => setToast(null), 2800); };
  const getOpt = (id) => PATIO_STATUS_OPTIONS.find(o => o.id === id) || PATIO_STATUS_OPTIONS[0];

  useEffect(() => {
    sb.from("patios").select("*").then(async ({ data }) => {
      if (!data || data.length === 0) {
        await sb.from("patios").upsert(PATIOS_REGULADORES.map(p => ({ id: p.id, status: "libre", last_update: Date.now(), updated_by: "Sistema", pending_voters: {} })));
        setPatios(mkPatios());
        return;
      }
      const map = {};
      data.forEach(r => {
        map[r.id] = { status: r.status, lastUpdate: r.last_update, updatedBy: r.updated_by, pendingVoters: r.pending_voters || {} };
      });
      setPatios({ ...(mkPatios()), ...map });
    });
    const chan = sb.channel("patios-rt")
      .on("postgres_changes", { event: "*", schema: "public", table: "patios" }, ({ new: r }) => {
        if (!r) return;
        setPatios(prev => ({ ...prev, [r.id]: { status: r.status, lastUpdate: r.last_update, updatedBy: r.updated_by, pendingVoters: r.pending_voters || {} } }));
      }).subscribe();
    return () => sb.removeChannel(chan);
  }, []);

  const vote = async (patioId, newStatus, forceChange = false) => {
    if (await notifyIfBlocked("vote", (m)=>alert(m))) return;
    const rl = rateLimiter.check(`patio_vote_${myId}`, 30000);
    if (!rl.allowed && !forceChange) return notify(`Espera ${rl.remaining}s antes de votar de nuevo`, "#f97316");
    const { data: yaVoto } = await sb.from("votos").select("id").eq("user_id", myId).eq("patio_id", patioId).eq("tipo", "patio");
    if (yaVoto && yaVoto.length > 0 && !forceChange) {
      const label = PATIO_STATUS_OPTIONS.find(o => o.id === newStatus)?.label || newStatus;
      setChangeModal({ type: "patio", id: patioId, newStatus, label });
      return;
    }
    if (yaVoto && yaVoto.length > 0 && forceChange) {
      await sb.from("votos").delete().eq("user_id", myId).eq("patio_id", patioId).eq("tipo", "patio");
    }
    const key = `patio_${patioId}_${newStatus}`;
    await sb.from("votos").insert({ key, user_id: myId, patio_id: patioId, status: newStatus, tipo: "patio" });
    // Persistir voto en localStorage para sobrevivir la limpieza de 15 min
    try { localStorage.setItem(`last_vote_patio_${patioId}_${myId}`, newStatus); } catch {}
    const { data: todosVotos } = await sb.from("votos").select("status").eq("patio_id", patioId).eq("tipo", "patio");
    const conteo = {};
    (todosVotos || []).forEach(v => { conteo[v.status] = (conteo[v.status] || 0) + 1; });
    const ganadora = Object.entries(conteo).sort((a,b) => b[1]-a[1])[0];
    const [statusGanador, votosGanador] = ganadora;
    // Optimistic update
    setPatios(prev => ({ ...prev, [patioId]: { ...prev[patioId], status: statusGanador, lastUpdate: Date.now(), updatedBy: `${votosGanador} votos`, pendingVoters: conteo } }));
    await sb.from("patios").upsert({ id: patioId, status: statusGanador, pending_voters: conteo, last_update: Date.now(), updated_by: `${votosGanador} votos` });
    await auditLog({ action:"votar_patio", section:"patios", entityId:patioId, after:{ status:statusGanador, votos:conteo }, actor:`Usuario_${myId.slice(-4)}` });
    const label = PATIO_STATUS_OPTIONS.find(o => o.id === statusGanador)?.label;
    notify(`Validado ${label} lidera con ${votosGanador} voto(s)`, "#22c55e");
    const patioNombre = PATIOS_REGULADORES.find(p => p.id === patioId)?.name || patioId.toUpperCase();
    await publicarNoticia({ tipo: "patio", icono: "🏭", color: "#fb923c", titulo: `Patio ${patioNombre} — ${label}`, detalle: `Actualizado por consenso de ${votosGanador} voto(s)` });
  };

  const resetAll = async () => {
    await sb.from("patios").upsert(PATIOS_REGULADORES.map(p => ({ id: p.id, status: "libre", last_update: Date.now(), updated_by: "Reset", pending_voters: {} })));
    notify("✓ Todos los patios marcados como Libres", "#22c55e");
  };

  const resetOne = async (id) => {
    await sb.from("patios").upsert({ id, status: "libre", last_update: Date.now(), updated_by: "Reset", pending_voters: {} });
    notify("✓ Patio marcado como Libre", "#22c55e");
  };

  const patioTickerItems = !patios ? [] : PATIOS_REGULADORES.map(p => {
    const st  = patios[p.id] || { status:"libre" };
    const opt = PATIO_STATUS_OPTIONS.find(o => o.id === st.status) || PATIO_STATUS_OPTIONS[0];
    return { text: `${p.name} — ${opt.label.toUpperCase()}`, color: opt.color };
  });

  return (
    <div style={{ padding:"16px", paddingBottom:"80px", minHeight:"100vh" }}>
      <TypewriterTicker items={patioTickerItems} />
      <div style={{ background:"rgba(255,255,255,0.08)", backdropFilter:"blur(12px)", WebkitBackdropFilter:"blur(12px)", border:"1px solid rgba(255,255,255,0.15)", borderRadius:"12px", padding:"12px", marginBottom:"14px" }}>
        <div style={{ fontSize:"10px", color:"#fb923c", fontFamily:getFont(theme, "secondary"), letterSpacing:"2px", marginBottom:"4px" }}>PATIO REGULADOR — PUERTO MANZANILLO</div>
        <div style={{ color:"rgba(255,255,255,0.7)", fontSize:"12px" }}>Estatus en tiempo real de los 8 patios reguladores del puerto.</div>
      </div>
      <div style={{ display:"flex", gap:"5px", flexWrap:"wrap", marginBottom:"14px" }}>
        {PATIO_STATUS_OPTIONS.map(o => (
          <div key={o.id} style={{ display:"flex", alignItems:"center", gap:"4px", background:o.color+"15", border:`1px solid ${o.color}33`, padding:"3px 8px", borderRadius:"4px" }}>
            <span style={{ color:o.color, fontSize:"11px", fontWeight:"700" }}>{o.icon}</span>
            <span style={{ color:o.color, fontSize:"10px", fontFamily:getFont(theme, "secondary") }}>{o.label}</span>
          </div>
        ))}
      </div>
      <PatioIdentificaMap myId={myId} />
      <SectionLabel text="PATIOS REGULADORES" rightBtn={<NormalBtn onClick={resetAll} label="TODOS LIBRES" />} />
      {(!patios) ? <SkeletonCard n={4}/> : PATIOS_REGULADORES.map(patio => {
        const st  = patios[patio.id] || { status:"libre", lastUpdate: Date.now(), updatedBy:"Sistema", pendingVoters:{} };
        const opt = getOpt(st.status);
        const votes = st.pendingVoters || {};
        const totalVotes = Object.values(votes).reduce((a,b)=>a+b,0);
        return (
          <div key={patio.id} style={{ background:"rgba(255,255,255,0.08)", backdropFilter:"blur(12px)", WebkitBackdropFilter:"blur(12px)", border:`1px solid ${opt.color}44`, borderRadius:"12px", padding:"14px", marginBottom:"14px", boxShadow:`0 0 18px ${opt.color}08` }}>
            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", marginBottom:"10px" }}>
              <div>
                <div style={{ color:"rgba(255,255,255,0.95)", fontFamily:getFont(theme, "secondary"), fontWeight:"700", fontSize:"14px" }}>{patio.name}</div>
                <div style={{ color:"rgba(255,255,255,0.4)", fontSize:"10px", marginTop:"2px" }}>{patio.fullName}</div>
                <div style={{ color:"rgba(255,255,255,0.3)", fontSize:"10px", fontFamily:getFont(theme, "secondary"), marginTop:"3px" }}>{timeAgo(st.lastUpdate)} · {st.updatedBy}</div>
              </div>
              <div style={{ display:"flex", flexDirection:"column", alignItems:"flex-end", gap:"6px" }}>
                <div style={{ background:opt.color+"22", border:`1px solid ${opt.color}66`, color:opt.color, padding:"5px 10px", borderRadius:"6px", fontFamily:getFont(theme, "secondary"), fontSize:"11px", fontWeight:"700", display:"flex", alignItems:"center", gap:"4px" }}><IconText icon={opt.icon} label={opt.label} size={15} /></div>
                {totalVotes > 0 && <span style={{ fontSize:"9px", color:"rgba(255,255,255,0.4)", fontFamily:getFont(theme, "secondary") }}>{totalVotes} voto(s)</span>}
                {st.status !== "libre" && <button onClick={() => resetOne(patio.id)} style={{ padding:"4px 8px", background:"#22c55e15", border:"1px solid #22c55e44", borderRadius:"5px", color:"#22c55e", fontFamily:getFont(theme, "secondary"), fontSize:"10px", cursor:"pointer", fontWeight:"700" }}>TODO NORMAL</button>}
              </div>
            </div>
            <div style={{ fontSize:"10px", color:"rgba(255,255,255,0.5)", fontFamily:getFont(theme, "secondary"), letterSpacing:"1px", marginBottom:"7px" }}>REPORTAR ESTATUS:</div>
            <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:"6px" }}>
              {PATIO_STATUS_OPTIONS.map(o => {
                const isAct = st.status === o.id;
                return (
                  <button key={o.id} onClick={() => vote(patio.id, o.id)} style={{ padding:"8px 6px", background: isAct ? o.color+"33" : "#0a1628", border:`1px solid ${isAct ? o.color : "#1e3a5f"}`, borderRadius:"8px", color: isAct ? o.color : "#64748b", fontFamily:getFont(theme, "secondary"), fontSize:"10px", cursor:"pointer", transition:"all 0.15s", display:"flex", alignItems:"center", justifyContent:"center", gap:"4px" }}>
                    <IconText icon={o.icon} label={o.label} size={15} />
                  </button>
                );
              })}
            </div>
          </div>
        );
      })}
      <ToastBox toast={toast} />
      {changeModal && (
        <div style={{ position:"fixed", inset:0, background:"rgba(0,0,0,0.75)", zIndex:9999, display:"flex", alignItems:"center", justifyContent:"center", padding:"20px" }}>
          <div style={{ background:"#0f2037", border:"1px solid #1e3a5f", borderRadius:"14px", padding:"24px", maxWidth:"300px", width:"100%", textAlign:"center" }}>
            <div style={{ fontSize:"28px", marginBottom:"10px" }}>🔄</div>
            <div style={{ color:"#e2e8f0", fontFamily:getFont(theme, "secondary"), fontSize:"14px", fontWeight:"700", marginBottom:"8px" }}>¿Cambiar tu voto?</div>
            <div style={{ color:"#94a3b8", fontFamily:getFont(theme, "secondary"), fontSize:"12px", marginBottom:"20px" }}>
              ¿Estás seguro que quieres cambiar tu voto a <span style={{ color:"#fb923c", fontWeight:"700" }}>{changeModal.label}</span>?
            </div>
            <div style={{ display:"flex", gap:"10px" }}>
              <button onClick={() => setChangeModal(null)} style={{ flex:1, padding:"10px", background:"#1e3a5f", border:"1px solid #2d4a6f", borderRadius:"8px", color:"#94a3b8", fontFamily:getFont(theme, "secondary"), fontSize:"12px", cursor:"pointer", fontWeight:"700" }}>Cancelar</button>
              <button onClick={async () => { const m = changeModal; setChangeModal(null); await vote(m.id, m.newStatus, true); }} style={{ flex:1, padding:"10px", background:"#fb923c22", border:"1px solid #fb923c", borderRadius:"8px", color:"#fb923c", fontFamily:getFont(theme, "secondary"), fontSize:"12px", cursor:"pointer", fontWeight:"700" }}>Sí, cambiar</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}


