// ─── COPYROW — componente auxiliar para filas copiables (HOOKS fuera de .map()) ──
function CopyRow({ label, value, mono, theme, getFont }) {
  const [copied, setCopied] = React.useState(false);
  const handleCopy = () => {
    try {
      if (navigator.clipboard && navigator.clipboard.writeText) {
        navigator.clipboard.writeText(value).then(() => {
          setCopied(true);
          setTimeout(() => setCopied(false), 1800);
        });
      } else {
        const ta = document.createElement("textarea");
        ta.value = value;
        ta.style.cssText = "position:fixed;top:-9999px;left:-9999px;opacity:0";
        document.body.appendChild(ta);
        ta.focus(); ta.select();
        document.execCommand("copy");
        document.body.removeChild(ta);
        setCopied(true);
        setTimeout(() => setCopied(false), 1800);
      }
    } catch {}
  };
  return (
    <div
      onClick={handleCopy}
      style={{
        display: "flex",
        justifyContent: "space-between",
        alignItems: "center",
        background: copied ? "rgba(168,85,247,0.18)" : (mono ? "rgba(255,255,255,0.05)" : "transparent"),
        borderRadius: "8px",
        padding: "8px 10px",
        marginBottom: "6px",
        cursor: "pointer",
        border: `1px solid ${copied ? "rgba(168,85,247,0.6)" : "rgba(255,255,255,0.07)"}`,
        transition: "all 0.2s",
        userSelect: "none",
      }}
      title={`Toca para copiar ${label}`}
    >
      <div style={{ display: "flex", flexDirection: "column", gap: "1px" }}>
        <span style={{ color: "rgba(255,255,255,0.45)", fontFamily: getFont(theme, "secondary"), fontSize: "9px", letterSpacing: "1px" }}>{label.toUpperCase()}</span>
        <span style={{
          color: mono ? "#A855F7" : "#fff",
          fontFamily: mono ? "'Space Mono', monospace" : getFont(theme, "secondary"),
          fontSize: mono ? "13px" : "12px",
          fontWeight: "700",
          letterSpacing: mono ? "0.5px" : "0",
        }}>{value}</span>
      </div>
      <div style={{
        display: "flex",
        alignItems: "center",
        gap: "4px",
        background: copied ? "rgba(168,85,247,0.3)" : "rgba(255,255,255,0.1)",
        border: `1px solid ${copied ? "rgba(168,85,247,0.5)" : "rgba(255,255,255,0.15)"}`,
        borderRadius: "6px",
        padding: "4px 8px",
        transition: "all 0.2s",
        flexShrink: 0,
      }}>
        <span style={{ fontSize: "11px" }}>{copied ? "✓" : "📋"}</span>
        <span style={{ fontFamily: getFont(theme, "secondary"), fontSize: "10px", color: copied ? "#c084fc" : "rgba(255,255,255,0.6)", fontWeight: "700" }}>
          {copied ? "¡Copiado!" : "Copiar"}
        </span>
      </div>
    </div>
  );
}


// ─────────────────────────────────────────────────────────────────────────────
// 🧮 MÓDULO DE COTIZACIÓN DE FLETES — Puerto Manzanillo / Lázaro Cárdenas
// Motor completo: rutas, vehículos, tipo carga, maniobras, seguro, margen
// ─────────────────────────────────────────────────────────────────────────────

// ── Parámetros de Operación (diccionario central) ─────────────────────────────
const parametrosFlete = {
  // Generales
  precioDiesel:        24.50,  // MXN / litro
  viaticosPorDia:      500,    // apoyo diario al operador (MXN)
  costoManiobraBase:   800,    // maniobras sencillas (MXN)
  costoManiobrasDobles:1400,   // maniobras dobles para Full (MXN)
  margenGanancia:      0.20,   // 20 % sobre costo total
  tasaSeguroCarga:     0.01,   // 1 % sobre valor declarado de mercancía

  // Rendimiento km/L por tipo de vehículo
  rendimientoKmLitro: {
    rabon:               3.5,
    torton:              2.8,
    sencillo_caja:       2.4,
    sencillo_contenedor: 2.3,
    full:                1.7,
  },

  // Mantenimiento + llantas por km (MXN/km)
  costoMantenimientoKm: {
    rabon:               1.5,
    torton:              2.0,
    sencillo_caja:       3.0,
    sencillo_contenedor: 3.0,
    full:                5.5,
  },

  // Sueldo operador por km (MXN/km)
  sueldoOperadorKm: {
    rabon:               1.2,
    torton:              1.5,
    sencillo_caja:       1.8,
    sencillo_contenedor: 1.8,
    full:                2.5,
  },

  // Multiplicador de peaje según número de ejes
  multiplicadorPeaje: {
    rabon:               1.0,
    torton:              1.2,
    sencillo_caja:       1.5,
    sencillo_contenedor: 1.5,
    full:                2.2,
  },
};

// ── Rutas con distancia y peaje base ─────────────────────────────────────────
// TODO: conectar km y peajeBase con tu API de mapas (Google Maps Distance Matrix
//       o similar). Por ahora son valores estimados.
